// Use the page's own origin so the health check always targets the live server,
// regardless of which domain it's deployed on. This also prevents requests from
// going to an ESP32 hotspot (no internet) — the production origin is unreachable
// from the local hotspot, so isOnlineAsync() correctly falls back to offline mode.
const API = window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1'
  ? ''
  : window.location.origin;

// Lazy script loader — returns a Promise that resolves when the script is ready.
// Calling it twice for the same URL is a no-op (resolved immediately on 2nd call).
// Lazy-aware _safeRender: ensures `scriptSrc` is loaded before calling fn.

// Opens external URLs in system browser. Uses Capacitor Browser plugin when
// running inside the native app so the in-app WebView is not navigated away.
async function openUrl(url, forceExternal = false) {
  const isInternal = url.startsWith('/') || url.startsWith(window.location.origin);
  if (!isInternal || forceExternal) {
    try {
      if (window.Capacitor?.isNativePlatform?.() && window.Capacitor?.Plugins?.Browser) {
        await window.Capacitor.Plugins.Browser.open({ url });
        return;
      }
    } catch (_) {}
    window.open(url, '_blank', 'noopener,noreferrer');
  } else {
    window.location.href = url;
  }
}

// Downloads a blob as a file. Uses Capacitor Filesystem + Share plugins when
// running inside the native app (iOS/Android), falls back to standard browser
// anchor-click download for web.
async function downloadBlob(blob, filename) {
  if (window.Capacitor?.isNativePlatform?.()) {
    try {
      const reader = new FileReader();
      const base64 = await new Promise((res, rej) => {
        reader.onload  = () => res(reader.result.split(',')[1]);
        reader.onerror = rej;
        reader.readAsDataURL(blob);
      });
      const result = await window.Capacitor.Plugins.Filesystem.writeFile({
        path:      filename,
        data:      base64,
        directory: 'DOCUMENTS',
        recursive: true,
      });
      await window.Capacitor.Plugins.Share.share({
        title:      filename,
        url:        result.uri,
        dialogTitle: 'Save or share ' + filename,
      });
      return;
    } catch (e) {
      console.warn('[downloadBlob] Native failed, using browser fallback:', e.message);
    }
  }
  // Standard browser download
  const url = URL.createObjectURL(blob);
  const a   = document.createElement('a');
  a.href = url; a.download = filename;
  document.body.appendChild(a); a.click(); document.body.removeChild(a);
  setTimeout(() => URL.revokeObjectURL(url), 5000);
}
// ═══════════════════════════════════════════════════════
// NOTIFICATION SOUND SYSTEM
// Uses Web Audio API — no external audio files needed.
// Plays a gentle two-tone chime when new messages or
// announcements arrive. Respects a mute toggle stored
// in localStorage so the user's preference survives reloads.
// ═══════════════════════════════════════════════════════
const _notifSound = (() => {
  let _ctx = null;
  function _getCtx() {
    if (!_ctx) _ctx = new (window.AudioContext || window.webkitAudioContext)();
    return _ctx;
  }
  function playChime(type = 'message') {
    if (localStorage.getItem('dikly_sound_muted') === '1') return;
    try {
      const ctx   = _getCtx();
      // Resume context if browser suspended it (autoplay policy)
      if (ctx.state === 'suspended') ctx.resume();
      const notes = type === 'announcement'
        ? [880, 1100]   // higher pitch for announcements
        : [660, 880];   // softer for messages
      // Each note gets its OWN gain node — sharing one causes the second
      // note's gain automation to overwrite the first note's envelope.
      notes.forEach((freq, i) => {
        const gain = ctx.createGain();
        gain.connect(ctx.destination);
        const t0 = ctx.currentTime + i * 0.18;
        gain.gain.setValueAtTime(0, t0);
        gain.gain.linearRampToValueAtTime(0.18, t0 + 0.02);
        gain.gain.exponentialRampToValueAtTime(0.001, t0 + 0.38);
        const osc = ctx.createOscillator();
        osc.type = 'sine';
        osc.frequency.value = freq;
        osc.connect(gain);
        osc.start(t0);
        osc.stop(t0 + 0.4);
      });
    } catch (_) {}
  }
  // Mobile browsers (Safari especially) block AudioContext.resume() unless
  // it's called from within a real user-gesture handler -- calling it later
  // from an SSE push (see startSSE's onmessage) doesn't count, so a chime
  // triggered by a notification that arrives before the user has tapped
  // anything on the page silently never plays. Priming the context on the
  // very first tap/click/keypress anywhere fixes that for the rest of the
  // session, before any real notification needs to use it.
  let _primed = false;
  function _primeOnGesture() {
    if (_primed) return;
    _primed = true;
    try {
      const ctx = _getCtx();
      if (ctx.state === 'suspended') ctx.resume();
    } catch (_) {}
    window.removeEventListener('pointerdown', _primeOnGesture);
    window.removeEventListener('keydown', _primeOnGesture);
  }
  window.addEventListener('pointerdown', _primeOnGesture, { once: true });
  window.addEventListener('keydown', _primeOnGesture, { once: true });

  function isMuted() { return localStorage.getItem('dikly_sound_muted') === '1'; }
  function toggleMute() {
    const muted = isMuted();
    localStorage.setItem('dikly_sound_muted', muted ? '0' : '1');
    _updateMuteBtn();
    if (muted) playChime('message'); // preview sound when unmuting
  }
  function _updateMuteBtn() {
    const btn = document.getElementById('sound-toggle-btn');
    if (!btn) return;
    const muted = isMuted();
    btn.title = muted ? 'Sound off — click to enable' : 'Sound on — click to mute';
    btn.innerHTML = muted
      ? `<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"/><line x1="23" y1="9" x2="17" y2="15"/><line x1="17" y1="9" x2="23" y2="15"/></svg>`
      : `<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"/><path d="M19.07 4.93a10 10 0 0 1 0 14.14"/><path d="M15.54 8.46a5 5 0 0 1 0 7.07"/></svg>`;
  }
  return { playChime, isMuted, toggleMute, updateBtn: _updateMuteBtn };
})();

// ── Notification polling ──────────────────────────────────────────────────────
// Polls every 30 s for new messages and announcements, plays a chime when the
// unread count rises above the last known value.
let _notifPollTimer  = null;
let _lastMsgUnread   = -1;  // -1 = not yet initialised; first run is a silent baseline
let _lastAnnUnread   = -1;

async function _pollNotifications() {
  if (!currentUser || !isOnline()) return;
  const baseline = _lastMsgUnread === -1; // first run records counts without playing sound
  try {
  // all roles poll for messages
      const md = await api('/api/messages/conversations').catch(() => null);
      if (md) {
        const total = (md.conversations || []).reduce((s, c) => s + (c.myUnreadCount || 0), 0);
        if (!baseline && total > _lastMsgUnread) _notifSound.playChime('message');
        _lastMsgUnread = total;
        // Update messages badge in sidebar
        _updateMsgBadge(total);
      }
  } catch (_) {}
  try {
    // Announcements
    if (!['employee'].includes(currentUser.role)) {
      const ad = await api('/api/announcements/unread-count').catch(() => null);
      if (ad) {
        const count = ad.count || 0;
        if (!baseline && count > _lastAnnUnread) {
          _notifSound.playChime('announcement');
          // Refresh the ann-badge in the sidebar
          const badge = document.getElementById('ann-badge');
          if (badge) {
            badge.textContent = count > 99 ? '99+' : count;
            badge.style.display = 'inline-block';
          }
        }
        _lastAnnUnread = count;
      }
    }
  } catch (_) {}
}

function _updateMsgBadge(total) {
  let badge = document.getElementById('msg-nav-badge');
  const msgLink = document.querySelector('#nav-messages');
  if (!msgLink) return;
  if (!badge) {
    badge = document.createElement('span');
    badge.id = 'msg-nav-badge';
    badge.style.cssText = 'position:absolute;top:4px;right:4px;background:#ef4444;color:#fff;font-size:9px;font-weight:700;padding:1px 5px;border-radius:20px;min-width:14px;text-align:center;line-height:14px;';
    msgLink.style.position = 'relative';
    msgLink.appendChild(badge);
  }
  if (total > 0) {
    badge.textContent = total > 99 ? '99+' : total;
    badge.style.display = 'inline-block';
  } else {
    badge.style.display = 'none';
  }
}

function startNotifPolling() {
  stopNotifPolling();
  _lastMsgUnread = -1; // reset so first run is a silent baseline
  _lastAnnUnread = -1;
  _pollNotifications();
  _notifPollTimer = setInterval(_pollNotifications, 30000);
}

function stopNotifPolling() {
  if (_notifPollTimer) { clearInterval(_notifPollTimer); _notifPollTimer = null; }
}

// ── Real-time notification SSE ────────────────────────────────────────────────
let _sseSource       = null;
let _notifUnread     = 0;
let _notifPanelOpen  = false;

function _updateNotifBadge(count) {
  _notifUnread = count;
  const badge = document.getElementById('notif-bell-badge');
  if (!badge) return;
  if (count > 0) {
    badge.textContent    = count > 99 ? '99+' : count;
    badge.style.display  = 'inline-block';
  } else {
    badge.style.display  = 'none';
  }
}

let _sseFailures = 0;
let _sseRetryTimer = null;

function startSSE(isRetry = false) {
  if (_sseRetryTimer) { clearTimeout(_sseRetryTimer); _sseRetryTimer = null; }
  if (!isRetry) _sseFailures = 0; // fresh start (login/reload) resets the backoff counter
  if (_sseSource) { _sseSource.close(); _sseSource = null; }
  const token = localStorage.getItem('token');
  if (!token) return;

  _sseSource = new EventSource(`/api/notifications/stream?token=${encodeURIComponent(token)}`);

  _sseSource.onmessage = (e) => {
    _sseFailures = 0; // reset backoff on successful message
    try {
      const msg = JSON.parse(e.data);
      if (msg.event === 'unread_count') {
        _updateNotifBadge(msg.count);
      } else if (msg.event === 'notification') {
        const n = msg.notification;
        _updateNotifBadge(_notifUnread + 1);
        _notifSound.playChime('announcement');
        if (window.toast) {
          window.toast(n.body || '', 'info', {
            title: n.title,
            duration: 6000,
          });
        }
        if (_notifPanelOpen) _loadNotifPanel();
      }
    } catch (_) {}
  };

  _sseSource.onerror = () => {
    if (_sseSource) { _sseSource.close(); _sseSource = null; }
    _sseFailures++;
    // Stop retrying after 5 consecutive failures (likely auth issue or server offline)
    if (_sseFailures > 5) return;
    // Exponential backoff: 5s, 10s, 20s, 40s, 60s
    const delay = Math.min(5000 * Math.pow(2, _sseFailures - 1), 60000);
    _sseRetryTimer = setTimeout(() => { if (currentUser) startSSE(true); }, delay);
  };
}

function stopSSE() {
  if (_sseSource) { _sseSource.close(); _sseSource = null; }
}

async function _loadNotifPanel() {
  const list = document.getElementById('notif-panel-list');
  if (!list) return;
  try {
    const d = await api('/api/notifications?limit=15');
    const notifs = d.notifications || [];
    if (!notifs.length) {
      list.innerHTML = '<p style="text-align:center;color:var(--text-muted);font-size:13px;padding:20px">All caught up!</p>';
      return;
    }
    list.innerHTML = notifs.map(n => `
      <div onclick="_notifPanelClick('${n._id}','${n.link || ''}')"
           style="display:flex;gap:10px;padding:10px 16px;cursor:pointer;border-bottom:1px solid var(--border);align-items:flex-start;background:${n.isRead ? 'transparent' : 'var(--primary-ultra-light,#f0f4ff)'}">
        <div style="width:8px;height:8px;border-radius:50%;background:${n.isRead ? 'transparent' : 'var(--primary)'};margin-top:5px;flex-shrink:0"></div>
        <div style="flex:1;min-width:0">
          <div style="font-weight:${n.isRead ? '400' : '600'};font-size:13px;line-height:1.3">${n.title}</div>
          ${n.body ? `<div style="font-size:12px;color:var(--text-light);margin-top:2px">${n.body}</div>` : ''}
          <div style="font-size:11px;color:var(--text-muted);margin-top:3px">${_timeAgo(new Date(n.createdAt))}</div>
        </div>
      </div>`).join('');
  } catch (_) {
    list.innerHTML = '<p style="text-align:center;color:var(--text-muted);font-size:13px;padding:20px">Could not load</p>';
  }
}

async function _notifPanelClick(id, link) {
  await api('/api/notifications/' + id + '/read', { method: 'PATCH' }).catch(() => {});
  _updateNotifBadge(Math.max(0, _notifUnread - 1));
  closeNotifPanel();
  if (!link) return;
  // Known SPA views navigate in-place instead of a full page reload -- a
  // hard location.href to these paths has no matching server route and
  // just bounces back to the dashboard, which is exactly the "doesn't know
  // where it should go" complaint this fixes. Anything else (real static
  // pages, hash routes) keeps the previous full-navigation behavior.
  const url = new URL(link, location.origin);
  if (url.pathname === '/users') {
    const highlight = url.searchParams.get('highlight');
    if (highlight) window._usersHighlightId = highlight;
    navigateTo('users');
    return;
  }
  if (url.pathname === '/profile') { navigateTo('profile'); return; }
  if (url.pathname.startsWith('/leaves/')) {
    // Reviewers land on the review queue; the requester lands on their own history.
    const reviewerRoles = ['manager', 'admin', 'superadmin', 'hod'];
    navigateTo(reviewerRoles.includes(currentUser?.role) ? 'leave-requests' : 'my-leaves');
    return;
  }
  if (url.pathname.startsWith('/announcements/')) { navigateTo('announcements'); return; }
  location.href = link;
}

function toggleNotifPanel() {
  const panel = document.getElementById('notif-panel');
  if (!panel) return;
  _notifPanelOpen = !_notifPanelOpen;
  panel.style.display = _notifPanelOpen ? 'flex' : 'none';
  if (_notifPanelOpen) _loadNotifPanel();
}

function closeNotifPanel() {
  const panel = document.getElementById('notif-panel');
  if (panel) panel.style.display = 'none';
  _notifPanelOpen = false;
}

async function markAllNotifsRead() {
  await api('/api/notifications/read-all', { method: 'PATCH' }).catch(() => {});
  _updateNotifBadge(0);
  _loadNotifPanel();
}

function _timeAgo(date) {
  const s = Math.floor((Date.now() - date) / 1000);
  if (s < 60)   return 'just now';
  if (s < 3600)  return Math.floor(s / 60) + 'm ago';
  if (s < 86400) return Math.floor(s / 3600) + 'h ago';
  return Math.floor(s / 86400) + 'd ago';
}

// ═══════════════════════════════════════════════════════
// TOAST NOTIFICATION SYSTEM
// Usage: toast('Message')           → info (default)
//        toast('Message', 'success') → green
//        toast('Message', 'error')   → red  
//        toast('Message', 'warning') → amber
//        toastConfirm('Sure?', onConfirm) → replaces confirm()
// ═══════════════════════════════════════════════════════

(function() {
  // Inject toast CSS once
  const style = document.createElement('style');
  style.textContent = `
    #toast-container {
      position: fixed;
      top: 70px;
      right: 18px;
      z-index: 9999;
      display: flex;
      flex-direction: column;
      gap: 8px;
      pointer-events: none;
      max-width: min(360px, calc(100vw - 36px));
    }
    .toast {
      display: flex;
      align-items: flex-start;
      gap: 10px;
      padding: 12px 14px;
      border-radius: 10px;
      font-family: 'Inter', -apple-system, sans-serif;
      font-size: 13px;
      font-weight: 500;
      line-height: 1.45;
      color: #0f172a;
      background: rgba(255,255,255,0.97);
      border: 1px solid #e2e8f0;
      box-shadow: 0 4px 20px rgba(0,0,0,0.10), 0 1px 4px rgba(0,0,0,0.06);
      pointer-events: all;
      cursor: pointer;
      backdrop-filter: blur(12px);
      transform: translateX(120%);
      opacity: 0;
      transition: transform 0.3s cubic-bezier(0.16,1,0.3,1), opacity 0.3s ease;
      max-width: 100%;
      word-break: break-word;
    }
    .toast.toast-in {
      transform: translateX(0);
      opacity: 1;
    }
    .toast.toast-out {
      transform: translateX(120%);
      opacity: 0;
      transition: transform 0.25s cubic-bezier(0.4,0,1,1), opacity 0.25s ease;
    }
    .toast-icon {
      font-size: 15px;
      flex-shrink: 0;
      margin-top: 1px;
    }
    .toast-body { flex: 1; min-width: 0; }
    .toast-title { font-weight: 600; margin-bottom: 1px; }
    .toast-msg { color: #475569; font-size: 12.5px; }
    .toast-close {
      flex-shrink: 0;
      font-size: 16px;
      color: #94a3b8;
      line-height: 1;
      padding: 0 2px;
      cursor: pointer;
      transition: color 0.15s;
      margin-top: -1px;
    }
    .toast-close:hover { color: #64748b; }
    .toast-progress {
      position: absolute;
      bottom: 0; left: 0;
      height: 2px;
      border-radius: 0 0 10px 10px;
      transition: width linear;
    }
    .toast { position: relative; overflow: hidden; }

    /* Types */
    .toast-success { border-left: 3px solid #10b981; }
    .toast-success .toast-progress { background: #10b981; }
    .toast-error   { border-left: 3px solid #ef4444; }
    .toast-error .toast-progress { background: #ef4444; }
    .toast-warning { border-left: 3px solid #f59e0b; }
    .toast-warning .toast-progress { background: #f59e0b; }
    .toast-info    { border-left: 3px solid #6366f1; }
    .toast-info .toast-progress { background: #6366f1; }

    /* Confirm toast */
    .toast-confirm-btns {
      display: flex;
      gap: 6px;
      margin-top: 9px;
    }
    .toast-confirm-btns button {
      flex: 1;
      padding: 5px 10px;
      border-radius: 6px;
      font-size: 12px;
      font-weight: 600;
      font-family: inherit;
      cursor: pointer;
      border: none;
      transition: opacity 0.15s;
    }
    .toast-confirm-btns button:hover { opacity: 0.85; }
    .toast-confirm-yes { background: #ef4444; color: white; }
    .toast-confirm-no  { background: #f1f5f9; color: #475569; border: 1px solid #e2e8f0 !important; }

    /* Mobile */
    @media (max-width: 540px) {
      #toast-container { top: auto; bottom: 74px; right: 12px; left: 12px; max-width: 100%; }
      .toast { transform: translateY(120%); }
      .toast.toast-in { transform: translateY(0); }
      .toast.toast-out { transform: translateY(120%); }
    }
  `;
  document.head.appendChild(style);

  // Create container
  let container;
  function getContainer() {
    if (!container || !document.body.contains(container)) {
      container = document.createElement('div');
      container.id = 'toast-container';
      document.body.appendChild(container);
    }
    return container;
  }

  const ICONS = {
    success: '✓',
    error:   '✕',
    warning: '⚠',
    info:    'ℹ',
  };

  const TITLES = {
    success: 'Success',
    error:   'Error',
    warning: 'Warning',
    info:    'Info',
  };

  const DURATIONS = {
    success: 3500,
    error:   5000,
    warning: 4500,
    info:    3500,
  };

  window.toast = function(message, type = 'info', options = {}) {
    if (!message) return;
    const c = getContainer();
    const duration = options.duration || DURATIONS[type] || 3500;
    const t = type in ICONS ? type : 'info';

    const el = document.createElement('div');
    el.className = `toast toast-${t}`;
    const title = options.title;
    el.innerHTML = `
      <span class="toast-icon">${ICONS[t]}</span>
      <div class="toast-body">
        ${title ? `<div class="toast-title">${title}</div>` : ''}
        ${message ? `<div class="toast-msg">${message}</div>` : ''}
      </div>
      <span class="toast-close">×</span>
      <div class="toast-progress" style="width:100%"></div>
    `;

    const close = () => dismiss(el);
    el.querySelector('.toast-close').addEventListener('click', e => { e.stopPropagation(); close(); });
    el.addEventListener('click', close);

    c.appendChild(el);
    requestAnimationFrame(() => requestAnimationFrame(() => el.classList.add('toast-in')));

    // Progress bar
    const bar = el.querySelector('.toast-progress');
    bar.style.transitionDuration = duration + 'ms';
    requestAnimationFrame(() => requestAnimationFrame(() => { bar.style.width = '0%'; }));

    const timer = setTimeout(close, duration);
    el._toastTimer = timer;

    // Pause on hover
    el.addEventListener('mouseenter', () => {
      clearTimeout(el._toastTimer);
      bar.style.transitionDuration = '0ms';
    });
    el.addEventListener('mouseleave', () => {
      const remaining = 1000;
      bar.style.transitionDuration = remaining + 'ms';
      bar.style.width = '0%';
      el._toastTimer = setTimeout(close, remaining);
    });

    return el;
  };

  function dismiss(el) {
    if (!el || el._dismissed) return;
    el._dismissed = true;
    clearTimeout(el._toastTimer);
    el.classList.remove('toast-in');
    el.classList.add('toast-out');
    setTimeout(() => el.remove(), 300);
  }

  // Convenience shorthands
  window.toastSuccess = (msg, opts) => window.toast(msg, 'success', opts);
  window.toastError   = (msg, opts) => window.toast(msg, 'error',   opts);
  window.toastWarning = (msg, opts) => window.toast(msg, 'warning', opts);
  window.toastInfo    = (msg, opts) => window.toast(msg, 'info',    opts);

  // Replaces window.confirm() — returns a Promise
  window.toastConfirm = function(message, onConfirm, onCancel, opts = {}) {
    const c = getContainer();
    const el = document.createElement('div');
    el.className = 'toast toast-warning';
    el.innerHTML = `
      <span class="toast-icon">⚠</span>
      <div class="toast-body">
        <div class="toast-msg">${message}</div>
        <div class="toast-confirm-btns">
          <button class="toast-confirm-no">${opts.cancelLabel || 'Cancel'}</button>
          <button class="toast-confirm-yes">${opts.confirmLabel || 'Confirm'}</button>
        </div>
      </div>
    `;

    const dismiss = () => {
      el.classList.remove('toast-in');
      el.classList.add('toast-out');
      setTimeout(() => el.remove(), 300);
    };

    el.querySelector('.toast-confirm-yes').addEventListener('click', () => {
      dismiss();
      if (onConfirm) onConfirm();
    });
    el.querySelector('.toast-confirm-no').addEventListener('click', () => {
      dismiss();
      if (onCancel) onCancel();
    });

    c.appendChild(el);
    requestAnimationFrame(() => requestAnimationFrame(() => el.classList.add('toast-in')));
  };

})();

let token = localStorage.getItem('token');

// ── Device fingerprint for 6-hour cross-device logout lock ───────────────────
function getDeviceFingerprint() {
  const nav = window.navigator;
  const raw = [
    nav.userAgent,
    nav.language,
    nav.hardwareConcurrency || '',
    screen.width, screen.height, screen.colorDepth,
    nav.platform || '',
    new Date().getTimezoneOffset(),
  ].join('|');
  let hash = 0;
  for (let i = 0; i < raw.length; i++) {
    hash = ((hash << 5) - hash + raw.charCodeAt(i)) | 0;
  }
  return 'fp_' + Math.abs(hash).toString(16);
}



// ══════════════════════════════════════════════════════════════════════════════
//  OFFLINE LOGIN MODULE
//  - On successful online login, saves a secure profile to localStorage
//  - On offline login attempt, verifies against the cached profile
//  - Uses SHA-256 hashing (no plaintext passwords ever stored)
//  - Supports all roles: admin, lecturer, employee, student
// ══════════════════════════════════════════════════════════════════════════════

const OFFLINE_LOGIN_KEY = 'dikly_offline_profiles';  // stores cached user profiles
const OFFLINE_LOGIN_MAX_AGE_DAYS = 30;               // cached profile expires after 30 days

// ── Hash a password with SHA-256 (async, no library needed) ──────────────────
// crypto.subtle only exists in a secure context (HTTPS/localhost); dikly.sbs
// always qualifies, but a defensive fallback costs nothing and means a
// missing/blocked Web Crypto API degrades to a weaker hash instead of
// silently killing offline-profile caching outright.
function _fallbackHash(str) {
  let h1 = 0xdeadbeef, h2 = 0x41c6ce57;
  for (let i = 0; i < str.length; i++) {
    const ch = str.charCodeAt(i);
    h1 = Math.imul(h1 ^ ch, 2654435761);
    h2 = Math.imul(h2 ^ ch, 1597334677);
  }
  h1 = Math.imul(h1 ^ (h1 >>> 16), 2246822507) ^ Math.imul(h2 ^ (h2 >>> 13), 3266489909);
  h2 = Math.imul(h2 ^ (h2 >>> 16), 2246822507) ^ Math.imul(h1 ^ (h1 >>> 13), 3266489909);
  return (h1 >>> 0).toString(16).padStart(8, '0') + (h2 >>> 0).toString(16).padStart(8, '0');
}

async function hashPassword(password) {
  const salted = password + 'DIKLY_SALT_2025'; // salted hash
  if (!window.crypto?.subtle) {
    console.warn('[OfflineLogin] crypto.subtle unavailable — using fallback hash');
    return 'fb1:' + _fallbackHash(salted);
  }
  const encoder = new TextEncoder();
  const data = encoder.encode(salted);
  const hashBuffer = await crypto.subtle.digest('SHA-256', data);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
}

// ── Save user profile after successful online login ───────────────────────────
// Returns true/false so callers can tell the user when caching genuinely
// failed, instead of them only discovering it's broken the next time they
// need offline access and get "No offline profile found."
async function saveOfflineProfile(credentials, userData) {
  try {
    const profiles = JSON.parse(localStorage.getItem(OFFLINE_LOGIN_KEY) || '{}');
    const profileKey = buildProfileKey(credentials);
    const passwordHash = await hashPassword(credentials.password);

    profiles[profileKey] = {
      passwordHash,
      user: {
        id: userData.user.id || userData.user._id,
        name: userData.user.name,
        email: userData.user.email,
        role: userData.user.role,
        isApproved: userData.user.isApproved,
        indexNumber: userData.user.indexNumber || null,
        employeeId: userData.user.employeeId || null,
        company: userData.user.company,
        department: userData.user.department || null,
        profilePhoto: userData.user.profilePhoto || null,
        lastLoginAt: userData.user.lastLoginAt || null,
      },
      token: userData.token,           // cached JWT (may expire but used for UI)
      refreshToken: userData.refreshToken || null, // renews the JWT on reconnect
      trial: userData.trial || null,
      savedAt: Date.now(),
    };

    localStorage.setItem(OFFLINE_LOGIN_KEY, JSON.stringify(profiles));
    console.log('[OfflineLogin] Profile cached for', credentials.email || credentials.indexNumber);
    return true;
  } catch (e) {
    console.warn('[OfflineLogin] Failed to save profile:', e);
    return false;
  }
}

// ── Build a unique key per user identity ─────────────────────────────────────
function buildProfileKey(credentials) {
  if (credentials.indexNumber) {
    return `student::${credentials.indexNumber}::${(credentials.institutionCode || '').toUpperCase()}`;
  }
  if (credentials.employeeId || (credentials.loginRole === 'employee')) {
    return `employee::${(credentials.email || '').toLowerCase()}::${(credentials.institutionCode || '').toUpperCase()}`;
  }
  const role = credentials.loginRole || 'admin';
  return `${role}::${(credentials.email || '').toLowerCase()}`;
}

// ── Attempt offline login ─────────────────────────────────────────────────────
async function attemptOfflineLogin(credentials) {
  try {
    const profiles = JSON.parse(localStorage.getItem(OFFLINE_LOGIN_KEY) || '{}');
    const profileKey = buildProfileKey(credentials);
    const profile = profiles[profileKey];

    if (!profile) {
      throw new Error('No offline profile found. Please login online at least once first.');
    }

    // Check if profile has expired
    const ageMs = Date.now() - profile.savedAt;
    const ageDays = ageMs / (1000 * 60 * 60 * 24);
    if (ageDays > OFFLINE_LOGIN_MAX_AGE_DAYS) {
      throw new Error('Offline session expired. Please connect to the internet to login.');
    }

    // Verify password hash
    const enteredHash = await hashPassword(credentials.password);
    if (enteredHash !== profile.passwordHash) {
      throw new Error('Wrong email or password.');
    }

    // NOTE: access tokens only live ~15 minutes, so the cached JWT is almost
    // always expired by the time someone needs offline login. That is fine:
    // offline pages read cached data, and the moment connectivity returns the
    // api() 401→refresh flow renews the token using the cached refresh token
    // (valid for 30 days). Never reject offline login for an expired JWT.
    try {
      const jwtPayload = JSON.parse(atob(profile.token.split('.')[1]));
      if (jwtPayload.exp && jwtPayload.exp * 1000 < Date.now()) {
        console.log('[OfflineLogin] Cached JWT expired — continuing offline; will refresh on reconnect');
      }
    } catch (_) { /* malformed JWT — server will reject it on first online call */ }

    // Return a fake login response matching the real API shape
    console.log('[OfflineLogin] Offline login successful for', profileKey);
    return {
      token: profile.token,
      refreshToken: profile.refreshToken || null,
      user: profile.user,
      trial: profile.trial,
      offlineMode: true,   // flag so app knows we're offline
    };
  } catch (e) {
    throw e;
  }
}

// ── Clear a specific offline profile (on logout) ──────────────────────────────
function clearOfflineProfile(userRole, email, indexNumber, institutionCode) {
  try {
    const profiles = JSON.parse(localStorage.getItem(OFFLINE_LOGIN_KEY) || '{}');
    const key = buildProfileKey({ loginRole: userRole, email, indexNumber, institutionCode });
    delete profiles[key];
    localStorage.setItem(OFFLINE_LOGIN_KEY, JSON.stringify(profiles));
  } catch (e) {
    console.warn('[OfflineLogin] Could not clear profile:', e);
  }
}

// ── Clear offline profile by user ID (used on logout — no need to reconstruct key) ──
function clearOfflineProfileById(userId) {
  try {
    const profiles = JSON.parse(localStorage.getItem(OFFLINE_LOGIN_KEY) || '{}');
    let changed = false;
    for (const key of Object.keys(profiles)) {
      const uid = profiles[key]?.user?.id || profiles[key]?.user?._id;
      if (uid && uid.toString() === userId.toString()) {
        delete profiles[key];
        changed = true;
      }
    }
    if (changed) localStorage.setItem(OFFLINE_LOGIN_KEY, JSON.stringify(profiles));
  } catch (e) {
    console.warn('[OfflineLogin] Could not clear profile by ID:', e);
  }
}

// ── Show offline login notice on the form ─────────────────────────────────────
function showOfflineLoginNotice(containerId) {
  const existing = document.getElementById('offline-login-notice');
  if (existing) return;
  const notice = document.createElement('div');
  notice.id = 'offline-login-notice';
  notice.style.cssText = [
    'background:#fef3c7','color:#92400e','border:1px solid #fbbf24',
    'border-radius:8px','padding:10px 14px','font-size:12px',
    'margin-bottom:12px','display:flex','align-items:center','gap:8px'
  ].join(';');
  notice.innerHTML = `
    <span style="font-size:16px">📶</span>
    <span><strong>You're offline.</strong> Signing in with your saved credentials.</span>
  `;
  const container = document.getElementById(containerId);
  if (container) container.prepend(notice);
}

function removeOfflineLoginNotice() {
  const n = document.getElementById('offline-login-notice');
  if (n) n.remove();
}

// ══════════════════════════════════════════════════════════════════════════════
//  OFFLINE SUPPORT MODULE
//  - Detects online/offline state and shows a banner
//  - Caches read data (sessions, courses, attendance) in localStorage
//  - Queues write actions (start/stop session, manual mark, student mark)
//  - Auto-syncs the queue the moment connection is restored
// ══════════════════════════════════════════════════════════════════════════════

const OFFLINE_CACHE_KEY   = 'edu_offline_cache';
const OFFLINE_QUEUE_KEY   = 'edu_offline_queue';
const OFFLINE_BANNER_ID   = 'offline-banner';

// ── Helpers ──────────────────────────────────────────────────────────────────
// navigator.onLine is true even when connected to an ESP32 hotspot with no
// internet. We do a real server ping so login correctly falls back to offline
// mode when the DIKLY server is unreachable (e.g. device is on ESP32 WiFi).
let _serverReachable = null; // null = unknown, true/false = cached result
let _serverCheckTs   = 0;
const SERVER_CHECK_TTL = 8000; // re-check every 8 s

async function checkServerReachable() {
  try {
    const ctrl = new AbortController();
    const tid   = setTimeout(() => ctrl.abort(), 8000);
    const res   = await fetch(API + '/health', { method: 'GET', signal: ctrl.signal, cache: 'no-store' });
    clearTimeout(tid);
    return res.ok;
  } catch (_) {
    return false;
  }
}

function isOnline() {
  // Fast path: if browser says offline, trust it immediately
  if (!navigator.onLine) return false;
  // Otherwise return the last known server reachability result.
  // Callers that need a fresh check should use isOnlineAsync().
  return _serverReachable !== false;
}

async function isOnlineAsync() {
  if (!navigator.onLine) { _serverReachable = false; return false; }
  const now = Date.now();
  if (now - _serverCheckTs < SERVER_CHECK_TTL && _serverReachable !== null) {
    return _serverReachable;
  }
  _serverReachable = await checkServerReachable();
  _serverCheckTs   = now;
  return _serverReachable;
}

// ── Offline fallback for logins ──────────────────────────────────────────────
// isOnlineAsync() can report a stale "online" — its result is cached for 8 s,
// and right after airplane mode iOS often keeps navigator.onLine === true.
// When that happens the online login request itself fails with a network
// error; instead of dead-ending on "Network error", retry against the
// offline profile store.
function _isNetworkError(e) {
  const m = String((e && e.message) || '').toLowerCase();
  return m.includes('failed to fetch') || m.includes('networkerror') || m.includes('network error')
      || m.includes('load failed')     || m.includes('network request failed')
      || m.includes('timed out')       || m.includes('timeout')
      || m.includes('you are offline') || m.includes('abort');
}

async function loginOnlineWithOfflineFallback(credentials, formId) {
  try {
    const data = await initiate2FA(credentials);
    const cached = await saveOfflineProfile(credentials, data);
    if (!cached) {
      showToastNotif('Could not save offline access on this device — you may need to reconnect to sign in next time.', 'warn');
    }
    return data;
  } catch (e) {
    if (!_isNetworkError(e)) throw e;
    // Server became unreachable mid-login — remember that and go offline.
    _serverReachable = false;
    _serverCheckTs   = Date.now();
    showOfflineLoginNotice(formId);
    return attemptOfflineLogin(credentials);
  }
}

function offlineCache(key, data) {
  try {
    const store = JSON.parse(localStorage.getItem(OFFLINE_CACHE_KEY) || '{}');
    // Prune old attendees_ entries if we have more than 20 (saves localStorage space)
    const attendeeKeys = Object.keys(store).filter(k => k.startsWith('attendees_'));
    if (attendeeKeys.length > 20) {
      // Remove oldest 10
      attendeeKeys.slice(0, 10).forEach(k => delete store[k]);
    }
    store[key] = { data, ts: Date.now() };
    localStorage.setItem(OFFLINE_CACHE_KEY, JSON.stringify(store));
  } catch(e) { console.warn('[Offline] Cache write failed', e); }
}

function offlineRead(key) {
  try {
    const store = JSON.parse(localStorage.getItem(OFFLINE_CACHE_KEY) || '{}');
    return store[key]?.data ?? null;
  } catch(e) { return null; }
}

function offlineEnqueue(action) {
  try {
    const q = JSON.parse(localStorage.getItem(OFFLINE_QUEUE_KEY) || '[]');
    q.push({ ...action, queuedAt: Date.now(), id: Math.random().toString(36).slice(2) });
    localStorage.setItem(OFFLINE_QUEUE_KEY, JSON.stringify(q));
    showOfflineBanner(true);
  } catch(e) { console.warn('[Offline] Queue write failed', e); }
}

function offlineQueueCount() {
  try {
    return JSON.parse(localStorage.getItem(OFFLINE_QUEUE_KEY) || '[]').length;
  } catch(e) { return 0; }
}

// ── Banner ────────────────────────────────────────────────────────────────────
function showOfflineBanner(hasPending) {
  let banner = document.getElementById(OFFLINE_BANNER_ID);
  if (!banner) {
    banner = document.createElement('div');
    banner.id = OFFLINE_BANNER_ID;
    banner.style.cssText = [
      'position:fixed','top:60px','left:0','right:0','z-index:9998',
      'display:flex','align-items:center','justify-content:center','gap:8px',
      'padding:7px 16px','font-size:12px','font-weight:600',
      'transition:all 0.3s ease','box-shadow:0 2px 8px rgba(0,0,0,0.1)'
    ].join(';');
    document.body.prepend(banner);
  }

  const count = offlineQueueCount();
  if (!isOnline()) {
    banner.style.background = '#fef3c7';
    banner.style.color = '#92400e';
    banner.style.borderBottom = '2px solid #fbbf24';
    banner.innerHTML = `
      <span>📶</span>
      <span>You're offline — changes will sync when you reconnect</span>
      ${count > 0 ? `<span style="background:#f59e0b;color:#fff;padding:2px 8px;border-radius:999px;font-size:11px">${count} pending</span>` : ''}
    `;
    banner.style.display = 'flex';
  } else if (count > 0) {
    banner.style.background = '#eff6ff';
    banner.style.color = '#1e40af';
    banner.style.borderBottom = '2px solid #93c5fd';
    banner.innerHTML = `
      <span>🔄</span>
      <span>Back online — syncing ${count} pending action${count !== 1 ? 's' : ''}…</span>
    `;
    banner.style.display = 'flex';
  } else {
    banner.style.display = 'none';
  }
}

function hideOfflineBanner() {
  const b = document.getElementById(OFFLINE_BANNER_ID);
  if (b) b.style.display = 'none';
}

// ── Auto-sync on reconnect ────────────────────────────────────────────────────
async function syncOfflineQueue() {
  const raw = localStorage.getItem(OFFLINE_QUEUE_KEY);
  if (!raw) return;
  const queue = JSON.parse(raw);
  if (!queue.length) return;

  console.log(`[Offline] Syncing ${queue.length} queued action(s)…`);
  showOfflineBanner(true);

  const remaining = [];
  for (const action of queue) {
    try {
      await api(action.url, action.options);
      console.log(`[Offline] Synced: ${action.label || action.url}`);
    } catch (e) {
      console.warn(`[Offline] Sync failed for ${action.url}:`, e.message);
      // Keep failed items if it's a server error (not 4xx client error)
      const is4xx = e.status >= 400 && e.status < 500 ||
        e.message.includes('400') || e.message.includes('409') || e.message.includes('404');
      if (!is4xx) {
        remaining.push(action);
      } else {
        console.log(`[Offline] Dropping ${action.label || action.url} — rejected by server (${e.status || e.message})`);
      }
    }
  }

  localStorage.setItem(OFFLINE_QUEUE_KEY, JSON.stringify(remaining));

  if (remaining.length === 0) {
    hideOfflineBanner();
    // Refresh whichever attendance view is active
    const active = document.querySelector('.nav-item.active')?.dataset?.view;
    if (active === 'sessions') renderSessions();
    else if (active === 'mark-attendance') renderMarkAttendance();
    showToastNotif('✅ All offline actions synced!', 'success');
  } else {
    showOfflineBanner(true);
  }
}

function showToastNotif(msg, type) {
  if (!msg) return;
  // Route through the modern stacking toast system so messages never overlap
  const t = type === 'success' ? 'success'
          : type === 'error'   ? 'error'
          : type === 'warn'    ? 'warning'
          : 'info';
  if (window.toast) { window.toast(msg, t); return; }
  // Fallback if called before the modern system is ready
  console.info('[toast]', type, msg);
}

// Alias used by Corporate Phase 1 functions (shifts, leave)
function toast(msg, type) {
  showToastNotif(msg, type === 'ok' ? 'success' : type || 'info');
}

// Listen for online/offline events
window.addEventListener('offline', () => showOfflineBanner(false));
window.addEventListener('online',  () => {
  showOfflineBanner(true);
  setTimeout(syncOfflineQueue, 800); // slight delay to ensure connection is stable
});

// Show banner on load if already offline or has queue
window.addEventListener('DOMContentLoaded', () => {
  if (!isOnline() || offlineQueueCount() > 0) showOfflineBanner(!isOnline());
});

let currentUser = null;
let currentUserTrial = null; // mirrors data.userTrial from the last /me response
let currentView = 'dashboard';
let _appOfflineMode = false; // true when logged in via cached credentials (no server reachable)

