async function _doFetch(path, options, tok) {
  const headers = { 'Content-Type': 'application/json' };
  if (tok) headers['Authorization'] = `Bearer ${tok}`;
  const ctrl = new AbortController();
  const timer = setTimeout(() => ctrl.abort(), 15000);
  try {
    const res = await fetch(`${API}${path}`, { signal: ctrl.signal, ...options, headers: { ...headers, ...options.headers } });
    clearTimeout(timer);
    return res;
  } catch (e) {
    clearTimeout(timer);
    if (e.name === 'AbortError') throw new Error('Request timed out. Check your connection and try again.');
    throw e;
  }
}

// ── Session expiry warning ────────────────────────────────────────────────────
let _expiryTimer = null;
let _expiryBannerVisible = false;

function _scheduleExpiryWarning() {
  if (_expiryTimer) { clearTimeout(_expiryTimer); _expiryTimer = null; }
  if (!token) return;
  try {
    const payload = JSON.parse(atob(token.split('.')[1]));
    const msLeft  = payload.exp * 1000 - Date.now();
    const warnAt  = msLeft - 2 * 60 * 1000; // 2 min before expiry
    if (warnAt <= 0) return;
    _expiryTimer = setTimeout(_showExpiryBanner, warnAt);
  } catch (_) {}
}

function _showExpiryBanner() {
  if (_expiryBannerVisible || !currentUser) return;
  _expiryBannerVisible = true;
  const banner = document.createElement('div');
  banner.id = 'session-expiry-banner';
  banner.style.cssText = 'position:fixed;bottom:80px;left:50%;transform:translateX(-50%);z-index:9999;background:#1e293b;color:#fff;padding:12px 20px;border-radius:12px;display:flex;align-items:center;gap:12px;box-shadow:0 4px 20px rgba(0,0,0,.35);font-size:13px;max-width:360px;width:90%';
  banner.innerHTML = `
    <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#fbbf24" stroke-width="2"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>
    <span style="flex:1">Your session expires in 2 minutes</span>
    <button onclick="stayLoggedIn()" style="background:#3b82f6;color:#fff;border:none;padding:6px 12px;border-radius:7px;font-size:12px;font-weight:600;cursor:pointer;white-space:nowrap">Stay logged in</button>
  `;
  document.body.appendChild(banner);
  setTimeout(_dismissExpiryBanner, 90 * 1000);
}

function _dismissExpiryBanner() {
  const el = document.getElementById('session-expiry-banner');
  if (el) el.remove();
  _expiryBannerVisible = false;
}

async function stayLoggedIn() {
  _dismissExpiryBanner();
  const ok = await _tryRefreshToken();
  if (ok) {
    _scheduleExpiryWarning();
    showToastNotif('Session extended', 'success');
  } else {
    showToastNotif('Could not extend session — please log in again', 'error');
  }
}

let _refreshing = null;
async function _tryRefreshToken() {
  const rt = localStorage.getItem('refreshToken');
  if (!rt) return false;
  try {
    // Unlike every other request (routed through _doFetch's 15s
    // AbortController), this fetch had no timeout — and api() awaits the
    // single shared `_refreshing` promise on every 401, app-wide. A stalled
    // refresh request (not an outright network error, just a connection
    // that never completes) hung that shared promise forever, freezing
    // every authenticated API call in the app on an indefinite "Loading…"
    // with nothing in the console to explain why.
    const ctrl = new AbortController();
    const timer = setTimeout(() => ctrl.abort(), 15000);
    let r;
    try {
      r = await fetch(`${API}/api/auth/refresh`, {
        method: 'POST',
        signal: ctrl.signal,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ refreshToken: rt }),
      });
    } finally {
      clearTimeout(timer);
    }
    if (!r.ok) return false;
    const d = await r.json();
    token = d.token;
    localStorage.setItem('token', token);
    if (d.refreshToken) localStorage.setItem('refreshToken', d.refreshToken);
    _scheduleExpiryWarning();
    return true;
  } catch { return false; }
}

async function api(path, options = {}) {
  let res = await _doFetch(path, options, token);
  if (res.status === 401 && path !== '/api/auth/refresh') {
    if (!_refreshing) _refreshing = _tryRefreshToken().finally(() => { _refreshing = null; });
    const refreshed = await _refreshing;
    if (refreshed) {
      res = await _doFetch(path, options, token);
    }
  }
  if (res.headers.get('content-type')?.includes('application/json')) {
    const data = await res.json();
    if (!res.ok) {
      // 402 = institution or personal subscription expired — hard full-screen block
      if (res.status === 402 && data.subscriptionExpired) {
        showSubscriptionBlock(data.message, data.isAdmin);
        throw new Error(data.message || 'Subscription expired');
      }
      // Legacy 403 subscription gate (old middleware responses)
      if (res.status === 403 && (data.subscriptionExpired || data.subscriptionRequired)) {
        showSubscriptionBlock(data.message, data.isAdmin);
        throw new Error(data.message || data.error || 'Subscription required');
      }
      const err = new Error(data.message || data.error || 'Request failed');
      err.status = res.status;
      err.data   = data;
      throw err;
    }
    return data;
  }
  if (!res.ok) throw new Error('Request failed');
  return res;
}

async function apiUpload(urlPath, formData, method = 'POST') {
  const headers = {};
  if (token) headers['Authorization'] = `Bearer ${token}`;
  const res = await fetch(`${API}${urlPath}`, { method, headers, body: formData });
  if (res.headers.get('content-type')?.includes('application/json')) {
    const data = await res.json();
    if (!res.ok) {
      if ((res.status === 402 || res.status === 403) && (data.subscriptionExpired || data.subscriptionRequired)) {
        showSubscriptionBlock(data.message, data.isAdmin);
        throw new Error(data.error || 'Subscription expired');
      }
      throw new Error(data.error || data.message || 'Request failed');
    }
    return data;
  }
  if (!res.ok) throw new Error('Request failed');
  return res;
}

let _subBlockActive = false;
function showSubscriptionBlock(message, isAdmin) {
  if (_subBlockActive) return;
  _subBlockActive = true;

  const msg = message || 'Your subscription has expired. Access is suspended.';
  const isAdminUser = isAdmin || (currentUser && currentUser.role === 'admin');
  // Every role except HOD has its own self-serve Paystack subscription (see
  // renderSubscription's "My Subscription" branch) -- HOD access rides on
  // the institution's plan with no individual pay option, so that's the
  // only role still pointed at "ask your admin" instead of a pay button.
  const isHodUser = currentUser && currentUser.role === 'hod';
  const canSelfServe = !isHodUser;
  const institutionName = currentUser?.company?.name || currentUser?.institutionName || '';

  // Remove any existing block overlay
  const existing = document.getElementById('_sub-block-overlay');
  if (existing) existing.remove();

  const overlay = document.createElement('div');
  overlay.id = '_sub-block-overlay';
  overlay.style.cssText = [
    'position:fixed', 'inset:0', 'z-index:99999',
    'background:rgba(15,23,42,0.97)',
    'display:flex', 'align-items:center', 'justify-content:center',
    'padding:24px', 'box-sizing:border-box',
  ].join(';');

  overlay.innerHTML = `
    <div style="background:#fff;border-radius:16px;max-width:460px;width:100%;padding:40px 32px;text-align:center;box-shadow:0 25px 60px rgba(0,0,0,.5)">
      <div style="width:72px;height:72px;border-radius:50%;background:#fef2f2;display:flex;align-items:center;justify-content:center;margin:0 auto 20px;font-size:32px">🔒</div>
      <h2 style="margin:0 0 8px;font-size:22px;font-weight:700;color:#0f172a">Subscription Expired</h2>
      ${institutionName ? `<p style="margin:0 0 16px;font-size:13px;font-weight:600;color:#6366f1;letter-spacing:.4px;text-transform:uppercase">${esc(institutionName)}</p>` : ''}
      <p style="margin:0 0 28px;font-size:14px;color:#475569;line-height:1.6">${esc(msg)}</p>
      ${canSelfServe
        ? `<div style="display:flex;flex-direction:column;gap:10px">
            <button onclick="(function(){var o=document.getElementById('_sub-block-overlay');if(o)o.remove();_subBlockActive=false;document.body.style.overflow='';navigateTo('subscription');})();"
              style="background:#6366f1;color:#fff;border:none;border-radius:8px;padding:12px 24px;font-size:14px;font-weight:600;cursor:pointer;width:100%">
              ${isAdminUser ? 'Renew Subscription' : 'Subscribe Now'}
            </button>
            <p style="margin:0;font-size:12px;color:#94a3b8">${isAdminUser ? 'Renewing will immediately restore access for all users.' : 'Subscribing restores your personal access immediately — paid via Paystack.'}</p>
          </div>`
        : `<div style="background:#f8fafc;border-radius:8px;padding:14px 16px;text-align:left">
            <p style="margin:0 0 4px;font-size:13px;font-weight:600;color:#0f172a">What to do</p>
            <p style="margin:0;font-size:13px;color:#64748b;line-height:1.5">Contact your <strong>institution administrator</strong> and ask them to renew the DIKLY subscription. All features will be restored immediately after renewal.</p>
          </div>`
      }
      <p style="margin:20px 0 0;font-size:12px;color:#94a3b8">Need help? Contact support at <strong>support@dikly.sbs</strong></p>
    </div>
  `;

  document.body.appendChild(overlay);

  // Prevent any interaction with the app behind the overlay
  document.body.style.overflow = 'hidden';
}

// Legacy alias — kept for any old callers
function showSubscriptionGate(message) {
  const isAdmin = currentUser && currentUser.role === 'admin';
  showSubscriptionBlock(message, isAdmin);
}

function timeAgo(dateStr) {
  if (!dateStr) return '';
  const diff = Math.floor((Date.now() - new Date(dateStr)) / 1000);
  if (diff < 60) return 'just now';
  if (diff < 3600) return Math.floor(diff/60) + 'm ago';
  if (diff < 86400) return Math.floor(diff/3600) + 'h ago';
  if (diff < 604800) return Math.floor(diff/86400) + 'd ago';
  return new Date(dateStr).toLocaleDateString();
}

// ── Date formatting helper ───────────────────────────────────────────────────
function fmtDate(d) {
  if (!d) return '—';
  return new Date(d).toLocaleString('en-GB', {
    day: 'numeric', month: 'short', year: 'numeric',
    hour: '2-digit', minute: '2-digit'
  });
}

// ── HTML escape helper ────────────────────────────────────────────────────────
function esc(s) {
  return (s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

function showError(msg) {
  const el = document.getElementById('auth-error');
  el.textContent = msg;
  el.style.display = 'block';
  setTimeout(() => el.style.display = 'none', 5000);
}

let selectedPortalType = 'admin-corporate';

// ── Mode selector (Corporate / Academic two-step flow) ────────────────────────
let _selectedMode = null;
function selectMode(mode) {
  const tglCorp  = document.getElementById('mode-tgl-corp');
  const tglAcad  = document.getElementById('mode-tgl-acad');
  const cardsCorp = document.getElementById('portal-cards-corp');
  const cardsAcad = document.getElementById('portal-cards-acad');
  if (!tglCorp || !tglAcad) return;

  // Collapse both first
  if (cardsCorp) cardsCorp.classList.remove('visible');
  if (cardsAcad) cardsAcad.classList.remove('visible');
  tglCorp.classList.remove('active-corp');
  tglAcad.classList.remove('active-acad');

  // Toggle off if same mode tapped again
  if (_selectedMode === mode) { _selectedMode = null; return; }

  const delay = _selectedMode !== null ? 120 : 0;
  _selectedMode = mode;

  setTimeout(() => {
    if (mode === 'corp') {
      tglCorp.classList.add('active-corp');
      if (cardsCorp) cardsCorp.classList.add('visible');
    } else {
      tglAcad.classList.add('active-acad');
      if (cardsAcad) cardsAcad.classList.add('visible');
    }
  }, delay);
}

function selectPortal(type) {
  selectedPortalType = type;
  document.getElementById('portal-selector').classList.add('hidden');
  if (type === 'admin-corporate' || type === 'admin-academic' || type === 'manager') {
    const isAcademic = type === 'admin-academic';
    const isManager  = type === 'manager';
    // selectedPortalType stays as 'manager' — used in handleAdminLogin to send loginRole:'manager'
    const portalSel = document.getElementById('portal-selector');
    if (portalSel) portalSel.classList.add('hidden');
    const adminAuth = document.getElementById('admin-auth');
    if (adminAuth) adminAuth.classList.remove('hidden');
    // Update labels
    const titleEl = document.getElementById('admin-portal-title');
    if (titleEl) titleEl.textContent = isManager ? 'Manager Portal' : isAcademic ? 'Institution Admin' : 'Admin Portal';
    const subtitleEl = document.getElementById('admin-portal-subtitle');
    if (subtitleEl) subtitleEl.textContent = isManager ? 'Corporate Manager Access' : isAcademic ? 'Academic Institution Admin' : 'Corporate Admin Access';
    const labelEl = document.getElementById('admin-reg-company-label');
    if (labelEl) labelEl.textContent = isAcademic ? 'Institution Name' : 'Company Name';
    const placeholderEl = document.getElementById('admin-reg-company');
    if (placeholderEl) placeholderEl.placeholder = isAcademic ? 'Your institution name' : 'Your company name';
  } else if (type === 'lecturer') {
    document.getElementById('lecturer-auth').classList.remove('hidden');
  } else if (type === 'hod') {
    document.getElementById('hod-auth').classList.remove('hidden');
  } else if (type === 'employee') {
    document.getElementById('employee-auth').classList.remove('hidden');
  } else if (type === 'student') {
    document.getElementById('student-auth').classList.remove('hidden');
  } else {
    // Unknown portal type — go back to selector safely
    document.getElementById('portal-selector').classList.remove('hidden');
  }
}

function showPortalSelector() {
  document.getElementById('admin-auth').classList.add('hidden');
  document.getElementById('lecturer-auth').classList.add('hidden');
  document.getElementById('hod-auth').classList.add('hidden');
  document.getElementById('employee-auth').classList.add('hidden');
  document.getElementById('student-auth').classList.add('hidden');
  document.getElementById('portal-selector').classList.remove('hidden');
  const mrf = document.getElementById('manager-register-form'); if (mrf) mrf.classList.add('hidden');
  document.querySelectorAll('.auth-container input').forEach(i => i.value = '');
  document.querySelectorAll('.error-msg').forEach(e => e.style.display = 'none');
  selectedPortalType = null;
}

function backToPortalSelector() {
  showPortalSelector();
}

function showAdminRegister() {
  document.getElementById('admin-login-form').classList.add('hidden');
  document.getElementById('admin-auth-error').style.display = 'none';
  let form;
  if (selectedPortalType === 'manager') {
    document.getElementById('admin-register-form').classList.add('hidden');
    form = document.getElementById('manager-register-form');
    form.classList.remove('hidden');
  } else {
    document.getElementById('manager-register-form').classList.add('hidden');
    form = document.getElementById('admin-register-form');
    form.classList.remove('hidden');
  }
  _playAuthTransition('admin-auth', 'register', form);
}

function showAdminLogin() {
  document.getElementById('admin-register-form').classList.add('hidden');
  document.getElementById('manager-register-form').classList.add('hidden');
  const form = document.getElementById('admin-login-form');
  form.classList.remove('hidden');
  document.getElementById('admin-auth-error').style.display = 'none';
  const f = document.getElementById('admin-forgot-form'); if(f) f.classList.add('hidden');
  _playAuthTransition('admin-auth', 'login', form);
}

async function handleManagerRegister() {
  try {
    const name            = document.getElementById('manager-reg-name').value.trim();
    const email           = document.getElementById('manager-reg-email').value.trim();
    const phone           = document.getElementById('manager-reg-phone').value.trim();
    const password        = document.getElementById('manager-reg-password').value;
    const institutionCode = document.getElementById('manager-reg-code').value.trim().toUpperCase();
    if (!name || !email || !password || !institutionCode) {
      return showAdminError('Please fill in all required fields');
    }
    if (password.length < 8) {
      return showAdminError('Password must be at least 8 characters');
    }
    const data = await api('/api/auth/register-manager', {
      method: 'POST',
      body: JSON.stringify({ name, email, phone: phone || undefined, password, institutionCode }),
    });
    promptEmailVerification({
      email: data.email,
      institutionCode,
      onVerified: (verifyData) => {
        const el = document.getElementById('admin-auth-error');
        el.textContent = verifyData.message || 'Registration submitted! Your account is pending admin approval.';
        el.style.background = '#f0fdf4';
        el.style.color = '#15803d';
        el.style.border = '1px solid #86efac';
        el.style.display = 'block';
        showAdminLogin();
      },
    });
  } catch (e) {
    showAdminError(e.message || 'Registration failed');
  }
}

function showAdminForgot() {
  document.getElementById('admin-login-form').classList.add('hidden');
  document.getElementById('admin-register-form').classList.add('hidden');
  const f = document.getElementById('admin-forgot-form'); if(f) f.classList.remove('hidden');
  const rc = document.getElementById('admin-reset-code-group'); if(rc) rc.classList.add('hidden');
  const np = document.getElementById('admin-new-password-group'); if(np) np.classList.add('hidden');
  const btn = document.getElementById('admin-forgot-btn'); if(btn) btn.textContent = 'Request Reset Code';
  adminForgotStep = 'request';
  _playAuthTransition('admin-auth', 'forgot', f);
}

let adminForgotEmail = '', adminForgotEmailAddr = '', adminForgotStep = 'request';
async function handleAdminForgotPassword() {
  function setAdminForgotMsg(msg, isSuccess) {
    let el = document.getElementById('admin-forgot-msg');
    if (!el) {
      el = document.createElement('div');
      el.id = 'admin-forgot-msg';
      el.style.cssText = 'padding:10px 14px;border-radius:8px;font-size:13px;margin-bottom:12px;display:none';
      const btn = document.getElementById('admin-forgot-btn');
      if (btn) btn.parentNode.insertBefore(el, btn);
    }
    el.textContent = msg;
    el.style.background = isSuccess ? '#f0fdf4' : '#fef2f2';
    el.style.color = isSuccess ? '#15803d' : '#dc2626';
    el.style.border = isSuccess ? '1px solid #86efac' : '1px solid #fca5a5';
    el.style.display = 'block';
  }

  if (adminForgotStep === 'request') {
    const phone = document.getElementById('admin-forgot-phone').value.trim();
    const email = document.getElementById('admin-forgot-email')?.value?.trim();
    if (!phone && !email) return setAdminForgotMsg('Please enter your phone number or email.', false);
    const btn = document.getElementById('admin-forgot-btn');
    btn.textContent = 'Sending...'; btn.disabled = true;
    try {
      const data = await api('/api/auth/forgot-password-admin', { method: 'POST', body: JSON.stringify({ phone: phone || undefined, email: email || undefined }) });
      adminForgotEmail = phone || ''; adminForgotEmailAddr = email || ''; adminForgotStep = 'reset';
      document.getElementById('admin-reset-code-group').classList.remove('hidden');
      document.getElementById('admin-new-password-group').classList.remove('hidden');
      btn.textContent = 'Reset Password'; btn.disabled = false;
      setAdminForgotMsg('📱 ' + (data.message || 'Reset code sent to your phone via SMS.'), true);
    } catch(e) { btn.textContent = 'Request Reset Code'; btn.disabled = false; setAdminForgotMsg(e.message, false); }
  } else {
    const resetCode = document.getElementById('admin-reset-code').value.trim();
    const newPassword = document.getElementById('admin-new-password').value;
    if (!resetCode || !newPassword) return setAdminForgotMsg('Please enter the reset code and new password', false);
    if (newPassword.length < 8) return setAdminForgotMsg('Password must be at least 8 characters', false);
    const btn = document.getElementById('admin-forgot-btn');
    btn.textContent = 'Resetting...'; btn.disabled = true;
    try {
      await api('/api/auth/reset-password-email', { method: 'POST', body: JSON.stringify({ phone: adminForgotEmail || undefined, email: adminForgotEmailAddr || undefined, resetCode, newPassword }) });
      adminForgotStep = 'request';
      setAdminForgotMsg('✅ Password reset! Redirecting to sign in...', true);
      setTimeout(() => { showAdminLogin(); }, 1800);
    } catch(e) { btn.textContent = 'Reset Password'; btn.disabled = false; setAdminForgotMsg(e.message, false); }
  }
}

function showAdminError(msg) {
  const el = document.getElementById('admin-auth-error');
  if (!el) return;
  el.textContent = msg;
  el.style.display = 'block';
  el.style.background = '';
  el.style.color = '';
  // Shake + keep visible for 8 seconds
  el.classList.remove('shake');
  void el.offsetWidth; // force reflow to restart animation
  el.classList.add('shake');
  clearTimeout(el._hideTimer);
  el._hideTimer = setTimeout(() => { el.style.display = 'none'; el.classList.remove('shake'); }, 8000);
}

