async function renderHodSessions() {
  const content = document.getElementById('main-content');
  content.innerHTML = '<div class="loading">Loading sessions…</div>';
  let sessions = [], _isOff = false;
  if (!isOnline()) {
    const _c = offlineRead('hod_sessions');
    if (_c) { sessions = _c.sessions || []; _isOff = true; }
    else { content.innerHTML = `<div style="text-align:center;padding:60px 20px"><div style="font-size:48px;margin-bottom:12px">📡</div><div style="font-size:18px;font-weight:700">You're Offline</div><p style="color:var(--text-muted);margin-top:8px">Connect once while online to cache this page.</p></div>`; return; }
  } else {
    try {
      const dept = currentUser.department ? '&department=' + encodeURIComponent(currentUser.department) : '';
      const data = await api('/api/attendance-sessions?limit=100' + dept);
      sessions = data.sessions || [];
      offlineCache('hod_sessions', data);
    } catch(e) {
      const _c = offlineRead('hod_sessions');
      if (_c) { sessions = _c.sessions || []; _isOff = true; }
      else { content.innerHTML = `<div class="card"><p style="color:#ef4444;">${e.message}</p></div>`; return; }
    }
  }
  { const data = { sessions }; /* compat */
    content.innerHTML = `
      <div class="page-header" style="display:flex;justify-content:space-between;align-items:flex-start;flex-wrap:wrap;gap:10px;">
        <div><h2>All Sessions</h2><p>Department-wide attendance sessions — ${sessions.length} total</p></div>
      </div>
      <div style="overflow-x:auto;">
        <table style="width:100%;border-collapse:collapse;font-size:13px;">
          <thead>
            <tr style="border-bottom:2px solid var(--border);">
              <th style="text-align:left;padding:10px 12px;font-weight:700;color:var(--text-muted);font-size:11px;text-transform:uppercase;">Session</th>
              <th style="text-align:left;padding:10px 12px;font-weight:700;color:var(--text-muted);font-size:11px;text-transform:uppercase;">Lecturer</th>
              <th style="text-align:left;padding:10px 12px;font-weight:700;color:var(--text-muted);font-size:11px;text-transform:uppercase;">Attendance</th>
              <th style="text-align:left;padding:10px 12px;font-weight:700;color:var(--text-muted);font-size:11px;text-transform:uppercase;">Date</th>
              <th style="text-align:left;padding:10px 12px;font-weight:700;color:var(--text-muted);font-size:11px;text-transform:uppercase;">Status</th>
            </tr>
          </thead>
          <tbody>
            ${sessions.length === 0 ? '<tr><td colspan="5" style="padding:24px;text-align:center;color:var(--text-muted);">No sessions yet.</td></tr>' :
              sessions.map(s => `
                <tr style="border-bottom:1px solid var(--border);">
                  <td style="padding:10px 12px;font-weight:600;">${s.title || s.courseName || 'Session'}</td>
                  <td style="padding:10px 12px;color:var(--text-muted);">${s.createdBy?.name || '—'}</td>
                  <td style="padding:10px 12px;">${s.attendanceCount ?? s.records?.length ?? '—'}</td>
                  <td style="padding:10px 12px;color:var(--text-muted);font-size:12px;">${fmtDate(s.createdAt)}</td>
                  <td style="padding:10px 12px;"><span class="tag ${['active','live','paused','locked'].includes(s.status) ? 'tag-green' : 'tag-gray'}">${['active','live','paused','locked'].includes(s.status) ? 'Live' : 'Ended'}</span></td>
                </tr>`).join('')}
          </tbody>
        </table>
      </div>`+ (_isOff ? `<div style="display:inline-flex;align-items:center;gap:6px;background:#fef3c7;border:1px solid #fde68a;border-radius:20px;padding:3px 12px;font-size:11.5px;font-weight:600;color:#92400e;margin-bottom:10px">📡 Offline · Cached data</div>` : '');
  }
}

async function renderLecturerActivity(viewAs) {
  const content = document.getElementById('main-content');
  content.innerHTML = '<div class="loading">Loading lecturer activity…</div>';

  // Default date range: last 6 months
  const now  = new Date();
  const sixMoAgo = new Date(now.getFullYear(), now.getMonth() - 6, now.getDate());
  let fromDate = sixMoAgo.toISOString().slice(0, 10);
  let toDate   = now.toISOString().slice(0, 10);
  let deptFilter = '';

  async function load() {
    let url = `/api/hod/lecturer-activity?from=${fromDate}&to=${toDate}`;
    if (deptFilter) url += `&department=${encodeURIComponent(deptFilter)}`;
    try {
      const data = await api(url);
      render(data);
    } catch(e) {
      content.innerHTML = `<div class="card"><p style="color:#ef4444">${e.message || 'Failed to load'}</p></div>`;
    }
  }

  function activityDot(lastActiveAt) {
    if (!lastActiveAt) return '<span style="width:8px;height:8px;border-radius:50%;background:#94a3b8;display:inline-block;margin-right:5px;" title="Never active"></span>';
    const days = Math.floor((Date.now() - new Date(lastActiveAt)) / 86400000);
    if (days <= 7)  return '<span style="width:8px;height:8px;border-radius:50%;background:#22c55e;display:inline-block;margin-right:5px;" title="Active this week"></span>';
    if (days <= 30) return '<span style="width:8px;height:8px;border-radius:50%;background:#f59e0b;display:inline-block;margin-right:5px;" title="Active this month"></span>';
    return '<span style="width:8px;height:8px;border-radius:50%;background:#ef4444;display:inline-block;margin-right:5px;" title="Inactive 30+ days"></span>';
  }

  function lastActiveLabel(lastActiveAt) {
    if (!lastActiveAt) return 'Never active';
    const days = Math.floor((Date.now() - new Date(lastActiveAt)) / 86400000);
    if (days === 0) return 'Active today';
    if (days === 1) return 'Yesterday';
    if (days < 7)  return `${days} days ago`;
    if (days < 30) return `${Math.floor(days/7)} week${Math.floor(days/7)>1?'s':''} ago`;
    return `${Math.floor(days/30)} month${Math.floor(days/30)>1?'s':''} ago`;
  }

  function render(data) {
    const lecturers = data.lecturers || [];
    const totalAtt  = lecturers.reduce((s, l) => s + l.attendanceSessions, 0);
    const totalMeet = lecturers.reduce((s, l) => s + l.meetingSessions, 0);
    const inactive  = lecturers.filter(l => !l.lastActiveAt || (Date.now() - new Date(l.lastActiveAt)) > 30*86400000).length;

    const deptOptions = viewAs === 'admin'
      ? `<select id="la-dept-filter" onchange="window._laSetDept(this.value)" style="padding:7px 10px;border:1.5px solid var(--border);border-radius:8px;font-size:13px;background:var(--card);color:var(--text-primary)"><option value="">All Departments</option></select>`
      : '';

    content.innerHTML = `
      <div class="page-header" style="display:flex;justify-content:space-between;align-items:flex-start;flex-wrap:wrap;gap:10px;">
        <div><h2>Lecturer Activity</h2><p>${lecturers.length} lecturer${lecturers.length!==1?'s':''} · ${fromDate} → ${toDate}</p></div>
        <button class="btn btn-secondary btn-sm" onclick="window._laExportCSV()" style="white-space:nowrap">⬇ Export CSV</button>
      </div>

      <!-- Stats bar -->
      <div style="display:flex;gap:12px;flex-wrap:wrap;margin-bottom:20px;">
        <div style="flex:1;min-width:120px;background:var(--card);border:1px solid var(--border);border-radius:10px;padding:14px 18px;">
          <div style="font-size:11px;color:var(--text-muted);font-weight:600;text-transform:uppercase;letter-spacing:.5px;margin-bottom:4px">Total Sessions</div>
          <div style="font-size:26px;font-weight:800;color:var(--primary)">${totalAtt + totalMeet}</div>
        </div>
        <div style="flex:1;min-width:120px;background:var(--card);border:1px solid var(--border);border-radius:10px;padding:14px 18px;">
          <div style="font-size:11px;color:var(--text-muted);font-weight:600;text-transform:uppercase;letter-spacing:.5px;margin-bottom:4px">Attendance</div>
          <div style="font-size:26px;font-weight:800;color:#3b82f6">${totalAtt}</div>
        </div>
        <div style="flex:1;min-width:120px;background:var(--card);border:1px solid var(--border);border-radius:10px;padding:14px 18px;">
          <div style="font-size:11px;color:var(--text-muted);font-weight:600;text-transform:uppercase;letter-spacing:.5px;margin-bottom:4px">Meetings</div>
          <div style="font-size:26px;font-weight:800;color:#8b5cf6">${totalMeet}</div>
        </div>
        <div style="flex:1;min-width:120px;background:var(--card);border:1px solid var(--border);border-radius:10px;padding:14px 18px;">
          <div style="font-size:11px;color:var(--text-muted);font-weight:600;text-transform:uppercase;letter-spacing:.5px;margin-bottom:4px">Inactive (30d)</div>
          <div style="font-size:26px;font-weight:800;color:#ef4444">${inactive}</div>
        </div>
      </div>

      <!-- Filters -->
      <div style="display:flex;gap:10px;flex-wrap:wrap;align-items:center;margin-bottom:20px;">
        <div style="display:flex;align-items:center;gap:6px;font-size:13px;">
          <label style="color:var(--text-muted);font-weight:600;white-space:nowrap">From</label>
          <input type="date" id="la-from" value="${fromDate}" onchange="window._laSetFrom(this.value)" style="padding:6px 10px;border:1.5px solid var(--border);border-radius:8px;font-size:13px;background:var(--card);color:var(--text-primary)">
        </div>
        <div style="display:flex;align-items:center;gap:6px;font-size:13px;">
          <label style="color:var(--text-muted);font-weight:600;white-space:nowrap">To</label>
          <input type="date" id="la-to" value="${toDate}" onchange="window._laSetTo(this.value)" style="padding:6px 10px;border:1.5px solid var(--border);border-radius:8px;font-size:13px;background:var(--card);color:var(--text-primary)">
        </div>
        ${deptOptions}
        <select id="la-sort" onchange="window._laSort(this.value)" style="padding:7px 10px;border:1.5px solid var(--border);border-radius:8px;font-size:13px;background:var(--card);color:var(--text-primary)">
          <option value="most">Most Sessions</option>
          <option value="least">Least Sessions</option>
          <option value="recent">Recently Active</option>
          <option value="name">Name A–Z</option>
        </select>
      </div>

      <!-- Cards -->
      <div id="la-cards" style="display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:14px;">
        ${lecturers.length === 0 ? '<div class="empty-state"><p>No lecturers found for this period.</p></div>' :
          lecturers.map(l => {
            const initial = (l.name||'?')[0].toUpperCase();
            const courseChips = (l.courses||[]).slice(0,3).map(c =>
              `<span style="font-size:10px;padding:2px 7px;border-radius:20px;background:rgba(59,130,246,.12);color:#60a5fa;border:1px solid rgba(59,130,246,.25);font-weight:600;white-space:nowrap">${esc(c.code||c.title)}${c.group?' · Grp '+esc(c.group):''}</span>`
            ).join('');
            const moreCourses = l.courses.length > 3 ? `<span style="font-size:10px;color:var(--text-muted)">+${l.courses.length-3} more</span>` : '';
            const isInactive = !l.lastActiveAt || (Date.now() - new Date(l.lastActiveAt)) > 30*86400000;
            return `<div class="card" onclick="window._laOpenDetail('${l._id}','${esc(l.name)}','${fromDate}','${toDate}')" style="cursor:pointer;padding:16px;transition:border-color .15s,transform .15s;position:relative;" onmouseenter="this.style.borderColor='var(--primary)';this.style.transform='translateY(-1px)'" onmouseleave="this.style.borderColor='';this.style.transform=''">
              ${isInactive ? `<span style="position:absolute;top:12px;right:12px;font-size:10px;font-weight:700;padding:2px 8px;border-radius:20px;background:#fef2f2;color:#ef4444;border:1px solid #fecaca">Inactive</span>` : ''}
              <div style="display:flex;align-items:center;gap:10px;margin-bottom:10px">
                <div style="width:40px;height:40px;border-radius:50%;background:linear-gradient(135deg,#3b82f6,#8b5cf6);color:#fff;display:flex;align-items:center;justify-content:center;font-weight:800;font-size:16px;flex-shrink:0">${initial}</div>
                <div style="min-width:0">
                  <div style="font-weight:700;font-size:13px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${esc(l.name)}</div>
                  <div style="font-size:11px;color:var(--text-muted);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${esc(l.email||'')}</div>
                </div>
              </div>
              ${viewAs==='admin' && l.department ? `<div style="margin-bottom:8px"><span style="font-size:10px;padding:2px 8px;border-radius:20px;background:rgba(139,92,246,.12);color:#a78bfa;border:1px solid rgba(139,92,246,.25);font-weight:600">${esc(l.department)}</span></div>` : ''}
              <div style="display:flex;gap:8px;margin-bottom:10px">
                <div style="flex:1;background:rgba(59,130,246,.08);border-radius:8px;padding:8px 10px;text-align:center">
                  <div style="font-size:20px;font-weight:800;color:#3b82f6">${l.attendanceSessions}</div>
                  <div style="font-size:10px;color:var(--text-muted);font-weight:600">Attendance</div>
                </div>
                <div style="flex:1;background:rgba(139,92,246,.08);border-radius:8px;padding:8px 10px;text-align:center">
                  <div style="font-size:20px;font-weight:800;color:#8b5cf6">${l.meetingSessions}</div>
                  <div style="font-size:10px;color:var(--text-muted);font-weight:600">Meetings</div>
                </div>
              </div>
              ${l.courses.length ? `<div style="display:flex;gap:4px;flex-wrap:wrap;margin-bottom:8px">${courseChips}${moreCourses}</div>` : ''}
              <div style="font-size:11px;color:var(--text-muted);display:flex;align-items:center">${activityDot(l.lastActiveAt)}${lastActiveLabel(l.lastActiveAt)}</div>
            </div>`;
          }).join('')}
      </div>
    `;

    // Populate dept filter options for admin
    if (viewAs === 'admin') {
      const depts = [...new Set(lecturers.map(l => l.department).filter(Boolean))].sort();
      const sel = document.getElementById('la-dept-filter');
      if (sel) depts.forEach(d => { const o = document.createElement('option'); o.value = d; o.textContent = d; if (d === deptFilter) o.selected = true; sel.appendChild(o); });
    }

    // Wire up sort
    window._laAllLecturers = lecturers;
    window._laSort = function(val) {
      const cards = document.getElementById('la-cards');
      if (!cards) return;
      const sorted = [...window._laAllLecturers].sort((a,b) => {
        if (val === 'most')   return (b.attendanceSessions+b.meetingSessions)-(a.attendanceSessions+a.meetingSessions);
        if (val === 'least')  return (a.attendanceSessions+a.meetingSessions)-(b.attendanceSessions+b.meetingSessions);
        if (val === 'recent') return (b.lastActiveAt||0) > (a.lastActiveAt||0) ? 1 : -1;
        return a.name.localeCompare(b.name);
      });
      // Re-render just the cards
      window._laAllLecturers = sorted;
      const tmp = data; tmp.lecturers = sorted;
      // Simple re-render of cards grid only
      cards.innerHTML = sorted.length === 0 ? '<div class="empty-state"><p>No lecturers found.</p></div>' :
        sorted.map(l => {
          const initial = (l.name||'?')[0].toUpperCase();
          const courseChips = (l.courses||[]).slice(0,3).map(c =>
            `<span style="font-size:10px;padding:2px 7px;border-radius:20px;background:rgba(59,130,246,.12);color:#60a5fa;border:1px solid rgba(59,130,246,.25);font-weight:600;white-space:nowrap">${esc(c.code||c.title)}${c.group?' · Grp '+esc(c.group):''}</span>`
          ).join('');
          const moreCourses = l.courses.length > 3 ? `<span style="font-size:10px;color:var(--text-muted)">+${l.courses.length-3} more</span>` : '';
          const isInactive = !l.lastActiveAt || (Date.now() - new Date(l.lastActiveAt)) > 30*86400000;
          return `<div class="card" onclick="window._laOpenDetail('${l._id}','${esc(l.name)}','${fromDate}','${toDate}')" style="cursor:pointer;padding:16px;transition:border-color .15s,transform .15s;position:relative;" onmouseenter="this.style.borderColor='var(--primary)';this.style.transform='translateY(-1px)'" onmouseleave="this.style.borderColor='';this.style.transform=''">
            ${isInactive ? `<span style="position:absolute;top:12px;right:12px;font-size:10px;font-weight:700;padding:2px 8px;border-radius:20px;background:#fef2f2;color:#ef4444;border:1px solid #fecaca">Inactive</span>` : ''}
            <div style="display:flex;align-items:center;gap:10px;margin-bottom:10px">
              <div style="width:40px;height:40px;border-radius:50%;background:linear-gradient(135deg,#3b82f6,#8b5cf6);color:#fff;display:flex;align-items:center;justify-content:center;font-weight:800;font-size:16px;flex-shrink:0">${initial}</div>
              <div style="min-width:0">
                <div style="font-weight:700;font-size:13px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${esc(l.name)}</div>
                <div style="font-size:11px;color:var(--text-muted);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${esc(l.email||'')}</div>
              </div>
            </div>
            ${viewAs==='admin' && l.department ? `<div style="margin-bottom:8px"><span style="font-size:10px;padding:2px 8px;border-radius:20px;background:rgba(139,92,246,.12);color:#a78bfa;border:1px solid rgba(139,92,246,.25);font-weight:600">${esc(l.department)}</span></div>` : ''}
            <div style="display:flex;gap:8px;margin-bottom:10px">
              <div style="flex:1;background:rgba(59,130,246,.08);border-radius:8px;padding:8px 10px;text-align:center">
                <div style="font-size:20px;font-weight:800;color:#3b82f6">${l.attendanceSessions}</div>
                <div style="font-size:10px;color:var(--text-muted);font-weight:600">Attendance</div>
              </div>
              <div style="flex:1;background:rgba(139,92,246,.08);border-radius:8px;padding:8px 10px;text-align:center">
                <div style="font-size:20px;font-weight:800;color:#8b5cf6">${l.meetingSessions}</div>
                <div style="font-size:10px;color:var(--text-muted);font-weight:600">Meetings</div>
              </div>
            </div>
            ${l.courses.length ? `<div style="display:flex;gap:4px;flex-wrap:wrap;margin-bottom:8px">${courseChips}${moreCourses}</div>` : ''}
            <div style="font-size:11px;color:var(--text-muted);display:flex;align-items:center">${activityDot(l.lastActiveAt)}${lastActiveLabel(l.lastActiveAt)}</div>
          </div>`;
        }).join('');
    };
  }

  // Wire up date/dept filter controls
  window._laSetFrom = function(v) { fromDate = v; load(); };
  window._laSetTo   = function(v) { toDate = v; load(); };
  window._laSetDept = function(v) { deptFilter = v; load(); };

  // CSV export
  window._laExportCSV = function() {
    const rows = [['Name','Email','Department','Attendance Sessions','Meetings','Last Active']];
    (window._laAllLecturers || []).forEach(l => {
      rows.push([l.name, l.email||'', l.department||'', l.attendanceSessions, l.meetingSessions, l.lastActiveAt ? new Date(l.lastActiveAt).toLocaleDateString() : 'Never']);
    });
    const csv = rows.map(r => r.map(v => `"${String(v).replace(/"/g,'""')}"`).join(',')).join('\n');
    const a = document.createElement('a');
    a.href = URL.createObjectURL(new Blob([csv], {type:'text/csv'}));
    a.download = `lecturer-activity-${fromDate}-${toDate}.csv`;
    a.click();
  };

  // Drill-down panel
  window._laOpenDetail = async function(lecturerId, lecturerName, from, to) {
    // Remove existing panel
    const old = document.getElementById('la-detail-panel');
    if (old) old.remove();

    // Create slide-in panel
    const panel = document.createElement('div');
    panel.id = 'la-detail-panel';
    panel.style.cssText = 'position:fixed;top:0;right:0;width:min(520px,100vw);height:100vh;background:var(--card);border-left:1px solid var(--border);z-index:9000;display:flex;flex-direction:column;box-shadow:-8px 0 32px rgba(0,0,0,.25);transform:translateX(100%);transition:transform .25s cubic-bezier(.22,1,.36,1)';
    panel.innerHTML = `
      <div style="display:flex;align-items:center;justify-content:space-between;padding:18px 20px;border-bottom:1px solid var(--border);flex-shrink:0">
        <div>
          <div style="font-weight:800;font-size:16px">${esc(lecturerName)}</div>
          <div style="font-size:12px;color:var(--text-muted)">${from} → ${to}</div>
        </div>
        <button onclick="document.getElementById('la-detail-panel').remove();document.getElementById('la-backdrop').remove()" style="width:32px;height:32px;border-radius:8px;border:1px solid var(--border);background:transparent;cursor:pointer;color:var(--text-primary);font-size:18px;display:flex;align-items:center;justify-content:center">✕</button>
      </div>
      <!-- Tabs -->
      <div style="display:flex;border-bottom:1px solid var(--border);flex-shrink:0">
        <button id="la-tab-att" onclick="window._laShowTab('att')" style="flex:1;padding:12px;font-size:13px;font-weight:700;border:none;cursor:pointer;border-bottom:2px solid var(--primary);background:transparent;color:var(--primary)">📋 Attendance</button>
        <button id="la-tab-meet" onclick="window._laShowTab('meet')" style="flex:1;padding:12px;font-size:13px;font-weight:600;border:none;cursor:pointer;border-bottom:2px solid transparent;background:transparent;color:var(--text-muted)">🎥 Meetings</button>
      </div>
      <div id="la-detail-body" style="flex:1;overflow-y:auto;padding:16px">
        <div class="loading">Loading…</div>
      </div>`;
    document.body.appendChild(panel);
    requestAnimationFrame(() => { panel.style.transform = 'translateX(0)'; });

    // Backdrop
    const bd = document.createElement('div');
    bd.id = 'la-backdrop';
    bd.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.4);z-index:8999';
    bd.onclick = () => { panel.remove(); bd.remove(); };
    document.body.appendChild(bd);

    // Load detail
    try {
      const data = await api(`/api/hod/lecturer-activity/${lecturerId}?from=${from}&to=${to}`);
      window._laDetailData = data;
      window._laShowTab('att');
    } catch(e) {
      document.getElementById('la-detail-body').innerHTML = `<p style="color:#ef4444">${e.message||'Failed to load'}</p>`;
    }
  };

  window._laShowTab = function(tab) {
    const data = window._laDetailData;
    if (!data) return;
    const body = document.getElementById('la-detail-body');
    const tabAtt  = document.getElementById('la-tab-att');
    const tabMeet = document.getElementById('la-tab-meet');
    if (!body) return;

    if (tab === 'att') {
      if (tabAtt)  { tabAtt.style.borderBottomColor='var(--primary)'; tabAtt.style.color='var(--primary)'; tabAtt.style.fontWeight='700'; }
      if (tabMeet) { tabMeet.style.borderBottomColor='transparent'; tabMeet.style.color='var(--text-muted)'; tabMeet.style.fontWeight='600'; }
      const sessions = data.attendanceSessions || [];
      body.innerHTML = sessions.length === 0
        ? '<div style="text-align:center;padding:40px;color:var(--text-muted)">No attendance sessions in this period.</div>'
        : `<div style="font-size:12px;color:var(--text-muted);margin-bottom:12px;font-weight:600">${sessions.length} session${sessions.length!==1?'s':''}</div>`
          + sessions.map(s => {
            const course = s.course ? `${esc(s.course.code||'')} ${esc(s.course.title||'')}` : esc(s.title||'Session');
            const grp    = s.targetGroup ? ` · Grp ${esc(s.targetGroup)}` : '';
            const date   = s.startedAt || s.createdAt;
            const mins   = s.durationSeconds ? Math.round(s.durationSeconds/60)+'min' : '—';
            const ended  = ['stopped','ended','locked'].includes(s.status);
            return `<div style="padding:12px;border:1px solid var(--border);border-radius:10px;margin-bottom:8px">
              <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:8px">
                <div>
                  <div style="font-weight:700;font-size:13px">${course}${grp}</div>
                  <div style="font-size:11px;color:var(--text-muted);margin-top:2px">${date ? new Date(date).toLocaleString() : '—'} · ${mins}</div>
                </div>
                <div style="text-align:right;flex-shrink:0">
                  <div style="font-size:18px;font-weight:800;color:#3b82f6">${s.totalMarked||0}</div>
                  <div style="font-size:10px;color:var(--text-muted)">marked</div>
                </div>
              </div>
              <div style="margin-top:6px">
                <span style="font-size:10px;padding:2px 7px;border-radius:20px;font-weight:600;${ended?'background:#f0fdf4;color:#166534;border:1px solid #bbf7d0':'background:#eff6ff;color:#1d4ed8;border:1px solid #bfdbfe'}">${s.status||'—'}</span>
              </div>
            </div>`;
          }).join('');
    } else {
      if (tabMeet) { tabMeet.style.borderBottomColor='var(--primary)'; tabMeet.style.color='var(--primary)'; tabMeet.style.fontWeight='700'; }
      if (tabAtt)  { tabAtt.style.borderBottomColor='transparent'; tabAtt.style.color='var(--text-muted)'; tabAtt.style.fontWeight='600'; }
      const meetings = data.meetings || [];
      body.innerHTML = meetings.length === 0
        ? '<div style="text-align:center;padding:40px;color:var(--text-muted)">No meetings in this period.</div>'
        : `<div style="font-size:12px;color:var(--text-muted);margin-bottom:12px;font-weight:600">${meetings.length} meeting${meetings.length!==1?'s':''}</div>`
          + meetings.map(m => {
            const title  = m.title || (m.linkedCourseId ? `${m.linkedCourseId.code||''} ${m.linkedCourseId.title||''}`.trim() : 'Meeting');
            const date   = m.actualStart || m.scheduledStart || m.createdAt;
            const typeLabel = (m.type||'meeting').replace(/_/g,' ').replace(/\b\w/g,c=>c.toUpperCase());
            const ended  = m.status === 'ended';
            const dur    = m.actualStart && m.actualEnd
              ? Math.round((new Date(m.actualEnd)-new Date(m.actualStart))/60000)+'min' : '—';
            return `<div style="padding:12px;border:1px solid var(--border);border-radius:10px;margin-bottom:8px">
              <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:8px">
                <div>
                  <div style="font-weight:700;font-size:13px">${esc(title)}</div>
                  <div style="font-size:11px;color:var(--text-muted);margin-top:2px">${date ? new Date(date).toLocaleString() : '—'} · ${dur}</div>
                </div>
                <span style="font-size:10px;padding:2px 7px;border-radius:20px;font-weight:600;white-space:nowrap;${ended?'background:#f0fdf4;color:#166534;border:1px solid #bbf7d0':'background:#eff6ff;color:#1d4ed8;border:1px solid #bfdbfe'}">${m.status||'—'}</span>
              </div>
              <div style="margin-top:6px">
                <span style="font-size:10px;padding:2px 7px;border-radius:20px;background:rgba(139,92,246,.1);color:#8b5cf6;border:1px solid rgba(139,92,246,.25);font-weight:600">${esc(typeLabel)}</span>
              </div>
            </div>`;
          }).join('');
    }
  };

  await load();
}

async function renderHodLecturers() {
  const content = document.getElementById('main-content');
  content.innerHTML = '<div class="loading">Loading lecturers…</div>';
  let lecturers = [], courses = [], _isOff = false;
  if (!isOnline()) {
    const _c = offlineRead('hod_lecturers');
    if (_c) { lecturers = _c.lecturers || []; courses = _c.courses || []; _isOff = true; }
    else { content.innerHTML = `<div style="text-align:center;padding:60px 20px"><div style="font-size:48px;margin-bottom:12px">📡</div><div style="font-size:18px;font-weight:700">You're Offline</div><p style="color:var(--text-muted);margin-top:8px">Connect once while online to cache this page.</p></div>`; return; }
  } else {
    try {
      const dept = currentUser.department ? '&department=' + encodeURIComponent(currentUser.department) : '';
      const [lecturerData, courseData] = await Promise.all([
        api('/api/users?role=lecturer&limit=200' + dept),
        api('/api/courses?limit=500'),
      ]);
      lecturers = lecturerData.users || [];
      courses   = courseData.courses || courseData || [];
      offlineCache('hod_lecturers', { lecturers, courses });
    } catch(e) {
      const _c = offlineRead('hod_lecturers');
      if (_c) { lecturers = _c.lecturers || []; courses = _c.courses || []; _isOff = true; }
      else { content.innerHTML = `<div class="card"><p style="color:#ef4444;">${e.message}</p></div>`; return; }
    }
  }
  {

    // Build map: lecturerId → [course titles]
    const coursesByLecturer = {};
    for (const c of courses) {
      const lid = c.lecturerId?._id || c.lecturerId;
      if (!lid) continue;
      const key = lid.toString();
      if (!coursesByLecturer[key]) coursesByLecturer[key] = [];
      coursesByLecturer[key].push(c.title || c.code || 'Untitled');
    }

    const deptLabel = currentUser.department ? `in ${currentUser.department}` : 'in your institution';
    content.innerHTML = `
      <div class="page-header">
        <div><h2>Lecturers</h2><p>${lecturers.length} lecturer${lecturers.length !== 1 ? 's' : ''} ${deptLabel}</p></div>
        <button class="btn btn-secondary btn-sm" onclick="hodExportCSV('lecturers')">Export CSV</button>
      </div>
      <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:12px;">
        ${lecturers.length === 0 ? '<div class="empty-state"><p>No lecturers found.</p></div>' :
          lecturers.map(u => {
            const lecCourses = coursesByLecturer[u._id] || [];
            const courseChips = lecCourses.slice(0, 3).map(t =>
              `<span style="font-size:10px;padding:2px 7px;border-radius:20px;background:#f0fdf4;color:#166534;border:1px solid #bbf7d0;font-weight:600;white-space:nowrap;">${esc(t)}</span>`
            ).join('');
            const moreTag = lecCourses.length > 3
              ? `<span style="font-size:10px;color:var(--text-muted)">+${lecCourses.length - 3} more</span>`
              : '';
            return `
            <div class="card" style="display:flex;align-items:flex-start;gap:12px;padding:14px 16px;">
              <div style="width:38px;height:38px;border-radius:50%;background:#ecfeff;color:#0891b2;display:flex;align-items:center;justify-content:center;font-weight:700;font-size:15px;flex-shrink:0;margin-top:2px;">
                ${(u.name||'?')[0].toUpperCase()}
              </div>
              <div style="min-width:0;flex:1;">
                <div style="font-weight:700;font-size:13px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${esc(u.name)}</div>
                <div style="font-size:11px;color:var(--text-muted);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${esc(u.email)}</div>
                <div style="display:flex;gap:6px;align-items:center;margin-top:4px;flex-wrap:wrap;">
                  <span class="tag ${u.isApproved ? 'tag-green' : 'tag-amber'}">${u.isApproved ? 'Active' : 'Pending'}</span>
                  ${u.department ? `<span style="font-size:10px;padding:2px 6px;border-radius:20px;background:#ecfeff;color:#0891b2;font-weight:600;">${esc(u.department)}</span>` : ''}
                </div>
                ${lecCourses.length ? `<div style="display:flex;gap:4px;flex-wrap:wrap;margin-top:6px;">${courseChips}${moreTag}</div>` : '<div style="font-size:11px;color:var(--text-muted);margin-top:5px;">No courses assigned</div>'}
              </div>
            </div>`;
          }).join('')}
      </div>`;
  }
}

let _hodCachedStudents = null;

async function renderHodStudents() {
  const content = document.getElementById('main-content');
  content.innerHTML = '<div class="loading">Loading students…</div>';
  if (!isOnline()) {
    const _c = offlineRead('hod_students');
    if (_c) { _hodCachedStudents = _c; _renderHodLevelCards(content, _c); return; }
    content.innerHTML = `<div style="text-align:center;padding:60px 20px"><div style="font-size:48px;margin-bottom:12px">📡</div><div style="font-size:18px;font-weight:700">You're Offline</div><p style="color:var(--text-muted);margin-top:8px">Connect once while online to cache this page.</p></div>`; return;
  }
  try {
    const dept = currentUser.department ? '&department=' + encodeURIComponent(currentUser.department) : '';
    const data = await api('/api/users?role=student&limit=500' + dept);
    _hodCachedStudents = data.users || [];
    offlineCache('hod_students', _hodCachedStudents);
    _renderHodLevelCards(content, _hodCachedStudents);
  } catch(e) {
    const _c = offlineRead('hod_students');
    if (_c) { _hodCachedStudents = _c; _renderHodLevelCards(content, _c); return; }
    content.innerHTML = `<div class="card"><p style="color:#ef4444;">${e.message}</p></div>`;
  }
}

function _renderHodLevelCards(content, allStudents) {
  const levelMap = {};
  allStudents.forEach(u => {
    const lv = u.studentLevel ? String(u.studentLevel) : 'Unassigned';
    if (!levelMap[lv]) levelMap[lv] = [];
    levelMap[lv].push(u);
  });
  const levels = Object.keys(levelMap).sort((a, b) => {
    if (a === 'Unassigned') return 1;
    if (b === 'Unassigned') return -1;
    return Number(a) - Number(b);
  });

  const cards = levels.map(lv => {
    const studs = levelMap[lv];
    const active = studs.filter(u => u.isApproved).length;
    const accent = _deptColor('Level ' + lv);
    const lvEnc = encodeURIComponent(lv);
    return `
      <div onclick="_renderHodLevelStudents(decodeURIComponent('${lvEnc}'), _hodCachedStudents)"
           style="background:#fff;border:1.5px solid #e8eaed;border-radius:16px;padding:0;cursor:pointer;overflow:hidden;box-shadow:0 1px 4px rgba(0,0,0,.06);transition:box-shadow .18s;position:relative"
           onmouseover="this.style.boxShadow='0 6px 24px rgba(0,0,0,.11)'" onmouseout="this.style.boxShadow='0 1px 4px rgba(0,0,0,.06)'">
        <div style="height:5px;background:${accent};border-radius:16px 16px 0 0"></div>
        <div style="padding:20px 22px 18px">
          <div style="display:flex;align-items:center;gap:12px;margin-bottom:14px">
            <div style="width:42px;height:42px;border-radius:12px;background:${accent}1a;display:flex;align-items:center;justify-content:center;flex-shrink:0">
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="${accent}" stroke-width="2"><path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/></svg>
            </div>
            <div>
              <div style="font-size:16px;font-weight:800;color:#0f172a">Level ${lv === 'Unassigned' ? '<span style="color:#94a3b8">Unassigned</span>' : lv}</div>
              <div style="font-size:12px;color:#64748b;margin-top:1px">${studs.length} student${studs.length !== 1 ? 's' : ''}</div>
            </div>
          </div>
          <div style="display:flex;gap:10px;flex-wrap:wrap">
            <span style="font-size:11px;font-weight:600;background:${accent}15;color:${accent};padding:3px 10px;border-radius:20px">${active} Active</span>
            ${studs.length - active > 0 ? `<span style="font-size:11px;font-weight:600;background:#fef3c715;color:#b45309;padding:3px 10px;border-radius:20px">${studs.length - active} Pending</span>` : ''}
          </div>
        </div>
      </div>`;
  }).join('');

  content.innerHTML = `
    <div class="page-header" style="margin-bottom:24px">
      <div>
        <h2 style="font-size:22px;font-weight:800;letter-spacing:-.5px;color:#0f172a;margin-bottom:2px">Students</h2>
        <p style="color:#64748b;font-size:13px">${allStudents.length} student${allStudents.length !== 1 ? 's' : ''} enrolled${currentUser.department ? ' · ' + esc(currentUser.department) : ''}</p>
      </div>
      <button class="btn btn-secondary btn-sm" onclick="hodExportCSV('students')">Export CSV</button>
    </div>
    ${levels.length === 0
      ? `<div style="background:#fff;border:1px solid #e8eaed;border-radius:16px;padding:60px 20px;text-align:center"><p style="color:#64748b">No students found.</p></div>`
      : `<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(230px,1fr));gap:16px">${cards}</div>`}`;
}

function _renderHodLevelStudents(level, allStudents) {
  const content = document.getElementById('main-content');
  const studs = allStudents.filter(u => {
    const lv = u.studentLevel ? String(u.studentLevel) : 'Unassigned';
    return lv === level;
  });
  const accent = _deptColor('Level ' + level);

  content.innerHTML = `
    <div class="page-header" style="margin-bottom:20px">
      <div style="display:flex;align-items:center;gap:10px">
        <button onclick="_renderHodLevelCards(document.getElementById('main-content'),_hodCachedStudents)"
                style="background:none;border:none;cursor:pointer;padding:6px 8px;border-radius:8px;color:#64748b;font-size:13px;display:flex;align-items:center;gap:5px;transition:background .15s"
                onmouseover="this.style.background='#f1f5f9'" onmouseout="this.style.background='none'">
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><polyline points="15 18 9 12 15 6"/></svg>
          All Levels
        </button>
        <span style="color:#cbd5e1">›</span>
        <span style="font-size:14px;font-weight:700;color:#0f172a">Level ${esc(level)}</span>
      </div>
      <div style="display:flex;gap:8px;align-items:center">
        <button class="btn btn-secondary btn-sm" onclick="hodExportCSV('students')">Export CSV</button>
        <input id="hod-stu-search" placeholder="Search students…" oninput="hodFilterStudents()"
               style="padding:8px 12px;border:1.5px solid var(--border);border-radius:8px;font-size:13px;font-family:inherit;outline:none;min-width:200px;">
      </div>
    </div>
    <div id="hod-stu-list" style="overflow-x:auto;">
      <table style="width:100%;border-collapse:collapse;font-size:13px;background:#fff;border:1px solid #e8eaed;border-radius:14px;overflow:hidden;box-shadow:0 1px 4px rgba(0,0,0,.05)">
        <thead>
          <tr style="border-bottom:2px solid var(--border);background:#f8fafc">
            <th style="text-align:left;padding:12px 14px;font-weight:700;color:var(--text-muted);font-size:11px;text-transform:uppercase;letter-spacing:.5px">Name</th>
            <th style="text-align:left;padding:12px 14px;font-weight:700;color:var(--text-muted);font-size:11px;text-transform:uppercase;letter-spacing:.5px">Index No.</th>
            <th style="text-align:left;padding:12px 14px;font-weight:700;color:var(--text-muted);font-size:11px;text-transform:uppercase;letter-spacing:.5px">Programme</th>
            <th style="text-align:left;padding:12px 14px;font-weight:700;color:var(--text-muted);font-size:11px;text-transform:uppercase;letter-spacing:.5px">Group</th>
            <th style="text-align:left;padding:12px 14px;font-weight:700;color:var(--text-muted);font-size:11px;text-transform:uppercase;letter-spacing:.5px">Session</th>
            <th style="text-align:left;padding:12px 14px;font-weight:700;color:var(--text-muted);font-size:11px;text-transform:uppercase;letter-spacing:.5px">Status</th>
            <th style="text-align:left;padding:12px 14px;font-weight:700;color:var(--text-muted);font-size:11px;text-transform:uppercase;letter-spacing:.5px"></th>
          </tr>
        </thead>
        <tbody id="hod-stu-tbody">
          ${studs.length === 0 ? `<tr><td colspan="7" style="padding:32px;text-align:center;color:var(--text-muted)">No students in Level ${esc(level)}.</td></tr>` :
            studs.map(u => `
              <tr class="hod-stu-row" data-name="${esc((u.name||'').toLowerCase())}" data-index="${esc((u.IndexNumber||u.indexNumber||'').toLowerCase())}" style="border-bottom:1px solid var(--border);">
                <td style="padding:11px 14px;font-weight:600">${esc(u.name)}</td>
                <td style="padding:11px 14px;color:var(--text-muted);font-family:monospace">${u.IndexNumber || u.indexNumber || '—'}</td>
                <td style="padding:11px 14px">${u.programme ? `<span style="background:#ede9fe;color:#7c3aed;padding:2px 9px;border-radius:20px;font-size:11px;font-weight:700">${esc(u.programme)}</span>` : '—'}</td>
                <td style="padding:11px 14px">${u.studentGroup ? `<span style="background:#ecfdf5;color:#059669;padding:2px 9px;border-radius:20px;font-size:11px;font-weight:700">Grp ${esc(u.studentGroup)}</span>` : '—'}</td>
                <td style="padding:11px 14px">
                  ${u.sessionType ? `<span style="background:#fff7ed;color:#c2410c;padding:2px 9px;border-radius:20px;font-size:11px;font-weight:600">${esc(u.sessionType)}</span>` : '—'}
                  ${u.semester ? `<span style="font-size:11px;color:var(--text-muted);margin-left:4px">Sem ${esc(u.semester)}</span>` : ''}
                  ${u.academicYear ? `<span style="font-size:10px;color:var(--text-muted);margin-left:4px">${esc(u.academicYear)}</span>` : ''}
                </td>
                <td style="padding:11px 14px">
                  <span class="tag ${u.isApproved ? 'tag-green' : 'tag-amber'}">${u.isApproved ? 'Active' : 'Pending'}</span>
                  ${u.isClassRep ? '<span class="tag" style="background:#7c3aed;color:#fff;margin-left:4px">Rep</span>' : ''}
                </td>
                <td style="padding:11px 14px;display:flex;gap:6px;flex-wrap:wrap">
                  <button class="btn btn-xs btn-secondary" onclick="hodViewStudentAttendance('${u._id}','${(u.name||'').replace(/'/g,"\\'")}')">Attendance</button>
                  ${u.isClassRep
                    ? `<button class="btn btn-xs" style="background:#fee2e2;color:#b91c1c;border:1px solid #fca5a5;" onclick="hodToggleClassRep('${u._id}','${esc(u.name).replace(/'/g,"\\'")}',false)">Remove Rep</button>`
                    : `<button class="btn btn-xs" style="background:#faf5ff;color:#7c3aed;border:1px solid #d8b4fe;" onclick="hodToggleClassRep('${u._id}','${esc(u.name).replace(/'/g,"\\'")}',true)">Make Rep</button>`}
                </td>
              </tr>`).join('')}
        </tbody>
      </table>
    </div>`;
}

function hodFilterStudents() {
  const q = (document.getElementById('hod-stu-search')?.value || '').toLowerCase();
  document.querySelectorAll('.hod-stu-row').forEach(row => {
    const match = row.dataset.name.includes(q) || row.dataset.index.includes(q);
    row.style.display = match ? '' : 'none';
  });
}

async function hodToggleClassRep(studentId, name, assign) {
  const action = assign ? `Make ${name} a class representative?` : `Remove ${name} as class representative?`;
  if (!confirm(action)) return;
  try {
    if (assign) {
      await api('/api/class-rep-admin/assign', { method: 'POST', body: JSON.stringify({ studentId }) });
      toastSuccess(`${name} is now a class representative`);
    } else {
      await api(`/api/class-rep-admin/remove/${studentId}`, { method: 'DELETE' });
      toastSuccess(`${name} removed as class representative`);
    }
    renderHodStudents();
  } catch(e) {
    toastError(e.message || 'Failed to update class representative');
  }
}

async function renderHodReports() {
  const content = document.getElementById('main-content');
  content.innerHTML = '<div class="loading">Loading reports…</div>';
  try {
    const hodDept = currentUser.department ? '&department=' + encodeURIComponent(currentUser.department) : '';
    const [sessData, userStats] = await Promise.all([
      api('/api/attendance-sessions?limit=200' + hodDept),
      api('/api/users/stats' + (currentUser.department ? '?department=' + encodeURIComponent(currentUser.department) : ''))
    ]);
    const sessions  = sessData.sessions || [];
    const stats     = userStats || {};
    const ended     = sessions.filter(s => !['active','live','paused','locked'].includes(s.status));
    const totalAtt  = ended.reduce((sum, s) => sum + (s.attendanceCount ?? s.records?.length ?? 0), 0);
    const avgAtt    = ended.length ? Math.round(totalAtt / ended.length) : 0;

    // Group sessions by lecturer
    const byLecturer = {};
    sessions.forEach(s => {
      const name = s.createdBy?.name || 'Unknown';
      if (!byLecturer[name]) byLecturer[name] = { sessions: 0, attendance: 0 };
      byLecturer[name].sessions++;
      byLecturer[name].attendance += s.attendanceCount ?? s.records?.length ?? 0;
    });
    const lecRows = Object.entries(byLecturer).sort((a,b) => b[1].sessions - a[1].sessions);

    // Group sessions by course for attendance rate
    const byCourse = {};
    sessions.forEach(s => {
      const name = s.courseName || s.title || 'Unknown Course';
      if (!byCourse[name]) byCourse[name] = { sessions: 0, attendance: 0, enrolled: s.enrolledCount || 0 };
      byCourse[name].sessions++;
      byCourse[name].attendance += s.attendanceCount ?? s.records?.length ?? 0;
      if (s.enrolledCount > byCourse[name].enrolled) byCourse[name].enrolled = s.enrolledCount;
    });
    const courseRows = Object.entries(byCourse).sort((a,b) => b[1].sessions - a[1].sessions);

    content.innerHTML = `
      <div class="page-header"><div><h2>Department Reports</h2><p>Attendance and activity overview</p></div></div>

      <div class="stats-grid" style="margin-bottom:20px;">
        <div class="stat-card"><div class="stat-value" style="color:#0891b2">${sessions.length}</div><div class="stat-label">TOTAL SESSIONS</div></div>
        <div class="stat-card"><div class="stat-value" style="color:#0891b2">${totalAtt}</div><div class="stat-label">TOTAL ATTENDANCE</div></div>
        <div class="stat-card"><div class="stat-value" style="color:#0891b2">${avgAtt}</div><div class="stat-label">AVG ATTENDANCE</div></div>
        <div class="stat-card"><div class="stat-value" style="color:#0891b2">${stats.lecturers || 0}</div><div class="stat-label">LECTURERS</div></div>
      </div>

      <div class="card" style="margin-bottom:16px;">
        <div style="font-size:13px;font-weight:700;margin-bottom:14px;">Attendance Rate by Course</div>
        ${courseRows.length === 0 ? '<p style="color:var(--text-muted);font-size:13px;">No data yet.</p>' : `
        <table style="width:100%;border-collapse:collapse;font-size:13px;">
          <thead>
            <tr style="border-bottom:2px solid var(--border);">
              <th style="text-align:left;padding:8px 12px;font-weight:700;color:var(--text-muted);font-size:11px;text-transform:uppercase;">Course</th>
              <th style="text-align:left;padding:8px 12px;font-weight:700;color:var(--text-muted);font-size:11px;text-transform:uppercase;">Sessions</th>
              <th style="text-align:left;padding:8px 12px;font-weight:700;color:var(--text-muted);font-size:11px;text-transform:uppercase;">Total Attendance</th>
              <th style="text-align:left;padding:8px 12px;font-weight:700;color:var(--text-muted);font-size:11px;text-transform:uppercase;">Avg / Session</th>
              <th style="text-align:left;padding:8px 12px;font-weight:700;color:var(--text-muted);font-size:11px;text-transform:uppercase;">Rate</th>
            </tr>
          </thead>
          <tbody>
            ${courseRows.map(([name, d]) => {
              const avg = d.sessions ? Math.round(d.attendance / d.sessions) : 0;
              const rate = d.enrolled > 0 ? Math.round((avg / d.enrolled) * 100) : null;
              const rateColor = rate === null ? '#9ca3af' : rate >= 75 ? '#16a34a' : rate >= 50 ? '#d97706' : '#dc2626';
              return `<tr style="border-bottom:1px solid var(--border);">
                <td style="padding:9px 12px;font-weight:600;">${name}</td>
                <td style="padding:9px 12px;">${d.sessions}</td>
                <td style="padding:9px 12px;">${d.attendance}</td>
                <td style="padding:9px 12px;">${avg}</td>
                <td style="padding:9px 12px;">
                  ${rate !== null
                    ? `<span style="font-weight:700;color:${rateColor}">${rate}%</span>
                       <div style="height:4px;background:var(--border);border-radius:2px;margin-top:3px;width:80px;">
                         <div style="height:4px;background:${rateColor};border-radius:2px;width:${Math.min(rate,100)}%"></div>
                       </div>`
                    : '<span style="color:var(--text-muted)">—</span>'
                  }
                </td>
              </tr>`;
            }).join('')}
          </tbody>
        </table>`}
      </div>

      <div class="card" style="margin-bottom:16px;">
        <div style="font-size:13px;font-weight:700;margin-bottom:14px;">Attendance by Lecturer</div>
        ${lecRows.length === 0 ? '<p style="color:var(--text-muted);font-size:13px;">No data yet.</p>' : `
        <table style="width:100%;border-collapse:collapse;font-size:13px;">
          <thead>
            <tr style="border-bottom:2px solid var(--border);">
              <th style="text-align:left;padding:8px 12px;font-weight:700;color:var(--text-muted);font-size:11px;text-transform:uppercase;">Lecturer</th>
              <th style="text-align:left;padding:8px 12px;font-weight:700;color:var(--text-muted);font-size:11px;text-transform:uppercase;">Sessions</th>
              <th style="text-align:left;padding:8px 12px;font-weight:700;color:var(--text-muted);font-size:11px;text-transform:uppercase;">Total Attendance</th>
              <th style="text-align:left;padding:8px 12px;font-weight:700;color:var(--text-muted);font-size:11px;text-transform:uppercase;">Avg / Session</th>
            </tr>
          </thead>
          <tbody>
            ${lecRows.map(([name, d]) => `
              <tr style="border-bottom:1px solid var(--border);">
                <td style="padding:9px 12px;font-weight:600;">${name}</td>
                <td style="padding:9px 12px;">${d.sessions}</td>
                <td style="padding:9px 12px;">${d.attendance}</td>
                <td style="padding:9px 12px;color:var(--text-muted);">${d.sessions ? Math.round(d.attendance / d.sessions) : 0}</td>
              </tr>`).join('')}
          </tbody>
        </table>`}
      </div>

      <div class="card">
        <div style="font-size:13px;font-weight:700;margin-bottom:14px;">Attendance Trend (Last 30 Days)</div>
        <canvas id="hod-trend-chart" height="120"></canvas>
      </div>`;

    // Build trend chart — group sessions by date
    const trendMap = {};
    const now = Date.now();
    const days30 = 30 * 24 * 60 * 60 * 1000;
    sessions.filter(s => !['active','live','paused','locked'].includes(s.status) && new Date(s.createdAt) > now - days30).forEach(s => {
      const d = new Date(s.createdAt).toLocaleDateString('en-GB', { day: '2-digit', month: 'short' });
      trendMap[d] = (trendMap[d] || 0) + (s.attendanceCount ?? s.records?.length ?? 0);
    });
    const trendLabels = Object.keys(trendMap).slice(-14);
    const trendData   = trendLabels.map(k => trendMap[k]);

    if (trendLabels.length > 0) {
      const loadChart = async () => {
        if (!window.Chart) {
          await new Promise((res, rej) => {
            const s = document.createElement('script');
            s.src = '/js/vendor/chart.umd.min.js';
            s.onload = res; s.onerror = rej; document.head.appendChild(s);
          });
        }
        const ctx = document.getElementById('hod-trend-chart');
        if (!ctx) return;
        const existingHod = Chart.getChart(ctx);
        if (existingHod) existingHod.destroy();
        new Chart(ctx, {
          type: 'line',
          data: {
            labels: trendLabels,
            datasets: [{
              label: 'Attendance',
              data: trendData,
              borderColor: '#0891b2',
              backgroundColor: 'rgba(8,145,178,0.1)',
              borderWidth: 2,
              fill: true,
              tension: 0.4,
              pointRadius: 4,
              pointBackgroundColor: '#0891b2',
            }]
          },
          options: {
            responsive: true,
            plugins: { legend: { display: false } },
            scales: {
              y: { beginAtZero: true, ticks: { stepSize: 1 } },
              x: { grid: { display: false } }
            }
          }
        });
      };
      setTimeout(loadChart, 50);
    }
  } catch(e) {
    content.innerHTML = `<div class="card"><p style="color:#ef4444;">${e.message}</p></div>`;
  }
}


