let _quizMonitorWs = null;
let _quizMonitorRefreshTimer = null;

async function renderQuizLiveDashboard(quizId, quizTitle) {
  const content = document.getElementById('main-content');
  content.innerHTML = '<div class="loading">Connecting to live monitor…</div>';

  // Cleanup previous ws
  if (_quizMonitorWs) { try { _quizMonitorWs.close(); } catch(_) {} _quizMonitorWs = null; }
  if (_quizMonitorRefreshTimer) { clearInterval(_quizMonitorRefreshTimer); _quizMonitorRefreshTimer = null; }

  const render = async () => {
    try {
      const d = await api(`/api/lecturer/snap-quizzes/${quizId}/live-monitor`);
      _renderQuizMonitorUI(d, quizId, quizTitle);
    } catch (e) {
      content.innerHTML = `<div class="card"><p>Error: ${e.message}</p><button class="btn btn-secondary btn-sm" onclick="renderQuizMonitorPage()">← Back</button></div>`;
    }
  };

  await render();

  // Connect WebSocket for live updates
  try {
    const token = localStorage.getItem('diklyToken') || sessionStorage.getItem('diklyToken') || '';
    const wsUrl = (location.protocol === 'https:' ? 'wss' : 'ws') + '://' + location.host + '/ws/monitor?token=' + encodeURIComponent(token);
    const ws = new WebSocket(wsUrl);
    _quizMonitorWs = ws;
    ws.onopen = () => ws.send(JSON.stringify({ type: 'subscribe', quizId }));
    ws.onmessage = (ev) => {
      try {
        const msg = JSON.parse(ev.data);
        if (msg.type && msg.type.startsWith('quiz:')) {
          _handleQuizMonitorEvent(msg.type.replace('quiz:', ''), msg.payload);
        }
      } catch (_) {}
    };
    ws.onerror = ws.onclose = () => { _quizMonitorWs = null; };
  } catch (_) {}

  // Fallback: refresh stats every 20s in case WS is unavailable
  _quizMonitorRefreshTimer = setInterval(render, 20000);
}

function _handleQuizMonitorEvent(eventType, payload) {
  const feed = document.getElementById('qm-feed');
  if (!feed) return;
  const colors = { violation_logged: '#ef4444', attempt_started: '#22c55e', attempt_submitted: '#3b82f6', attempt_auto_submitted: '#f59e0b', heartbeat_missed: '#f97316', snapshot_analyzed: '#8b5cf6' };
  const icons  = { violation_logged: '⚠️', attempt_started: '▶️', attempt_submitted: '✅', attempt_auto_submitted: '⏰', heartbeat_missed: '💔', snapshot_analyzed: '🤖' };
  const labels = { violation_logged: 'Violation', attempt_started: 'Started', attempt_submitted: 'Submitted', attempt_auto_submitted: 'Auto-submitted', heartbeat_missed: 'Missed heartbeat', snapshot_analyzed: 'AI analysis' };
  const color = colors[eventType] || '#64748b';
  const icon  = icons[eventType]  || '📌';
  const label = labels[eventType] || eventType;

  const item = document.createElement('div');
  item.style.cssText = `display:flex;align-items:flex-start;gap:10px;padding:8px 12px;border-left:3px solid ${color};background:${color}11;border-radius:0 8px 8px 0;margin-bottom:6px`;
  item.innerHTML = `
    <span style="font-size:14px;margin-top:1px">${icon}</span>
    <div style="flex:1;min-width:0">
      <div style="font-size:12px;font-weight:700;color:${color}">${label}</div>
      <div style="font-size:11px;color:var(--text-muted);margin-top:1px">${payload.studentId ? 'Student: ...'+String(payload.studentId).slice(-6) : ''}${payload.violationType ? ' · '+payload.violationType : ''}${payload.causedTermination ? ' · <strong style="color:#ef4444">TERMINATED</strong>' : ''}</div>
    </div>
    <span style="font-size:10px;color:#94a3b8;white-space:nowrap">${new Date().toLocaleTimeString()}</span>`;
  feed.prepend(item);
  while (feed.children.length > 50) feed.removeChild(feed.lastChild);

  // Update student row if present
  if (payload.attemptId) {
    const row = document.getElementById('qm-student-' + payload.attemptId);
    if (row && eventType === 'violation_logged') {
      const vc = row.querySelector('.qm-vcount');
      if (vc) vc.textContent = (parseInt(vc.textContent) || 0) + 1;
    }
    if (row && (eventType === 'attempt_submitted' || eventType === 'attempt_auto_submitted')) {
      row.style.opacity = '0.6';
      const st = row.querySelector('.qm-status');
      if (st) { st.textContent = eventType === 'attempt_auto_submitted' ? 'Auto-submitted' : 'Submitted'; st.style.color = '#22c55e'; }
    }
  }
}

function _renderQuizMonitorUI(d, quizId, quizTitle) {
  const content = document.getElementById('main-content');
  const { quiz, students, recentViolations, summary } = d;
  const secColors = { low: '#22c55e', medium: '#6366f1', high: '#dc2626' };
  const secColor = secColors[quiz.securityLevel] || '#6366f1';
  const fmt = n => n ?? '—';

  const studentRows = students.map(s => {
    const statusColor = s.status === 'active' ? '#22c55e' : s.isTerminated ? '#ef4444' : '#64748b';
    const statusLabel = s.isTerminated ? 'Terminated' : s.status === 'active' ? 'Active' : s.status === 'submitted' ? 'Submitted' : s.status === 'auto_submitted' ? 'Auto-submitted' : s.status;
    const onlineDot = s.online ? '🟢' : s.status === 'active' ? '🔴' : '⚫';
    const minutes = s.timeRemaining != null ? Math.floor(s.timeRemaining / 60) + ':' + String(s.timeRemaining % 60).padStart(2, '0') : '—';
    return `<tr id="qm-student-${s.attemptId}" style="border-bottom:1px solid var(--border)">
      <td style="padding:10px 12px">
        <div style="font-weight:600;font-size:13px">${esc(s.student.name)}</div>
        <div style="font-size:10px;color:var(--text-muted)">${esc(s.student.indexNumber || s.student.email)}</div>
        <div style="font-size:10px;color:#94a3b8">${esc(s.platform)}</div>
      </td>
      <td style="padding:10px 12px">
        ${onlineDot} <span class="qm-status" style="font-size:12px;font-weight:600;color:${statusColor}">${statusLabel}</span>
      </td>
      <td style="padding:10px 12px;text-align:center">
        <span class="qm-vcount" style="font-size:13px;font-weight:700;color:${(s.violationCount||0) > 0 ? '#ef4444' : '#64748b'}">${s.violationCount||0}</span>
      </td>
      <td style="padding:10px 12px;text-align:center;font-size:12px;color:var(--text-muted)">${minutes}</td>
      <td style="padding:10px 12px;text-align:center">
        ${s.percentageScore != null ? `<span style="font-size:12px;font-weight:700">${s.percentageScore}%</span>` : '<span style="color:#94a3b8;font-size:11px">—</span>'}
      </td>
      <td style="padding:10px 12px;text-align:center">
        <button class="btn btn-xs" style="font-size:10px" onclick="sqForceSubmit('${quizId}','${s.attemptId}','${esc(s.student.name).replace(/'/g,"\\'")}')">Force Submit</button>
      </td>
    </tr>`;
  }).join('');

  content.innerHTML = `
    <div style="display:flex;align-items:center;justify-content:space-between;gap:12px;margin-bottom:18px;flex-wrap:wrap">
      <div>
        <div style="display:flex;align-items:center;gap:10px">
          <button class="btn btn-secondary btn-sm" onclick="renderQuizMonitorPage()">← Back</button>
          <h2 style="font-size:18px;font-weight:800;margin:0">${esc(quizTitle)}</h2>
          <span style="background:#dcfce7;color:#166534;padding:3px 10px;border-radius:20px;font-size:11px;font-weight:700">● LIVE</span>
        </div>
        <div style="margin-top:4px;font-size:12px;color:var(--text-muted)">
          Security: <span style="background:${secColor}22;color:${secColor};padding:1px 8px;border-radius:20px;font-size:11px;font-weight:700">${(quiz.securityLevel||'medium').toUpperCase()}</span>
          · ${quiz.monitoringMode === 'ai' ? '🤖 AI Monitoring ON' : '📋 Standard monitoring'}
          ${quiz.mobileMonitoring ? ' · 📱 Mobile' : ''}
        </div>
      </div>
      <button class="btn btn-sm" style="background:#f1f5f9;border:1px solid var(--border)" onclick="renderQuizLiveDashboard('${quizId}','${esc(quizTitle).replace(/'/g,"\\'")}')">🔄 Refresh</button>
    </div>

    <!-- KPI row -->
    <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(130px,1fr));gap:10px;margin-bottom:18px">
      ${[
        { label:'Total', value:fmt(summary.total),     color:'#6366f1' },
        { label:'Active', value:fmt(summary.active),   color:'#22c55e' },
        { label:'Submitted', value:fmt(summary.submitted), color:'#3b82f6' },
        { label:'Online now', value:fmt(summary.online),  color:'#10b981' },
        { label:'Terminated', value:fmt(summary.terminated), color:'#ef4444' },
      ].map(k => `<div style="background:var(--card);border:1.5px solid ${k.color}33;border-radius:12px;padding:14px;text-align:center">
        <div style="font-size:22px;font-weight:800;color:${k.color}">${k.value}</div>
        <div style="font-size:11px;color:var(--text-muted);margin-top:2px">${k.label}</div>
      </div>`).join('')}
    </div>

    <div style="display:grid;grid-template-columns:1fr 300px;gap:16px;align-items:start">
      <!-- Student table -->
      <div style="background:var(--card);border:1px solid var(--border);border-radius:14px;overflow:hidden">
        <div style="padding:12px 16px;border-bottom:1px solid var(--border);font-weight:700;font-size:13px">Students (${students.length})</div>
        <div style="overflow-x:auto">
          <table style="width:100%;border-collapse:collapse;font-size:12px">
            <thead><tr style="background:var(--bg);border-bottom:1.5px solid var(--border)">
              <th style="padding:8px 12px;text-align:left;font-size:11px;color:var(--text-muted);text-transform:uppercase">Student</th>
              <th style="padding:8px 12px;text-align:left;font-size:11px;color:var(--text-muted);text-transform:uppercase">Status</th>
              <th style="padding:8px 12px;text-align:center;font-size:11px;color:var(--text-muted);text-transform:uppercase">Violations</th>
              <th style="padding:8px 12px;text-align:center;font-size:11px;color:var(--text-muted);text-transform:uppercase">Time left</th>
              <th style="padding:8px 12px;text-align:center;font-size:11px;color:var(--text-muted);text-transform:uppercase">Score</th>
              <th style="padding:8px 12px;text-align:center;font-size:11px;color:var(--text-muted);text-transform:uppercase">Action</th>
            </tr></thead>
            <tbody>${studentRows || '<tr><td colspan="6" style="text-align:center;padding:24px;color:var(--text-muted)">No students yet</td></tr>'}</tbody>
          </table>
        </div>
      </div>

      <!-- Live event feed -->
      <div style="background:var(--card);border:1px solid var(--border);border-radius:14px;overflow:hidden">
        <div style="padding:12px 16px;border-bottom:1px solid var(--border);font-weight:700;font-size:13px;display:flex;align-items:center;justify-content:space-between">
          Live Events
          <span style="width:8px;height:8px;border-radius:50%;background:#22c55e;display:inline-block" title="WebSocket connected"></span>
        </div>
        <div id="qm-feed" style="padding:10px;max-height:480px;overflow-y:auto">
          ${recentViolations.length === 0
            ? '<p style="font-size:12px;color:#94a3b8;text-align:center;padding:24px 0">No events yet</p>'
            : recentViolations.map(v => `
              <div style="display:flex;align-items:flex-start;gap:8px;padding:7px 10px;border-left:3px solid ${v.severity==='critical'?'#ef4444':v.severity==='warning'?'#f59e0b':'#94a3b8'};background:${v.severity==='critical'?'#fef2f2':v.severity==='warning'?'#fffbeb':'#f8fafc'};border-radius:0 8px 8px 0;margin-bottom:5px">
                <div style="flex:1;min-width:0">
                  <div style="font-size:11px;font-weight:700;color:${v.severity==='critical'?'#ef4444':'#f59e0b'}">${v.violationType?.replace(/_/g,' ') || 'Event'}</div>
                  ${v.causedTermination ? '<div style="font-size:10px;color:#ef4444;font-weight:700">SESSION TERMINATED</div>' : ''}
                </div>
                <span style="font-size:10px;color:#94a3b8;white-space:nowrap">${v.occurredAt ? new Date(v.occurredAt).toLocaleTimeString() : ''}</span>
              </div>`).join('')}
        </div>
      </div>
    </div>`;
}

window.sqForceSubmit = async function(quizId, attemptId, studentName) {
  if (!confirm(`Force-submit quiz for ${studentName}? This cannot be undone.`)) return;
  try {
    await api(`/api/lecturer/snap-quizzes/${quizId}/attempts/${attemptId}/force-submit`, { method: 'POST' });
    toastSuccess(`Submitted for ${studentName}`);
    const row = document.getElementById('qm-student-' + attemptId);
    if (row) {
      row.style.opacity = '0.6';
      const st = row.querySelector('.qm-status');
      if (st) { st.textContent = 'Force-submitted'; st.style.color = '#22c55e'; }
    }
  } catch (e) {
    toastError(e.message);
  }
};

// Cleanup ws when navigating away
document.addEventListener('navigated', () => {
  if (_quizMonitorWs) { try { _quizMonitorWs.close(); } catch(_) {} _quizMonitorWs = null; }
  if (_quizMonitorRefreshTimer) { clearInterval(_quizMonitorRefreshTimer); _quizMonitorRefreshTimer = null; }
});

async function renderAdminQuizzes(content) {
  try {
    const data = await api('/api/admin/quizzes');
    const quizzes = data.quizzes || [];
    content.innerHTML = `
      <div class="page-header"><h2>Quizzes</h2><p>Overview of all quizzes across all lecturers</p></div>

      <!-- Duplicate finder tool -->
      <div class="card" style="margin-bottom:16px;border:2px solid #fde68a;background:#fffbeb">
        <div style="display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:10px">
          <div>
            <div style="font-size:14px;font-weight:700;margin-bottom:2px">🔍 Duplicate Quiz Finder</div>
            <div style="font-size:12px;color:#92400e">Find and remove quizzes with the same title</div>
          </div>
          <button class="btn btn-primary" style="background:#f59e0b;border-color:#f59e0b" onclick="findDuplicateQuizzes()">Scan for Duplicates</button>
        </div>
        <div id="duplicates-result" style="margin-top:12px"></div>
      </div>

      <div class="card">
        ${quizzes.length ? `
          <table>
            <thead><tr><th>Title</th><th>Lecturer</th><th>Course</th><th>Questions</th><th>Submissions</th><th>Avg Score</th><th>Status</th><th>Actions</th></tr></thead>
            <tbody>${quizzes.map(q => `
              <tr>
                <td><strong>${q.title}</strong></td>
                <td>${q.createdBy?.name || 'Unknown'}</td>
                <td>${q.course?.code || 'N/A'}</td>
                <td>${q.questionCount || 0}</td>
                <td>${q.attemptCount || 0}</td>
                <td>${q.averageScore || 0}</td>
                <td>${quizStatusBadge(q)}</td>
                <td style="display:flex;gap:6px">
                  <button class="btn btn-sm btn-secondary" onclick="viewAdminQuizDetail('${q._id}')">View</button>
                  <button class="btn btn-sm" style="background:#fef2f2;color:#dc2626;border:1px solid #fecaca;font-size:11px" onclick="adminDeleteQuiz('${q._id}','${q.title.replace(/'/g,"\\'")}')">Delete</button>
                </td>
              </tr>
            `).join('')}</tbody>
          </table>
        ` : '<div class="empty-state"><p>No quizzes found.</p></div>'}
      </div>
    `;
  } catch (e) {
    content.innerHTML = `<div class="card"><p>Error: ${e.message}</p></div>`;
  }
}

async function findDuplicateQuizzes() {
  const el = document.getElementById('duplicates-result');
  if (!el) return;
  el.innerHTML = '<p style="font-size:13px;color:#92400e">Scanning…</p>';
  try {
    const { duplicates } = await api('/api/admin/quizzes/utils/duplicates');
    if (!duplicates.length) {
      el.innerHTML = '<p style="font-size:13px;color:#16a34a;font-weight:600">✅ No duplicate quizzes found.</p>';
      return;
    }
    el.innerHTML = `
      <div style="font-size:13px;font-weight:700;color:#92400e;margin-bottom:10px">
        Found ${duplicates.length} group(s) of duplicates:
      </div>
      ${duplicates.map(group => `
        <div style="border:1px solid #fde68a;border-radius:8px;padding:12px;margin-bottom:10px;background:#fff">
          <div style="font-weight:700;margin-bottom:8px">
            "${group._id.title}" — ${group.count} copies
          </div>
          <table style="width:100%;font-size:12px;border-collapse:collapse">
            <thead><tr style="color:#6b7280">
              <th style="text-align:left;padding:4px 8px">Title</th>
              <th style="text-align:left;padding:4px 8px">Created By</th>
              <th style="text-align:left;padding:4px 8px">Date</th>
              <th style="text-align:left;padding:4px 8px">Type</th>
              <th style="padding:4px 8px">Action</th>
            </tr></thead>
            <tbody>
              ${group.quizzes.map((q, i) => `
                <tr style="border-top:1px solid #f3f4f6;${i === 0 ? 'background:#f0fdf4' : ''}">
                  <td style="padding:6px 8px;font-weight:${i===0?'700':'400'}">${q.title} ${i===0 ? '<span style="font-size:10px;color:#16a34a;font-weight:600">(keep)</span>' : ''}</td>
                  <td style="padding:6px 8px">${q.createdByName || '—'}</td>
                  <td style="padding:6px 8px">${new Date(q.createdAt).toLocaleDateString()}</td>
                  <td style="padding:6px 8px">${q.type || '—'}</td>
                  <td style="padding:6px 8px;text-align:center">
                    ${i === 0
                      ? '<span style="color:#16a34a;font-size:11px">✓ Keep</span>'
                      : `<button class="btn btn-sm" style="background:#fef2f2;color:#dc2626;border:1px solid #fecaca;font-size:11px" onclick="adminDeleteQuiz('${q.id}','${q.title.replace(/'/g,"\\'")}', true)">Delete</button>`
                    }
                  </td>
                </tr>
              `).join('')}
            </tbody>
          </table>
        </div>
      `).join('')}
    `;
  } catch(e) {
    el.innerHTML = `<p style="color:#ef4444;font-size:13px">Error: ${e.message}</p>`;
  }
}

async function adminDeleteQuiz(id, title, fromDuplicates = false) {
  if (!confirm(`Delete quiz "${title}"?\n\nThis will permanently remove all questions and submissions.`)) return;
  try {
    await api(`/api/admin/quizzes/${id}`, { method: 'DELETE' });
    toast(`Quiz "${title}" deleted`, 'ok');
    if (fromDuplicates) {
      findDuplicateQuizzes(); // re-scan
    } else {
      const content = document.getElementById('main-content');
      if (content) await renderAdminQuizzes(content);
    }
  } catch(e) {
    toast(e.message || 'Failed to delete quiz', 'err');
  }
}

async function viewAdminQuizDetail(quizId) {
  const content = document.getElementById('main-content');
  if (!content) return;
  content.innerHTML = '<div class="card"><p>Loading...</p></div>';
  try {
    const data = await api(`/api/admin/quizzes/${quizId}`);
    const quiz = data.quiz;
    const questions = data.questions || [];
    const attempts = data.attempts || [];
    const stats = data.stats || {};

    content.innerHTML = `
      <div class="page-header"><h2>${quiz.title}</h2><p>${quiz.description || 'No description'} — by ${quiz.createdBy?.name || 'Unknown'}</p></div>
      <div class="actions-bar"><button class="btn btn-secondary btn-sm" onclick="renderQuizzes()">← Back</button></div>
      <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(140px,1fr));gap:12px;margin-bottom:16px;">
        <div class="card" style="text-align:center;"><div style="font-size:1.8em;font-weight:bold;color:#3b82f6;">${stats.submitted || 0}</div><div style="color:#6b7280;font-size:0.9em;">Submitted</div></div>
        <div class="card" style="text-align:center;"><div style="font-size:1.8em;font-weight:bold;color:#22c55e;">${stats.averageScore || 0}</div><div style="color:#6b7280;font-size:0.9em;">Avg Score</div></div>
        <div class="card" style="text-align:center;"><div style="font-size:1.8em;font-weight:bold;color:#f59e0b;">${stats.highestScore || 0}</div><div style="color:#6b7280;font-size:0.9em;">Highest</div></div>
        <div class="card" style="text-align:center;"><div style="font-size:1.8em;font-weight:bold;color:#ef4444;">${stats.lowestScore || 0}</div><div style="color:#6b7280;font-size:0.9em;">Lowest</div></div>
      </div>
      <div class="card" style="margin-bottom:16px;">
        <h3>Quiz Info</h3>
        <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:10px;margin-top:8px;">
          <div><strong>Course:</strong> ${quiz.course?.code || 'N/A'} — ${quiz.course?.title || ''}</div>
          <div><strong>Time Limit:</strong> ${quiz.timeLimit || 30} min</div>
          <div><strong>Total Marks:</strong> ${quiz.totalMarks || 0}</div>
          <div><strong>Start:</strong> ${new Date(quiz.startTime).toLocaleString()}</div>
          <div><strong>End:</strong> ${new Date(quiz.endTime).toLocaleString()}</div>
          <div><strong>Status:</strong> ${quizStatusBadge(quiz)}</div>
        </div>
      </div>
      <div class="card" style="margin-bottom:16px;">
        <h3>Questions (${questions.length})</h3>
        ${questions.length ? questions.map((qn, i) => `
          <div style="padding:10px;border:1px solid #e5e7eb;border-radius:8px;margin-bottom:8px;">
            <strong>Q${i + 1}.</strong> ${qn.questionText} <span style="color:#9ca3af;">(${qn.marks} marks)</span>
            <div style="margin-top:4px;font-size:0.9em;">
              ${qn.options.map((o, oi) => `<span style="margin-right:10px;${oi === qn.correctAnswer ? 'color:#22c55e;font-weight:bold;' : ''}">${String.fromCharCode(65 + oi)}) ${o}</span>`).join('')}
            </div>
          </div>
        `).join('') : '<p style="color:#9ca3af;">No questions.</p>'}
      </div>
      <div class="card">
        <h3>Student Submissions (${attempts.length})</h3>
        ${attempts.length ? `
          <table>
            <thead><tr><th>Student</th><th>ID</th><th>Score</th><th>Percentage</th><th>Submitted</th></tr></thead>
            <tbody>${attempts.map(a => {
              const pct = a.maxScore > 0 ? Math.round((a.score / a.maxScore) * 100) : 0;
              return `<tr>
                <td>${a.student?.name || 'Unknown'}</td>
                <td>${a.student?.IndexNumber || a.student?.indexNumber || a.student?.email || 'N/A'}</td>
                <td>${a.score}/${a.maxScore}</td>
                <td><span style="color:${pct >= 50 ? '#22c55e' : '#ef4444'};font-weight:bold;">${pct}%</span></td>
                <td>${a.submittedAt ? new Date(a.submittedAt).toLocaleString() : 'N/A'}</td>
              </tr>`;
            }).join('')}</tbody>
          </table>
        ` : '<div class="empty-state"><p>No submissions yet.</p></div>'}
      </div>
    `;
  } catch (e) {
    content.innerHTML = `<div class="card"><p>Error: ${e.message}</p><button class="btn btn-secondary" onclick="renderQuizzes()">← Back</button></div>`;
  }
}

async function renderMyAttendance() {
  const content = document.getElementById('main-content');
  if (!content) return;

  // Corporate employees use the rich CorporateAttendance system
  if (currentUser.company?.mode === 'corporate') {
    return renderMyCorporateAttendance(content);
  }

  // Academic students use the session-based system
  if (!isOnline()) {
    const cached = offlineRead('my_attendance');
    if (cached) {
      content.innerHTML = '<div style="background:#fef3c7;color:#92400e;padding:10px 16px;border-radius:8px;font-size:13px;margin-bottom:16px">📡 Offline — showing cached attendance</div>';
      _renderMyAttendanceHTML(content, cached);
    } else {
      content.innerHTML = '<div class="card" style="text-align:center;padding:32px"><div style="font-size:36px">📡</div><p style="margin-top:8px;color:var(--text-light)">No cached data. Connect once to view attendance offline.</p></div>';
    }
    return;
  }
  try {
    const data = await api('/api/attendance-sessions/my-attendance');
    offlineCache('my_attendance', data);
    content.innerHTML = `
      <div class="page-header"><h2>My Attendance</h2><p>Your attendance history</p></div>
      <div class="card">
        ${data.records.length ? `
          <table>
            <thead><tr><th>Session</th><th>Status</th><th>Method</th><th>Check-in Time</th></tr></thead>
            <tbody>${data.records.map(r => `
              <tr>
                <td>${r.session?.title || 'N/A'}</td>
                <td><span class="status-badge status-${r.status}">${r.status}</span></td>
                <td>${r.method}</td>
                <td>${new Date(r.checkInTime).toLocaleString()}</td>
              </tr>
            `).join('')}</tbody>
          </table>
        ` : '<div class="empty-state"><p>No attendance records yet</p></div>'}
      </div>
    `;
  } catch (e) {
    content.innerHTML = `<div class="card"><p>Error: ${e.message}</p></div>`;
  }
}

async function renderMyCorporateAttendance(content) {
  try {
    // Fetch current month by default
    const now       = new Date();
    const fromDate  = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().slice(0, 10);
    const toDate    = now.toISOString().slice(0, 10);

    const data = await api(`/api/corporate-attendance/my?from=${fromDate}&to=${toDate}`);
    const records = data.records || [];

    // Summary stats
    const totalDays    = records.length;
    const presentDays  = records.filter(r => r.status === 'present' || r.status === 'late').length;
    const lateDays     = records.filter(r => r.status === 'late').length;
    const totalWorked  = records.reduce((s, r) => s + (r.hoursWorked || 0), 0);
    const totalOvertime = records.reduce((s, r) => s + (r.overtimeHours || 0), 0);
    const attendanceRate = totalDays > 0 ? Math.round((presentDays / totalDays) * 100) : 0;

    const statusColors = { present:'#16a34a', late:'#d97706', absent:'#dc2626', half_day:'#7c3aed', on_leave:'#0284c7', remote:'#0891b2' };

    content.innerHTML = `
      <div class="page-header">
        <h2>My Attendance</h2>
        <p>${now.toLocaleString('en-GB', {month:'long', year:'numeric'})}</p>
      </div>

      <div class="stats-grid">
        <div class="stat-card"><div class="stat-value">${attendanceRate}%</div><div class="stat-label">Attendance Rate</div></div>
        <div class="stat-card"><div class="stat-value">${presentDays}</div><div class="stat-label">Days Present</div></div>
        <div class="stat-card"><div class="stat-value">${Math.round(totalWorked * 10) / 10}h</div><div class="stat-label">Hours Worked</div></div>
        <div class="stat-card"><div class="stat-value">${lateDays}</div><div class="stat-label">Late Arrivals</div></div>
        ${totalOvertime > 0 ? `<div class="stat-card"><div class="stat-value" style="color:#8b5cf6">+${Math.round(totalOvertime*10)/10}h</div><div class="stat-label">Overtime</div></div>` : ''}
      </div>

      <div class="card">
        <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:12px;flex-wrap:wrap;gap:8px">
          <div class="card-title" style="margin:0">Attendance Records</div>
          <button class="btn btn-primary btn-sm" onclick="navigateTo('sign-in-out')">
            ${svgIcon('<polyline points="9 11 12 14 22 4"/><path d="M21 12v7a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11"/>', 14)} Clock In / Out
          </button>
        </div>
        ${records.length ? `
          <div style="overflow-x:auto">
          <table>
            <thead>
              <tr>
                <th>Date</th><th>Status</th><th>Shift</th>
                <th>Time In</th><th>Time Out</th>
                <th>Worked</th><th>Overtime</th><th>Lateness</th>
              </tr>
            </thead>
            <tbody>${records.map(r => {
              const ci  = r.clockIn?.time  ? new Date(r.clockIn.time)  : null;
              const co  = r.clockOut?.time ? new Date(r.clockOut.time) : null;
              const dateStr = r.date ? new Date(r.date).toLocaleDateString('en-GB', {day:'2-digit',month:'short'}) : '—';
              const sc  = statusColors[r.status] || 'var(--text-light)';
              return `<tr>
                <td style="font-size:13px;font-weight:600;white-space:nowrap">${dateStr}</td>
                <td><span style="background:${sc}20;color:${sc};border:1px solid ${sc}40;padding:2px 8px;border-radius:20px;font-size:11px;font-weight:700;text-transform:capitalize;white-space:nowrap">${(r.status || '—').replace(/_/g,' ')}</span></td>
                <td style="font-size:12px;color:var(--text-muted)">${r.shift?.name || '—'}</td>
                <td style="font-size:13px">${ci ? ci.toLocaleTimeString([], {hour:'2-digit',minute:'2-digit'}) : '—'}</td>
                <td style="font-size:13px">${co ? co.toLocaleTimeString([], {hour:'2-digit',minute:'2-digit'}) : (ci ? '<span style="color:#f59e0b;font-size:11px;font-weight:600">Active</span>' : '—')}</td>
                <td style="font-size:13px">${r.hoursWorked != null ? r.hoursWorked+'h' : '—'}</td>
                <td style="font-size:13px">${r.overtimeHours > 0 ? '<span style="color:#8b5cf6;font-weight:600">+'+r.overtimeHours+'h</span>' : '—'}</td>
                <td style="font-size:13px">${r.clockIn?.isLate ? '<span style="color:#ef4444">'+r.clockIn.lateMinutes+'m late</span>' : (ci ? '<span style="color:#16a34a">On time</span>' : '—')}</td>
              </tr>`;
            }).join('')}</tbody>
          </table>
          </div>
        ` : '<div class="empty-state"><p>No attendance records this month. Use Clock In / Out to start.</p></div>'}
      </div>
    `;
  } catch (e) {
    content.innerHTML = `<div class="card"><p>Error loading attendance: ${e.message}</p></div>`;
  }
}




