async function loadMyDevices() {
  const container = document.getElementById('devices-list');
  if (!container) return;
  const esc = (s) => s == null ? '' : String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
  try {
    const data = await api('/api/auth/my-devices');
    const devices = data.devices || [];
    if (devices.length === 0) {
      container.innerHTML = `<div style="color:var(--text-muted);font-size:13px;text-align:center;padding:12px 0">No devices found</div>`;
      return;
    }

    const platformIcon = (p) => p === 'mobile' ? '📱' : p === 'tablet' ? '📟' : p === 'desktop' ? '💻' : '🖥️';
    const timeAgo = (dateStr) => {
      if (!dateStr) return 'Unknown';
      const diff = Date.now() - new Date(dateStr).getTime();
      const m = Math.floor(diff / 60000);
      if (m < 1) return 'Just now';
      if (m < 60) return `${m}m ago`;
      const h = Math.floor(m / 60);
      if (h < 24) return `${h}h ago`;
      return `${Math.floor(h / 24)}d ago`;
    };

    container.innerHTML = devices.map(d => `
      <div style="display:flex;align-items:center;gap:12px;padding:12px 14px;border-radius:10px;border:1.5px solid ${d.isCurrent ? 'var(--primary)' : 'var(--border)'};background:${d.isCurrent ? 'rgba(79,70,229,0.04)' : 'var(--bg)'};margin-bottom:10px">
        <div style="font-size:28px;flex-shrink:0">${platformIcon(d.platform)}</div>
        <div style="flex:1;min-width:0">
          <div style="display:flex;align-items:center;gap:8px;font-weight:600;font-size:13px">
            ${d.platform ? esc(d.platform.charAt(0).toUpperCase() + d.platform.slice(1)) : 'Unknown device'}
            ${d.isCurrent ? `<span style="font-size:10px;padding:2px 8px;border-radius:20px;background:var(--primary);color:#fff;font-weight:700">Current</span>` : ''}
          </div>
          <div style="font-size:11px;color:var(--text-muted);margin-top:2px">${esc(d.ipAddress) || 'IP unknown'} · Last seen ${timeAgo(d.lastSeenAt)}</div>
          ${d.userAgent ? `<div style="font-size:10px;color:var(--text-muted);margin-top:1px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${esc(d.userAgent)}</div>` : ''}
        </div>
        ${!d.isCurrent ? `<button onclick="removeDevice('${esc(d.deviceId)}')" style="flex-shrink:0;padding:6px 12px;border-radius:8px;border:1.5px solid #ef4444;background:transparent;color:#ef4444;font-size:12px;font-weight:600;cursor:pointer">Remove</button>` : ''}
      </div>
    `).join('');

    // Show device lock warning if active
    if (data.deviceLock?.isLocked && data.deviceLock?.lockedUntil) {
      const until = new Date(data.deviceLock.lockedUntil);
      const remainingH = ((until - Date.now()) / 3600000).toFixed(1);
      container.insertAdjacentHTML('beforeend', `
        <div style="margin-top:12px;padding:10px 14px;border-radius:8px;background:#fef2f2;border:1.5px solid #fca5a5;color:#b91c1c;font-size:13px">
          ⚠️ Account locked due to new device login. Unlocks in ${remainingH}h (${until.toLocaleTimeString()}).
        </div>
      `);
    }
  } catch (e) {
    container.innerHTML = `<div style="color:var(--text-muted);font-size:13px">Could not load devices.</div>`;
  }
}

async function removeDevice(deviceId) {
  if (!confirm('Remove this device from your trusted list?')) return;
  try {
    await api(`/api/auth/my-devices/${encodeURIComponent(deviceId)}`, { method: 'DELETE' });
    toastSuccess('Device removed');
    loadMyDevices();
  } catch (e) {
    toastError('Failed to remove device');
  }
}

async function toggle2FA(enable) {
  const cb = document.getElementById('twofa-toggle');
  try {
    await api('/api/auth/2fa/toggle', { method: 'POST', body: JSON.stringify({ enable }) });
    currentUser.twoFactorEnabled = enable;
    // Update toggle visual immediately
    const span = document.querySelector('#twofa-toggle + span');
    if (span) {
      span.style.background = enable ? 'var(--primary)' : '#d1d5db';
      const dot = span.querySelector('span');
      if (dot) dot.style.left = enable ? '23px' : '3px';
    }
    if (cb) cb.checked = enable;
    showToastNotif(enable ? '2FA enabled — you will get a code by email each login' : '2FA disabled', enable ? 'success' : 'warn');
  } catch(e) {
    showToastNotif('Failed to update 2FA: ' + e.message, 'warn');
    // Revert toggle
    if (cb) cb.checked = !enable;
  }
}

async function saveProfile() {
  const name = document.getElementById('profile-name').value.trim();
  const dept = document.getElementById('profile-dept')?.value?.trim();
  const currentPassword = document.getElementById('profile-current-pw').value;
  const newPassword = document.getElementById('profile-new-pw').value;
  const confirmPw = document.getElementById('profile-confirm-pw').value;
  const msg = document.getElementById('profile-msg');

  if (newPassword && newPassword !== confirmPw) {
    msg.textContent = 'New passwords do not match'; msg.style.background = '#fef2f2'; msg.style.color = '#dc2626'; msg.style.display = 'block'; return;
  }
  if (newPassword && newPassword.length < 8) {
    msg.textContent = 'Password must be at least 8 characters'; msg.style.background = '#fef2f2'; msg.style.color = '#dc2626'; msg.style.display = 'block'; return;
  }

  const body = {};
  if (name) body.name = name;
  if (dept !== undefined && ['lecturer','hod'].includes(currentUser.role)) {
    body.department = dept;
  }
  if (newPassword) { body.currentPassword = currentPassword; body.newPassword = newPassword; }

  try {
    const data = await api('/api/auth/profile', { method: 'PUT', body: JSON.stringify(body) });
    if (data.user?.name) { currentUser.name = data.user.name; document.getElementById('user-name').textContent = data.user.name; }
    if (data.user?.department !== undefined) { currentUser.department = data.user.department; }
    msg.textContent = '✅ Profile updated successfully!'; msg.style.background = '#f0fdf4'; msg.style.color = '#15803d'; msg.style.display = 'block';
    document.getElementById('profile-current-pw').value = '';
    document.getElementById('profile-new-pw').value = '';
    document.getElementById('profile-confirm-pw').value = '';
    setTimeout(() => { msg.style.display = 'none'; }, 4000);
  } catch(e) {
    msg.textContent = e.message; msg.style.background = '#fef2f2'; msg.style.color = '#dc2626'; msg.style.display = 'block';
  }
}

