// ═══════════════════════════════════════════════════════════════════
//  CORPORATE MODULES: Departments · Teams · Tasks · Calendar ·
//  Company Settings · Roles & Permissions
// ═══════════════════════════════════════════════════════════════════

function _corpHeader(title, sub) {
  return `<div class="page-header" style="margin-bottom:1.2rem"><div>
    <h1 style="margin:0 0 .25rem">${title}</h1>
    <p style="margin:0;color:var(--text-light);font-size:.9rem">${sub}</p>
  </div></div>`;
}

// ── Departments ─────────────────────────────────────────────────────
async function renderDepartments() {
  const content = document.getElementById('main-content');
  if (!content) return;
  content.innerHTML = _corpHeader('Departments', 'Organize your workforce into departments') + '<div class="card" style="padding:2rem;text-align:center;color:var(--text-light)">Loading…</div>';
  let depts = [];
  try { depts = (await api('/api/departments')).departments || []; }
  catch (e) { content.innerHTML += `<div class="card" style="padding:1rem;color:var(--error)">${esc(e.message)}</div>`; return; }

  const isAdmin = ['admin', 'superadmin'].includes(currentUser.role);
  content.innerHTML = `
    ${_corpHeader('Departments', 'Organize your workforce into departments')}
    ${isAdmin ? `
    <div class="card" style="padding:1rem 1.2rem;margin-bottom:1rem;display:flex;gap:.6rem;flex-wrap:wrap;align-items:center">
      <input id="dept-name" placeholder="Department name (e.g. Human Resources)" style="flex:2;min-width:200px;padding:.6rem .8rem;border:1px solid var(--border);border-radius:8px;background:var(--bg);color:var(--text)" />
      <input id="dept-desc" placeholder="Description (optional)" style="flex:3;min-width:200px;padding:.6rem .8rem;border:1px solid var(--border);border-radius:8px;background:var(--bg);color:var(--text)" />
      <button class="btn btn-primary" onclick="_deptCreate()">+ Add Department</button>
    </div>` : ''}
    <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(260px,1fr));gap:1rem" id="dept-grid">
      ${depts.length ? depts.map(d => `
        <div class="card" style="padding:1.1rem 1.2rem">
          <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:.5rem">
            <div style="font-weight:700;font-size:.95rem">${esc(d.name)}</div>
            ${isAdmin ? `<button class="btn btn-sm btn-ghost" title="Delete" onclick="_deptDelete('${d._id}','${esc(d.name)}')" style="padding:.15rem .45rem">✕</button>` : ''}
          </div>
          ${d.description ? `<div style="font-size:.78rem;color:var(--text-light);margin-top:.3rem">${esc(d.description)}</div>` : ''}
          <div style="margin-top:.7rem;display:flex;gap:1rem;font-size:.78rem;color:var(--text-muted)">
            <span>👥 ${d.headcount} member${d.headcount === 1 ? '' : 's'}</span>
            ${d.head?.name ? `<span>Head: ${esc(d.head.name)}</span>` : ''}
          </div>
          <div style="margin-top:.7rem;display:flex;gap:.5rem;flex-wrap:wrap">
            <button class="btn btn-sm btn-ghost" style="font-size:.75rem" onclick="_deptEmployees('${d._id}','${esc(d.name)}')">View employees</button>
            ${isAdmin ? `<button class="btn btn-sm btn-ghost" style="font-size:.75rem" onclick="_deptAssign('${d._id}','${esc(d.name).replace(/'/g,"\\'")}')">+ Assign employees</button>` : ''}
          </div>
          <div id="dept-emps-${d._id}"></div>
        </div>`).join('') : '<div class="card" style="padding:2rem;text-align:center;color:var(--text-muted)">No departments yet — create your first one above.</div>'}
    </div>`;
}
window._deptCreate = async function() {
  const name = document.getElementById('dept-name')?.value?.trim();
  const description = document.getElementById('dept-desc')?.value?.trim();
  if (!name) { toastError('Enter a department name'); return; }
  try {
    await api('/api/departments', { method: 'POST', body: JSON.stringify({ name, description }) });
    toastSuccess('Department created');
    renderDepartments();
  } catch (e) { toastError(e.message); }
};
window._deptDelete = async function(id, name) {
  if (!confirm(`Delete department "${name}"? Employees keep their department label but it will no longer be managed here.`)) return;
  try { await api('/api/departments/' + id, { method: 'DELETE' }); toastSuccess('Department deleted'); renderDepartments(); }
  catch (e) { toastError(e.message); }
};
window._deptEmployees = async function(id, name) {
  const box = document.getElementById('dept-emps-' + id);
  if (!box) return;
  if (box.innerHTML) { box.innerHTML = ''; return; }
  box.innerHTML = '<div style="font-size:.75rem;color:var(--text-muted);padding:.4rem 0">Loading…</div>';
  try {
    const d = await api(`/api/departments/${id}/employees`);
    const emps = d.employees || d.users || [];
    box.innerHTML = emps.length
      ? `<div style="margin-top:.5rem;border-top:1px solid var(--border);padding-top:.5rem;display:flex;flex-direction:column;gap:.3rem">${emps.map(u => `<div style="font-size:.78rem;color:var(--text-light)">• ${esc(u.name)}${u.role ? ` <span style="color:var(--text-muted)">(${u.role})</span>` : ''}</div>`).join('')}</div>`
      : '<div style="font-size:.75rem;color:var(--text-muted);padding:.4rem 0">No employees assigned yet.</div>';
  } catch (e) { box.innerHTML = `<div style="font-size:.75rem;color:var(--error)">${esc(e.message)}</div>`; }
};

// ── Assign existing employees to a department ──────────────────────────────
window._deptAssign = async function(deptId, deptName) {
  let users = [];
  try { users = (await api('/api/users')).users || []; }
  catch (e) { toastError(e.message); return; }

  const candidates = users
    .filter(u => ['employee', 'manager'].includes(u.role) && u.isActive)
    .sort((a, b) => (a.name || '').localeCompare(b.name || ''));

  const rows = candidates.length
    ? candidates.map(u => `
        <label style="display:flex;align-items:center;gap:8px;padding:7px 4px;border-bottom:1px solid var(--border);font-size:13px">
          <input type="checkbox" class="dept-assign-cb" value="${u._id}" ${u.department === deptName ? 'checked' : ''}>
          <span style="flex:1">${esc(u.name)}</span>
          ${u.department && u.department !== deptName ? `<span style="font-size:11px;color:var(--text-muted)">currently: ${esc(u.department)}</span>` : ''}
        </label>`).join('')
    : `<p style="font-size:12.5px;color:var(--text-light);padding:8px 0">No employees or managers yet.</p>`;

  const container = document.getElementById('modal-container');
  container.classList.remove('hidden');
  container.innerHTML = `
    <div class="modal-overlay" onclick="closeModal(event)">
      <div class="modal" onclick="event.stopPropagation()">
        <h3>Assign employees to ${esc(deptName)}</h3>
        <p style="font-size:12.5px;color:var(--text-light);margin-bottom:8px">Check who belongs in this department. Unchecking someone already here removes them from it.</p>
        <div style="max-height:320px;overflow-y:auto">${rows}</div>
        <div class="modal-actions">
          <button class="btn btn-secondary btn-sm" onclick="closeModal()">Cancel</button>
          <button class="btn btn-primary btn-sm" onclick="_saveDeptAssign('${deptId}','${deptName.replace(/'/g,"\\'")}')" ${candidates.length ? '' : 'disabled'}>Save</button>
        </div>
      </div>
    </div>
  `;
  window._deptAssignCandidates = candidates; // stash for diffing on save
};
window._saveDeptAssign = async function(deptId, deptName) {
  const boxes = Array.from(document.querySelectorAll('.dept-assign-cb'));
  const candidates = window._deptAssignCandidates || [];
  const byId = Object.fromEntries(candidates.map(u => [u._id, u]));

  const changes = boxes
    .map(cb => {
      const u = byId[cb.value];
      if (!u) return null;
      const wasIn = u.department === deptName;
      if (cb.checked === wasIn) return null; // unchanged
      return { id: u._id, department: cb.checked ? deptName : null };
    })
    .filter(Boolean);

  if (!changes.length) { closeModal(); return; }

  try {
    await Promise.all(changes.map(c =>
      api(`/api/users/${c.id}`, { method: 'PATCH', body: JSON.stringify({ department: c.department }) })
    ));
    toastSuccess(`Updated ${changes.length} employee${changes.length === 1 ? '' : 's'}`);
    closeModal();
    renderDepartments();
  } catch (e) { toastError(e.message); }
};

// ── Teams ───────────────────────────────────────────────────────────
async function renderCorpTeams() {
  const content = document.getElementById('main-content');
  if (!content) return;
  content.innerHTML = _corpHeader('Teams', 'Cross-department working groups') + '<div class="card" style="padding:2rem;text-align:center;color:var(--text-light)">Loading…</div>';
  let teams = [], depts = [];
  try {
    const [t, d] = await Promise.all([api('/api/teams'), api('/api/departments').catch(() => ({ departments: [] }))]);
    teams = t.teams || []; depts = d.departments || [];
  } catch (e) { content.innerHTML += `<div class="card" style="padding:1rem;color:var(--error)">${esc(e.message)}</div>`; return; }

  const canManage = ['admin', 'superadmin', 'manager'].includes(currentUser.role);
  content.innerHTML = `
    ${_corpHeader('Teams', 'Cross-department working groups')}
    ${canManage ? `
    <div class="card" style="padding:1rem 1.2rem;margin-bottom:1rem;display:flex;gap:.6rem;flex-wrap:wrap;align-items:center">
      <input id="team-name" placeholder="Team name" style="flex:2;min-width:180px;padding:.6rem .8rem;border:1px solid var(--border);border-radius:8px;background:var(--bg);color:var(--text)" />
      <select id="team-dept" style="flex:1;min-width:160px;padding:.6rem .8rem;border:1px solid var(--border);border-radius:8px;background:var(--bg);color:var(--text)">
        <option value="">No department</option>
        ${depts.map(d => `<option value="${d._id}">${esc(d.name)}</option>`).join('')}
      </select>
      <button class="btn btn-primary" onclick="_teamCreate()">+ Add Team</button>
    </div>` : ''}
    <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:1rem">
      ${teams.length ? teams.map(t => `
        <div class="card" style="padding:1.1rem 1.2rem">
          <div style="display:flex;justify-content:space-between;align-items:flex-start">
            <div style="font-weight:700;font-size:.95rem">${esc(t.name)}</div>
            ${['admin','superadmin'].includes(currentUser.role) ? `<button class="btn btn-sm btn-ghost" title="Delete" onclick="_teamDelete('${t._id}','${esc(t.name)}')" style="padding:.15rem .45rem">✕</button>` : ''}
          </div>
          <div style="font-size:.76rem;color:var(--text-muted);margin-top:.25rem">
            ${t.department?.name ? esc(t.department.name) + ' · ' : ''}${(t.members || []).length} member${(t.members || []).length === 1 ? '' : 's'}${t.lead?.name ? ' · Lead: ' + esc(t.lead.name) : ''}
          </div>
          ${(t.members || []).length ? `<div style="margin-top:.6rem;display:flex;flex-wrap:wrap;gap:.3rem">${t.members.slice(0, 8).map(mb => `<span style="font-size:.72rem;background:var(--bg);border:1px solid var(--border);border-radius:20px;padding:.15rem .55rem">${esc(mb.name)}</span>`).join('')}${t.members.length > 8 ? `<span style="font-size:.72rem;color:var(--text-muted)">+${t.members.length - 8} more</span>` : ''}</div>` : ''}
        </div>`).join('') : '<div class="card" style="padding:2rem;text-align:center;color:var(--text-muted)">No teams yet.</div>'}
    </div>`;
}
window._teamCreate = async function() {
  const name = document.getElementById('team-name')?.value?.trim();
  const departmentId = document.getElementById('team-dept')?.value || null;
  if (!name) { toastError('Enter a team name'); return; }
  try {
    await api('/api/teams', { method: 'POST', body: JSON.stringify({ name, departmentId }) });
    toastSuccess('Team created'); renderCorpTeams();
  } catch (e) { toastError(e.message); }
};
window._teamDelete = async function(id, name) {
  if (!confirm(`Delete team "${name}"?`)) return;
  try { await api('/api/teams/' + id, { method: 'DELETE' }); toastSuccess('Team deleted'); renderCorpTeams(); }
  catch (e) { toastError(e.message); }
};

// ── Tasks ───────────────────────────────────────────────────────────
const TASK_STATUS_META = {
  pending:     { label: 'Pending',     color: '#b45309', icon: '⏳' },
  in_progress: { label: 'In Progress', color: '#2563eb', icon: '▶' },
  completed:   { label: 'Completed',   color: '#0ca30c', icon: '✓' },
};
async function renderTasks() {
  const content = document.getElementById('main-content');
  if (!content) return;
  const isManager = ['admin', 'superadmin', 'manager'].includes(currentUser.role);
  const title = isManager ? 'Tasks' : 'My Tasks';
  content.innerHTML = _corpHeader(title, isManager ? 'Assign and track work across your team' : 'Work assigned to you') + '<div class="card" style="padding:2rem;text-align:center;color:var(--text-light)">Loading…</div>';

  let tasks = [], staff = [];
  try {
    const [t, u] = await Promise.all([
      api('/api/tasks'),
      isManager ? api('/api/users?role=employee&limit=200').catch(() => ({ users: [] })) : Promise.resolve({ users: [] }),
    ]);
    tasks = t.tasks || [];
    staff = u.users || [];
  } catch (e) { content.innerHTML += `<div class="card" style="padding:1rem;color:var(--error)">${esc(e.message)}</div>`; return; }

  const counts = { pending: 0, in_progress: 0, completed: 0 };
  tasks.forEach(t => { if (counts[t.status] !== undefined) counts[t.status]++; });

  const taskRow = t => {
    const m = TASK_STATUS_META[t.status] || TASK_STATUS_META.pending;
    const due = t.dueDate ? new Date(t.dueDate) : null;
    const overdue = due && due < new Date() && t.status !== 'completed';
    return `<div class="card" style="padding: .85rem 1rem;display:flex;gap:.8rem;align-items:center;flex-wrap:wrap">
      <span style="color:${m.color};font-weight:800" title="${m.label}">${m.icon}</span>
      <div style="flex:1;min-width:200px">
        <div style="font-weight:600;font-size:.88rem;${t.status === 'completed' ? 'text-decoration:line-through;opacity:.65' : ''}">${esc(t.title)}</div>
        <div style="font-size:.74rem;color:var(--text-muted)">
          ${isManager ? `→ ${esc(t.assignedTo?.name || '?')}` : `From ${esc(t.assignedBy?.name || '?')}`}
          ${due ? ` · due <span style="${overdue ? 'color:var(--error);font-weight:700' : ''}">${due.toLocaleDateString()}</span>` : ''}
          ${t.priority && t.priority !== 'medium' ? ` · <span style="text-transform:capitalize">${t.priority} priority</span>` : ''}
        </div>
        ${t.description ? `<div style="font-size:.76rem;color:var(--text-light);margin-top:.2rem">${esc(t.description)}</div>` : ''}
      </div>
      <select onchange="_taskStatus('${t._id}', this.value)" style="padding:.35rem .5rem;border:1px solid var(--border);border-radius:7px;background:var(--bg);color:var(--text);font-size:.78rem">
        ${Object.entries(TASK_STATUS_META).map(([k, v]) => `<option value="${k}" ${t.status === k ? 'selected' : ''}>${v.label}</option>`).join('')}
      </select>
      ${isManager ? `<button class="btn btn-sm btn-ghost" onclick="_taskDelete('${t._id}')" style="padding:.2rem .5rem">✕</button>` : ''}
    </div>`;
  };

  content.innerHTML = `
    ${_corpHeader(title, isManager ? 'Assign and track work across your team' : 'Work assigned to you')}
    <div style="display:flex;gap:.7rem;margin-bottom:1rem;flex-wrap:wrap">
      ${Object.entries(TASK_STATUS_META).map(([k, v]) => `
        <div class="card" style="padding:.7rem 1.1rem;display:flex;align-items:center;gap:.5rem">
          <span style="color:${v.color};font-weight:800">${v.icon}</span>
          <span style="font-weight:700;font-size:1.05rem">${counts[k]}</span>
          <span style="font-size:.78rem;color:var(--text-light)">${v.label}</span>
        </div>`).join('')}
    </div>
    ${isManager ? `
    <div class="card" style="padding:1rem 1.2rem;margin-bottom:1rem;display:flex;gap:.6rem;flex-wrap:wrap;align-items:center">
      <input id="task-title" placeholder="Task title" style="flex:2;min-width:180px;padding:.6rem .8rem;border:1px solid var(--border);border-radius:8px;background:var(--bg);color:var(--text)" />
      <select id="task-assignee" style="flex:1;min-width:160px;padding:.6rem .8rem;border:1px solid var(--border);border-radius:8px;background:var(--bg);color:var(--text)">
        <option value="">Assign to…</option>
        ${staff.map(u => `<option value="${u._id}">${esc(u.name)}${u.department ? ' — ' + esc(u.department) : ''}</option>`).join('')}
      </select>
      <input id="task-due" type="date" style="padding:.6rem .8rem;border:1px solid var(--border);border-radius:8px;background:var(--bg);color:var(--text)" />
      <select id="task-priority" style="padding:.6rem .8rem;border:1px solid var(--border);border-radius:8px;background:var(--bg);color:var(--text)">
        <option value="medium">Medium</option><option value="high">High</option><option value="low">Low</option>
      </select>
      <button class="btn btn-primary" onclick="_taskCreate()">+ Assign Task</button>
    </div>` : ''}
    <div style="display:flex;flex-direction:column;gap:.55rem">
      ${tasks.length ? tasks.map(taskRow).join('') : '<div class="card" style="padding:2rem;text-align:center;color:var(--text-muted)">No tasks yet.</div>'}
    </div>`;
}
window._taskCreate = async function() {
  const title = document.getElementById('task-title')?.value?.trim();
  const assignedTo = document.getElementById('task-assignee')?.value;
  const dueDate = document.getElementById('task-due')?.value || null;
  const priority = document.getElementById('task-priority')?.value || 'medium';
  if (!title || !assignedTo) { toastError('Title and assignee are required'); return; }
  try {
    await api('/api/tasks', { method: 'POST', body: JSON.stringify({ title, assignedTo, dueDate, priority }) });
    toastSuccess('Task assigned'); renderTasks();
  } catch (e) { toastError(e.message); }
};
window._taskStatus = async function(id, status) {
  try { await api(`/api/tasks/${id}/status`, { method: 'PATCH', body: JSON.stringify({ status }) }); renderTasks(); }
  catch (e) { toastError(e.message); }
};
window._taskDelete = async function(id) {
  if (!confirm('Delete this task?')) return;
  try { await api('/api/tasks/' + id, { method: 'DELETE' }); renderTasks(); }
  catch (e) { toastError(e.message); }
};

// ── Company Calendar ────────────────────────────────────────────────
let _calCursor = null;
async function renderCorpCalendar(offsetMonths) {
  const content = document.getElementById('main-content');
  if (!content) return;
  if (_calCursor === null || offsetMonths === undefined) _calCursor = new Date();
  if (offsetMonths) _calCursor = new Date(_calCursor.getFullYear(), _calCursor.getMonth() + offsetMonths, 1);
  const year = _calCursor.getFullYear(), month = _calCursor.getMonth();

  content.innerHTML = _corpHeader('Company Calendar', 'Meetings, leave, holidays, and company events in one view') + '<div class="card" style="padding:2rem;text-align:center;color:var(--text-light)">Loading…</div>';
  let items = [];
  try { items = (await api(`/api/calendar/company-month?year=${year}&month=${month + 1}`)).items || []; }
  catch (e) { content.innerHTML += `<div class="card" style="padding:1rem;color:var(--error)">${esc(e.message)}</div>`; return; }

  const byDay = {};
  for (const it of items) {
    const s0 = new Date(it.start), e0 = new Date(it.end || it.start);
    for (let d = new Date(Math.max(s0, new Date(year, month, 1))); d <= e0 && d.getMonth() === month; d.setDate(d.getDate() + 1)) {
      (byDay[d.getDate()] = byDay[d.getDate()] || []).push(it);
    }
  }
  const first = new Date(year, month, 1);
  const startPad = (first.getDay() + 6) % 7; // Monday-first
  const daysIn = new Date(year, month + 1, 0).getDate();
  const today = new Date();
  const isToday = d => d === today.getDate() && month === today.getMonth() && year === today.getFullYear();

  const KIND_META = { meeting: ['#0ea5e9', 'Meetings'], leave: ['#f59e0b', 'Leave'], holiday: ['#ef4444', 'Public holidays'], event: ['#6366f1', 'Company events'] };
  const cells = [];
  for (let i = 0; i < startPad; i++) cells.push('<div></div>');
  for (let d = 1; d <= daysIn; d++) {
    const evs = byDay[d] || [];
    cells.push(`<div class="cal-cell${isToday(d) ? ' cal-cell-today' : ''}${evs.length ? ' cal-has-events' : ''}">
      <div class="cal-cell-num${isToday(d) ? ' cal-cell-num-today' : ''}">${d}</div>
      ${evs.slice(0, 3).map(ev => `<div class="cal-ev" title="${esc(ev.title)}" style="background:${ev.color}22;border-left-color:${ev.color}">${esc(ev.title)}</div>`).join('')}
      ${evs.length > 3 ? `<div class="cal-ev-more">+${evs.length - 3} more</div>` : ''}
    </div>`);
  }

  content.innerHTML = `
    ${_corpHeader('Company Calendar', 'Meetings, leave, holidays, and company events in one view')}
    <div class="card cal-card">
      <div class="cal-toolbar">
        <div style="display:flex;align-items:center;gap:.6rem">
          <button class="btn btn-sm btn-ghost" onclick="renderCorpCalendar(-1)">←</button>
          <div style="font-weight:700;font-size:1.02rem;min-width:150px;text-align:center">${first.toLocaleDateString(undefined, { month: 'long', year: 'numeric' })}</div>
          <button class="btn btn-sm btn-ghost" onclick="renderCorpCalendar(1)">→</button>
        </div>
        <div class="cal-legend">
          ${Object.entries(KIND_META).map(([k, [c, lbl]]) => `<span class="cal-legend-item"><span class="cal-legend-dot" style="background:${c}"></span>${lbl}</span>`).join('')}
        </div>
      </div>
      <div class="cal-grid cal-dow-row">
        ${['Mon','Tue','Wed','Thu','Fri','Sat','Sun'].map(d => `<div class="cal-dow">${d}</div>`).join('')}
      </div>
      <div class="cal-grid cal-cells-row">${cells.join('')}</div>
    </div>`;
}

// ── Company Settings ────────────────────────────────────────────────
async function renderCompanySettings() {
  const content = document.getElementById('main-content');
  if (!content) return;
  content.innerHTML = _corpHeader('Company Settings', 'Organization-wide configuration') + '<div class="card" style="padding:2rem;text-align:center;color:var(--text-light)">Loading…</div>';
  let st;
  try { st = (await api('/api/advanced/company-settings')).settings || {}; }
  catch (e) { content.innerHTML += `<div class="card" style="padding:1rem;color:var(--error)">${esc(e.message)}</div>`; return; }
  let selfReg = { enabled: false, institutionCode: '' };
  try { selfReg = await api('/api/approvals/self-registration'); } catch (_) {}

  const TZS = ['Africa/Accra','Africa/Lagos','Africa/Nairobi','Africa/Johannesburg','Africa/Cairo','Europe/London','America/New_York','Asia/Dubai'];
  const holidayRow = (h, i) => `
    <div style="display:flex;gap:.5rem;margin-bottom:.4rem" data-holiday>
      <input value="${esc(h?.name || '')}" placeholder="Holiday name" style="flex:2;padding:.5rem .7rem;border:1px solid var(--border);border-radius:7px;background:var(--bg);color:var(--text)" data-h-name />
      <input type="date" value="${h?.date ? new Date(h.date).toISOString().slice(0, 10) : ''}" style="padding:.5rem .7rem;border:1px solid var(--border);border-radius:7px;background:var(--bg);color:var(--text)" data-h-date />
      <button class="btn btn-sm btn-ghost" onclick="this.parentElement.remove()">✕</button>
    </div>`;
  const locationRow = l => `
    <div style="display:flex;gap:.5rem;margin-bottom:.4rem" data-location>
      <input value="${esc(l?.name || '')}" placeholder="Office name" style="flex:1;padding:.5rem .7rem;border:1px solid var(--border);border-radius:7px;background:var(--bg);color:var(--text)" data-l-name />
      <input value="${esc(l?.address || '')}" placeholder="Address" style="flex:2;padding:.5rem .7rem;border:1px solid var(--border);border-radius:7px;background:var(--bg);color:var(--text)" data-l-addr />
      <button class="btn btn-sm btn-ghost" onclick="this.parentElement.remove()">✕</button>
    </div>`;
  window._csAddHoliday = () => document.getElementById('cs-holidays').insertAdjacentHTML('beforeend', holidayRow(null));
  window._csAddLocation = () => document.getElementById('cs-locations').insertAdjacentHTML('beforeend', locationRow(null));

  content.innerHTML = `
    ${_settingsHubTabs('company-settings')}
    ${_corpHeader('Company Settings', 'Organization-wide configuration')}
    <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(320px,1fr));gap:1rem;align-items:start">
      <div class="card" style="padding:1.2rem">
        <div style="font-weight:700;margin-bottom:.9rem">Organization</div>
        <label style="font-size:.75rem;color:var(--text-light);font-weight:600">Company name</label>
        <input id="cs-name" value="${esc(st.name || '')}" style="width:100%;padding:.6rem .8rem;border:1px solid var(--border);border-radius:8px;background:var(--bg);color:var(--text);margin:.3rem 0 .9rem" />
        <label style="font-size:.75rem;color:var(--text-light);font-weight:600">Time zone</label>
        <select id="cs-tz" style="width:100%;padding:.6rem .8rem;border:1px solid var(--border);border-radius:8px;background:var(--bg);color:var(--text);margin:.3rem 0 .9rem">
          ${TZS.map(z => `<option value="${z}" ${st.timezone === z ? 'selected' : ''}>${z}</option>`).join('')}
        </select>
        <div style="display:flex;gap:.5rem;flex-wrap:wrap;margin-top:.4rem">
          <button class="btn btn-sm btn-ghost" onclick="navigateTo('branding')">🎨 Branding & logo</button>
          ${currentUser.company?.mode === 'corporate' ? `<button class="btn btn-sm btn-ghost" onclick="navigateTo('corp-clock-settings')">🕐 Working hours</button>` : ''}
        </div>
      </div>
      <div class="card" style="padding:1.2rem">
        <div style="font-weight:700;margin-bottom:.9rem">Public holidays <span style="font-weight:400;font-size:.75rem;color:var(--text-muted)">shown on the calendar</span></div>
        <div id="cs-holidays">${(st.publicHolidays || []).map(holidayRow).join('')}</div>
        <button class="btn btn-sm btn-ghost" onclick="_csAddHoliday()">+ Add holiday</button>
      </div>
      <div class="card" style="padding:1.2rem">
        <div style="font-weight:700;margin-bottom:.9rem">Office locations</div>
        <div id="cs-locations">${(st.officeLocations || []).map(locationRow).join('')}</div>
        <button class="btn btn-sm btn-ghost" onclick="_csAddLocation()">+ Add location</button>
      </div>
      <div class="card" style="padding:1.2rem">
        <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:.4rem">
          <div style="font-weight:700">New user self-registration</div>
          <label style="position:relative;display:inline-block;width:40px;height:22px;flex-shrink:0">
            <input type="checkbox" id="cs-selfreg" ${selfReg.enabled ? 'checked' : ''} onchange="_csToggleSelfReg(this)" style="opacity:0;width:0;height:0">
            <span id="cs-selfreg-track" style="position:absolute;inset:0;background:${selfReg.enabled ? 'var(--primary)' : 'var(--border)'};border-radius:22px;transition:background .18s ease;cursor:pointer" onclick="document.getElementById('cs-selfreg').click()"></span>
            <span id="cs-selfreg-knob" style="position:absolute;top:2px;left:${selfReg.enabled ? '20px' : '2px'};width:18px;height:18px;background:#fff;border-radius:50%;transition:left .18s ease;box-shadow:0 1px 3px rgba(0,0,0,.3);pointer-events:none"></span>
          </label>
        </div>
        <div style="font-size:.78rem;color:var(--text-muted);margin-bottom:.7rem">
          When on, anyone with your institution code can create their own account at <code>/register.html</code> and will show up under Pending Approvals. When off, only admins/managers can add new users.
        </div>
        <div id="cs-selfreg-status" style="font-size:.78rem;font-weight:600;color:${selfReg.enabled ? 'var(--success, #16a34a)' : 'var(--text-light)'}">${selfReg.enabled ? 'Open — registration is currently accepting new users' : 'Closed — new users cannot self-register'}</div>
        ${selfReg.institutionCode ? `
        <div style="margin-top:.7rem;display:flex;align-items:center;gap:.5rem">
          <span style="font-size:.75rem;color:var(--text-light)">Institution code:</span>
          <code style="font-weight:700;letter-spacing:.5px">${esc(selfReg.institutionCode)}</code>
          <button class="btn btn-sm btn-ghost" onclick="navigator.clipboard.writeText('${esc(selfReg.institutionCode)}').then(()=>toastSuccess('Code copied'))">Copy</button>
        </div>` : ''}
      </div>
    </div>
    <div style="margin-top:1rem"><button class="btn btn-primary" onclick="_csSave()">Save settings</button></div>`;
}
window._csToggleSelfReg = async function(checkbox) {
  const enabled = checkbox.checked;
  const track = document.getElementById('cs-selfreg-track');
  const knob = document.getElementById('cs-selfreg-knob');
  const status = document.getElementById('cs-selfreg-status');
  checkbox.disabled = true;
  try {
    const res = await api('/api/approvals/self-registration', { method: 'PATCH', body: JSON.stringify({ enabled }) });
    checkbox.checked = !!res.enabled;
    if (track) track.style.background = res.enabled ? 'var(--primary)' : 'var(--border)';
    if (knob) knob.style.left = res.enabled ? '20px' : '2px';
    if (status) {
      status.textContent = res.enabled ? 'Open — registration is currently accepting new users' : 'Closed — new users cannot self-register';
      status.style.color = res.enabled ? 'var(--success, #16a34a)' : 'var(--text-light)';
    }
    toastSuccess(res.enabled ? 'Self-registration is now open' : 'Self-registration is now closed');
  } catch (e) {
    checkbox.checked = !enabled;
    toastError(e.message);
  } finally {
    checkbox.disabled = false;
  }
};
// Reads every row under containerSelector into a plain object per fieldMap
// key -> input selector, trimmed. Shared by the holiday/location sections
// below so the DOM-scraping shape lives in exactly one place.
function _csExtractRows(containerSelector, fieldMap) {
  return [...document.querySelectorAll(containerSelector)].map(row => {
    const obj = {};
    for (const key in fieldMap) obj[key] = row.querySelector(fieldMap[key])?.value?.trim() || '';
    return obj;
  });
}
// A row missing just one required field (e.g. a holiday name typed but no
// date picked) used to be silently dropped from the save payload — the
// request still "succeeded" so the admin saw a success toast, then the row
// was simply gone on reload. Blocks the save and names the bad row instead
// of quietly discarding it. Returns null (caller should abort) or the
// original rows array (still including intentionally-empty untouched rows,
// which are not "incomplete" — the caller filters those out separately).
function _csRejectIncompleteRow(rows, isIncomplete, describe) {
  const bad = rows.find(isIncomplete);
  if (!bad) return rows;
  toastError(describe(bad));
  return null;
}
window._csSave = async function() {
  const holidayRows = _csRejectIncompleteRow(
    _csExtractRows('[data-holiday]', { name: '[data-h-name]', date: '[data-h-date]' }),
    h => Boolean(h.name) !== Boolean(h.date),
    h => `Holiday "${h.name || '(untitled)'}" needs both a name and a date — fill both in, or remove the row.`
  );
  if (!holidayRows) return;
  const publicHolidays = holidayRows.filter(h => h.name && h.date);

  const locationRows = _csRejectIncompleteRow(
    _csExtractRows('[data-location]', { name: '[data-l-name]', address: '[data-l-addr]' }),
    l => !l.name && l.address,
    () => `An office location needs a name (address alone isn't enough) — fill it in, or remove the row.`
  );
  if (!locationRows) return;
  const officeLocations = locationRows.filter(l => l.name);

  try {
    await api('/api/advanced/company-settings', { method: 'PATCH', body: JSON.stringify({
      name: document.getElementById('cs-name')?.value,
      timezone: document.getElementById('cs-tz')?.value,
      publicHolidays, officeLocations,
    })});
    toastSuccess('Company settings saved');
  } catch (e) { toastError(e.message); }
};

// ── Roles & Permissions ─────────────────────────────────────────────
const CORP_MODULES = [
  ['users', 'Employees / Team'], ['departments', 'Departments'], ['corp-teams', 'Teams'],
  ['corp-attendance', 'Attendance'], ['sign-in-out', 'Clock In / Out'], ['shifts', 'Shifts'],
  ['leave-requests', 'Leave Management'], ['training', 'Training & Assessments'], ['performance', 'Performance Reviews'],
  ['branches', 'Branches'], ['assets', 'Assets'], ['timesheets', 'Timesheets'],
  ['approvals', 'Approvals'], ['tasks', 'Tasks'], ['messages', 'Messages'], ['meetings', 'Meetings'],
  ['corp-calendar', 'Calendar'], ['announcements', 'Announcements'], ['reports', 'Reports'],
  ['audit-logs', 'Audit Logs'], ['ai-reports', 'Dikly AI'],
];
const EMP_MODULES = [
  ['sign-in-out', 'Clock In / Out'], ['my-attendance', 'My Attendance'], ['my-shift', 'My Shift'],
  ['my-leaves', 'Leave'], ['tasks', 'My Tasks'], ['emp-notifications', 'Notifications'],
  ['announcements', 'Announcements'], ['messages', 'Messages'], ['meetings', 'Meetings'],
  ['corp-calendar', 'Calendar'], ['my-performance', 'My Performance'], ['reports', 'Reports'],
];
async function renderRolesPermissions() {
  const content = document.getElementById('main-content');
  if (!content) return;
  content.innerHTML = _corpHeader('Roles & Permissions', 'Control which modules each role can access') + '<div class="card" style="padding:2rem;text-align:center;color:var(--text-light)">Loading…</div>';
  let mp = null;
  try { mp = (await api('/api/advanced/company-settings')).settings?.modulePermissions || null; }
  catch (e) { /* default = all allowed */ }

  const isChecked = (role, mod) => !mp || !Array.isArray(mp[role]) || mp[role].includes(mod);
  const matrix = (role, mods) => `
    <div class="card" style="padding:1.2rem">
      <div style="font-weight:700;margin-bottom:.2rem;text-transform:capitalize">${role === 'manager' ? 'Manager' : 'Employee'}</div>
      <div style="font-size:.74rem;color:var(--text-muted);margin-bottom:.9rem">Untick a module to hide it from every ${role} in your company.</div>
      <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(190px,1fr));gap:.35rem">
        ${mods.map(([id, label]) => `
          <label style="display:flex;align-items:center;gap:.45rem;font-size:.8rem;padding:.3rem .4rem;border-radius:6px;cursor:pointer">
            <input type="checkbox" data-perm-role="${role}" data-perm-mod="${id}" ${isChecked(role, id) ? 'checked' : ''} />
            ${label}
          </label>`).join('')}
      </div>
    </div>`;

  content.innerHTML = `
    ${_corpHeader('Roles & Permissions', 'Control which modules each role can access')}
    <div class="card" style="padding:.9rem 1.2rem;margin-bottom:1rem;background:var(--primary-ultra-light, var(--bg));border-left:3px solid var(--primary)">
      <div style="font-size:.82rem;color:var(--text-light)"><strong>Admins always see everything.</strong> Changes apply to managers and employees the next time they sign in (or refresh).</div>
    </div>
    <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(340px,1fr));gap:1rem">
      ${matrix('manager', CORP_MODULES)}
      ${matrix('employee', EMP_MODULES)}
    </div>
    <div style="margin-top:1rem;display:flex;gap:.6rem">
      <button class="btn btn-primary" onclick="_permsSave()">Save permissions</button>
      <button class="btn btn-ghost" onclick="_permsReset()">Reset to all modules</button>
    </div>`;
}
window._permsSave = async function() {
  const modulePermissions = { manager: [], employee: [] };
  document.querySelectorAll('[data-perm-role]').forEach(cb => {
    if (cb.checked) modulePermissions[cb.dataset.permRole].push(cb.dataset.permMod);
  });
  try {
    const d = await api('/api/advanced/module-permissions', { method: 'PATCH', body: JSON.stringify({ modulePermissions }) });
    if (currentUser.company) currentUser.company.modulePermissions = d.modulePermissions;
    toastSuccess('Permissions saved — applies at next sign-in');
  } catch (e) { toastError(e.message); }
};
window._permsReset = async function() {
  try {
    await api('/api/advanced/module-permissions', { method: 'PATCH', body: JSON.stringify({ modulePermissions: null }) });
    if (currentUser.company) currentUser.company.modulePermissions = null;
    toastSuccess('Reset — all roles see all modules');
    renderRolesPermissions();
  } catch (e) { toastError(e.message); }
};

// ═══════════════════════════════════════════════════════════════════
//  EXECUTIVE DASHBOARD (corporate)
// ═══════════════════════════════════════════════════════════════════

// ── Shared chart tooltip ──
function _exvTip() {
  let t = document.getElementById('exv-tip');
  if (!t) {
    t = document.createElement('div');
    t.id = 'exv-tip';
    t.style.cssText = 'position:fixed;z-index:9000;pointer-events:none;display:none;background:var(--text);color:var(--card);padding:.4rem .6rem;border-radius:7px;font-size:.75rem;font-weight:600;box-shadow:0 4px 14px rgba(0,0,0,.25);white-space:nowrap';
    document.body.appendChild(t);
  }
  return t;
}
window._exvShowTip = function(ev, html) {
  const t = _exvTip();
  t.innerHTML = html;
  t.style.display = 'block';
  t.style.left = Math.min(ev.clientX + 12, window.innerWidth - t.offsetWidth - 8) + 'px';
  t.style.top  = (ev.clientY - t.offsetHeight - 10) + 'px';
};
window._exvHideTip = function() { const t = document.getElementById('exv-tip'); if (t) t.style.display = 'none'; };

// Table-view twin — every chart ships its data as an accessible table
function _exvTable(rows, cols) {
  return `<details style="margin-top:.5rem"><summary style="font-size:.72rem;color:var(--text-muted);cursor:pointer">View data</summary>
    <table style="width:100%;font-size:.76rem;margin-top:.4rem;border-collapse:collapse">
      <thead><tr>${cols.map(c => `<th style="text-align:left;padding:.25rem .4rem;color:var(--text-light);font-weight:600;border-bottom:1px solid var(--border)">${c}</th>`).join('')}</tr></thead>
      <tbody>${rows.map(r => `<tr>${r.map((v, i) => `<td style="padding:.25rem .4rem;border-bottom:1px solid var(--border);${i > 0 ? 'font-variant-numeric:tabular-nums' : ''}">${v}</td>`).join('')}</tr>`).join('')}</tbody>
    </table></details>`;
}

// ── Line chart: single series, 2px line, 10% area wash, end label ──
function _exvLineChart(points, { unit = '%', yMax = 100 } = {}) {
  if (!points.length) return '<div style="padding:1.6rem;text-align:center;color:var(--text-muted);font-size:.82rem">No data yet</div>';
  const W = 560, H = 170, PL = 34, PR = 44, PT = 12, PB = 26;
  const iw = W - PL - PR, ih = H - PT - PB;
  const x = i => PL + (points.length === 1 ? iw / 2 : (i / (points.length - 1)) * iw);
  const y = v => PT + ih - (Math.min(v, yMax) / yMax) * ih;
  const path = points.map((p, i) => `${i ? 'L' : 'M'}${x(i).toFixed(1)},${y(p.rate).toFixed(1)}`).join(' ');
  const area = `${path} L${x(points.length - 1).toFixed(1)},${PT + ih} L${x(0).toFixed(1)},${PT + ih} Z`;
  const last = points[points.length - 1];
  const gridVals = [0, 50, 100];
  const dayLbl = d => { const dt = new Date(d + 'T00:00:00'); return dt.toLocaleDateString(undefined, { day: 'numeric', month: 'short' }); };
  return `
  <svg viewBox="0 0 ${W} ${H}" style="width:100%;height:auto;display:block" role="img" aria-label="Attendance trend, last 14 days">
    ${gridVals.map(v => `<line x1="${PL}" y1="${y(v)}" x2="${W - PR}" y2="${y(v)}" stroke="var(--border)" stroke-width="1"/>
      <text x="${PL - 6}" y="${y(v) + 3}" text-anchor="end" font-size="9" fill="var(--text-muted)" style="font-variant-numeric:tabular-nums">${v}</text>`).join('')}
    <path d="${area}" fill="var(--primary, #4f6ef7)" opacity="0.10"/>
    <path d="${path}" fill="none" stroke="var(--primary, #4f6ef7)" stroke-width="2" stroke-linejoin="round" stroke-linecap="round"/>
    ${points.map((p, i) => `
      <circle cx="${x(i)}" cy="${y(p.rate)}" r="${i === points.length - 1 ? 4 : 3}" fill="var(--primary, #4f6ef7)" stroke="var(--card)" stroke-width="2"
        style="cursor:default" onmousemove="_exvShowTip(event,'${dayLbl(p.date)}: <b>${p.rate}${unit}</b>')" onmouseleave="_exvHideTip()"/>`).join('')}
    <text x="${x(points.length - 1) + 8}" y="${y(last.rate) + 4}" font-size="11" font-weight="700" fill="var(--text)">${last.rate}${unit}</text>
    ${points.map((p, i) => i % 3 === 0 || i === points.length - 1
      ? `<text x="${x(i)}" y="${H - 8}" text-anchor="middle" font-size="9" fill="var(--text-muted)">${dayLbl(p.date)}</text>` : '').join('')}
  </svg>
  ${_exvTable(points.map(p => [dayLbl(p.date), p.rate + unit]), ['Day', 'Attendance'])}`;
}

// ── Horizontal bars: single hue, ≤16px thick, rounded data-end, value at tip ──
function _exvHBars(items, { unit = '%', max = 100 } = {}) {
  if (!items.length) return '<div style="padding:1.6rem;text-align:center;color:var(--text-muted);font-size:.82rem">No data yet</div>';
  return `<div style="display:flex;flex-direction:column;gap:.55rem">
    ${items.map(it => {
      const w = Math.max(2, Math.round((it.value / max) * 100));
      return `<div class="exv-bar-row"
        onmousemove="_exvShowTip(event,'${esc(it.name)}: <b>${it.value}${unit}</b>')" onmouseleave="_exvHideTip()">
        <div class="exv-bar-label" style="overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${esc(it.name)}">${esc(it.name)}</div>
        <div style="height:14px;position:relative">
          <div style="position:absolute;inset:0;background:var(--border);opacity:.35;border-radius:0 4px 4px 0"></div>
          <div style="position:absolute;top:0;bottom:0;left:0;width:${w}%;background:var(--primary, #4f6ef7);border-radius:0 4px 4px 0"></div>
        </div>
        <div class="exv-bar-value">${it.value}${unit}</div>
      </div>`;
    }).join('')}
  </div>
  ${_exvTable(items.map(it => [esc(it.name), it.value + unit]), ['Name', 'Rate'])}`;
}

async function renderExecutiveDashboard() {
  const content = document.getElementById('main-content');
  if (!content) return;
  content.innerHTML = '<div class="card" style="padding:2.5rem;text-align:center;color:var(--text-light)">Loading executive dashboard…</div>';

  let d;
  try {
    d = await api('/api/executive/dashboard');
  } catch (e) {
    content.innerHTML = `<div class="card" style="padding:2rem;text-align:center"><div style="color:var(--error);font-weight:600">Could not load the executive dashboard</div><div style="font-size:.85rem;color:var(--text-light);margin-top:.4rem">${esc(e.message)}</div></div>`;
    return;
  }

  const k = d.kpis;
  const scoreColor = k.healthScore >= 75 ? '#0ca30c' : k.healthScore >= 50 ? '#fab219' : '#d03b3b';
  // Status roles are reserved and always paired with an icon + label
  const alertMeta = {
    good:     { icon: '✓', color: '#0ca30c', label: 'Good' },
    warning:  { icon: '⚠', color: '#b45309', label: 'Warning' },
    serious:  { icon: '⚠', color: '#c2410c', label: 'Attention' },
    critical: { icon: '⛔', color: '#d03b3b', label: 'Critical' },
  };
  const tile = (label, value, sub = '') => `
    <div class="card exv-tile">
      <div class="exv-tile-label">${label}</div>
      <div class="exv-tile-value">${value}</div>
      ${sub ? `<div class="exv-tile-sub">${sub}</div>` : ''}
    </div>`;

  const leaveTotal = Math.max(1, d.leaveStats.approved + d.leaveStats.pending + d.leaveStats.rejected);
  const leaveRow = (label, count, color, icon) => `
    <div class="exv-bar-row" style="margin-bottom:.55rem">
      <div class="exv-bar-label"><span style="color:${color};font-weight:800">${icon}</span> ${label}</div>
      <div style="height:12px;position:relative">
        <div style="position:absolute;inset:0;background:var(--border);opacity:.35;border-radius:0 4px 4px 0"></div>
        <div style="position:absolute;top:0;bottom:0;left:0;width:${Math.round((count / leaveTotal) * 100)}%;background:${color};border-radius:0 4px 4px 0"></div>
      </div>
      <div class="exv-bar-value">${count}</div>
    </div>`;

  const chartCard = (title, sub, body) => `
    <div class="card" style="padding:1.1rem 1.2rem">
      <div style="font-weight:700;font-size:.92rem;color:var(--text)">${title}</div>
      <div style="font-size:.74rem;color:var(--text-muted);margin-bottom:.8rem">${sub}</div>
      ${body}
    </div>`;

  content.innerHTML = `
    <div class="page-header" style="margin-bottom:1.2rem">
      <div>
        <h1 style="margin:0 0 .25rem">Executive Dashboard</h1>
        <p style="margin:0;color:var(--text-light);font-size:.9rem">Company-wide view for ${new Date(d.generatedAt).toLocaleDateString(undefined, { weekday: 'long', day: 'numeric', month: 'long' })}</p>
      </div>
      <button class="btn btn-sm btn-ghost" onclick="renderExecutiveDashboard()">↻ Refresh</button>
    </div>

    <div class="exv-hero-grid">
      <div class="card exv-health">
        <div class="exv-tile-label">Company health score</div>
        <div class="exv-score">${k.healthScore}<span> / 100</span></div>
        <div style="height:8px;border-radius:4px;background:${scoreColor}2b;overflow:hidden">
          <div style="height:100%;width:${k.healthScore}%;background:${scoreColor};border-radius:4px"></div>
        </div>
        <div class="exv-tile-sub" style="margin-top:.5rem">Attendance · punctuality · approvals backlog</div>
      </div>
      <div class="exv-kpis">
        ${tile('Present today', k.presentToday, `${k.attendanceRateToday}% of workforce`)}
        ${tile('Absent today', k.absentToday)}
        ${tile('Late arrivals', k.lateToday)}
        ${tile('Active employees', k.activeEmployees)}
        ${tile('Active branches', k.activeBranches)}
        ${tile('Pending approvals', k.pendingApprovals, 'leave · timesheets')}
        ${tile("Today's meetings", k.meetingsToday)}
        ${tile('Departments', k.totalDepartments)}
      </div>
    </div>

    <div class="card" style="padding:1.1rem 1.2rem;margin-bottom:1rem">
      <div style="font-weight:700;font-size:.92rem;color:var(--text);margin-bottom:.7rem">Executive alerts</div>
      <div style="display:flex;flex-direction:column;gap:.45rem">
        ${d.alerts.map(a => {
          const m = alertMeta[a.level] || alertMeta.warning;
          return `<div style="display:flex;align-items:center;gap:.6rem;padding:.55rem .75rem;border-radius:9px;background:${m.color}14;border-left:3px solid ${m.color}">
            <span style="color:${m.color};font-weight:800">${m.icon}</span>
            <span style="font-size:.83rem;color:var(--text)"><strong style="color:${m.color}">${m.label}:</strong> ${esc(a.text)}</span>
          </div>`;
        }).join('')}
      </div>
    </div>

    <div class="exv-charts">
      ${chartCard('Attendance trend', 'Daily attendance rate, last 14 days', _exvLineChart(d.attendanceTrend))}
      ${chartCard('Department performance', '30-day attendance rate by department', _exvHBars(d.departmentPerformance.map(x => ({ name: x.name, value: x.rate }))))}
      ${chartCard('Branch performance', '30-day attendance rate by branch', _exvHBars(d.branchPerformance.map(x => ({ name: x.name, value: x.rate }))))}
      ${chartCard('Leave statistics', 'Requests in the last 90 days', `
        ${leaveRow('Approved', d.leaveStats.approved, '#0ca30c', '✓')}
        ${leaveRow('Pending',  d.leaveStats.pending,  '#b45309', '⏳')}
        ${leaveRow('Rejected', d.leaveStats.rejected, '#d03b3b', '✗')}
        ${_exvTable([['Approved', d.leaveStats.approved], ['Pending', d.leaveStats.pending], ['Rejected', d.leaveStats.rejected]], ['Status', 'Requests'])}`)}
    </div>`;
}

// ── HR Portal — dashboard for HR-flagged employees/managers ────────────────
async function renderHRPortal() {
  const content = document.getElementById('main-content');
  if (!content) return;
  content.innerHTML = '<div class="card" style="padding:2.5rem;text-align:center;color:var(--text-light)">Loading HR portal…</div>';

  const hr = currentUser.hrAssignment;
  const scopeLabel = hr?.scope === 'company' ? 'Company-wide' : (hr?.department?.name ? `${hr.department.name} department` : 'Department');

  const [usersRes, leavesRes, todayRes, trainingRes] = await Promise.all([
    api('/api/users').catch(() => ({ users: [] })),
    api('/api/leaves/pending').catch(() => ({ leaves: [] })),
    api('/api/corporate-attendance/today').catch(() => ({ summary: null, records: [] })),
    api('/api/training/overview').catch(() => ({ stats: null })),
  ]);

  const headcount = (usersRes.users || []).filter(u => ['employee', 'manager'].includes(u.role)).length;
  const pendingLeaves = (leavesRes.leaves || []).length;
  const todayRecords = todayRes.records || [];
  const todayRate = headcount > 0 && todayRes.summary
    ? Math.round(((todayRes.summary.present || 0) + (todayRes.summary.late || 0)) / headcount * 100)
    : null;
  const overdueTraining = trainingRes.stats?.overdue ?? 0;

  const tile = (label, value, sub, view) => `
    <div class="card exv-tile"${view ? ` style="cursor:pointer" onclick="navigateTo('${view}')"` : ''}>
      <div class="exv-tile-label">${label}</div>
      <div class="exv-tile-value">${value}</div>
      ${sub ? `<div class="exv-tile-sub">${sub}</div>` : ''}
    </div>`;

  const sparkle = '<svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M12 3l1.9 5.7L19.6 10l-5.7 1.9L12 17.6l-1.9-5.7L4.4 10l5.7-1.9z"/><path d="M19 3l.7 2.1L21.8 6l-2.1.7L19 8.8l-.7-2.1L16.2 6l2.1-.9z"/></svg>';

  content.innerHTML = `
    <div class="page-header" style="margin-bottom:1.2rem">
      <div>
        <h1 style="margin:0 0 .25rem">HR Portal</h1>
        <p style="margin:0;color:var(--text-light);font-size:.9rem">${esc(scopeLabel)} people-ops view — leave, attendance, performance and training.</p>
      </div>
      <button class="btn btn-sm btn-ghost" onclick="renderHRPortal()">↻ Refresh</button>
    </div>

    <div class="adx-ai-band" onclick="navigateTo('ai-reports')" role="button" tabindex="0">
      <div class="adx-ai-icon">${sparkle}</div>
      <div class="adx-ai-body">
        <div class="adx-ai-eyebrow">Dikly AI · HR Insights</div>
        <div class="adx-ai-headline">Ask about attendance patterns, leave trends, or who needs a performance review.</div>
      </div>
      <div class="adx-ai-cta">Ask Dikly AI <span style="font-size:15px;line-height:1">→</span></div>
    </div>

    <div class="exv-kpis" style="margin-top:1rem">
      ${tile('Headcount in scope', headcount, scopeLabel, 'users')}
      ${tile('Pending leave requests', pendingLeaves, pendingLeaves ? 'Needs review' : 'All caught up', 'leave-requests')}
      ${tile("Today's attendance rate", todayRate != null ? todayRate + '%' : '—', `${todayRecords.length} clocked in today`, 'corp-attendance')}
      ${tile('Training overdue', overdueTraining, overdueTraining ? 'Follow up needed' : 'On track')}
    </div>

    <div class="card" style="padding:1.1rem 1.2rem;margin-top:1rem">
      <div style="font-weight:700;font-size:.92rem;color:var(--text);margin-bottom:.7rem">Quick actions</div>
      <div style="display:flex;gap:.6rem;flex-wrap:wrap">
        <button class="btn btn-sm" onclick="navigateTo('leave-requests')">Review leave requests</button>
        <button class="btn btn-sm" onclick="navigateTo('corp-attendance')">View attendance</button>
        <button class="btn btn-sm" onclick="navigateTo('performance')">Performance reviews</button>
        <button class="btn btn-sm" onclick="navigateTo('users')">Employee directory</button>
      </div>
    </div>`;
}

