// Client-side transcript for the Dikly AI chat. Each entry is
// { role:'user'|'assistant', ... }. The backend (POST /api/ai-reports/
// generate) is stateless per call, so the transcript lives here and is
// rebuilt into the DOM on every renderAIReports() (e.g. returning to the
// page keeps the current session's conversation until a full reload).
let _aiChat = [];

async function renderAIReports() {
  const content = document.getElementById('main-content');
  if (!content) return;

  const role = currentUser?.role || '';
  const instMode = currentUser?.company?.mode === 'corporate' ? 'corporate' : 'academic';
  const available = Object.entries(AI_REPORT_DEFS).filter(([, d]) =>
    d.roles.includes(role) && (!d.modes || d.modes.includes(instMode)));
  const canAsk = AI_REPORT_DEFS.custom_query.roles.includes(role);
  const hasSpeech = !!(window.SpeechRecognition || window.webkitSpeechRecognition);

  content.style.padding = '0';
  content.innerHTML = `
    <style>
      .aic-wrap { display:flex; flex-direction:column; height:calc(100vh - 58px); max-height:calc(100vh - 58px); background:var(--bg); }
      [data-theme="dark"] .aic-wrap { background:#0b1020; }
      .aic-head {
        display:flex; align-items:center; gap:.6rem; padding:.85rem 1.1rem;
        border-bottom:1px solid var(--border); flex-shrink:0; background:var(--bg);
      }
      [data-theme="dark"] .aic-head { background:#0d1224; }
      .aic-head-orb {
        width:26px; height:26px; border-radius:50%; flex-shrink:0;
        background: radial-gradient(circle at 62% 38%, #fde68a 0%, #f9a8d4 32%, #a78bfa 68%, #7c3aed 100%);
        box-shadow:0 0 12px 2px rgba(167,139,250,.5);
      }
      .aic-head-title { font-weight:800; font-size:1rem; color:var(--text); }
      .aic-head-new {
        margin-left:auto; border:1px solid var(--border); background:transparent; color:var(--text-light);
        border-radius:8px; padding:.4rem .7rem; font-size:.78rem; font-weight:600; cursor:pointer; font-family:inherit;
        display:inline-flex; align-items:center; gap:.35rem; transition:border-color .12s, color .12s;
      }
      .aic-head-new:hover { border-color:var(--accent); color:var(--accent); }

      .aic-scroll { flex:1; overflow-y:auto; padding:1.2rem 0; scroll-behavior:smooth; }
      .aic-thread { max-width:760px; margin:0 auto; padding:0 1rem; display:flex; flex-direction:column; gap:1.3rem; }

      .aic-row { display:flex; gap:.75rem; align-items:flex-start; }
      .aic-row.user { justify-content:flex-end; }
      .aic-avatar {
        width:30px; height:30px; border-radius:50%; flex-shrink:0; margin-top:2px;
        background: radial-gradient(circle at 62% 38%, #fde68a 0%, #f9a8d4 32%, #a78bfa 68%, #7c3aed 100%);
        box-shadow:0 0 10px 1px rgba(167,139,250,.4);
      }
      .aic-bubble-user {
        background:linear-gradient(135deg, var(--accent, #4f6ef7), var(--accent2, #7c3aed)); color:#fff;
        padding:.7rem 1rem; border-radius:18px 18px 4px 18px; max-width:80%;
        font-size:.92rem; line-height:1.55; white-space:pre-wrap; word-break:break-word;
      }
      .aic-msg-assistant {
        flex:1; min-width:0; color:var(--text); font-size:.92rem; line-height:1.7;
        padding-top:.15rem; word-break:break-word;
      }
      .aic-msg-assistant h2 { font-size:1rem; font-weight:700; margin:1.1rem 0 .45rem; }
      .aic-msg-assistant h3 { font-size:.9rem; font-weight:700; margin:.9rem 0 .35rem; }
      .aic-msg-assistant ul { padding-left:1.25rem; margin:.5rem 0; }
      .aic-msg-assistant li { margin:.25rem 0; }
      .aic-msg-assistant p  { margin:.5rem 0; }
      .aic-msg-tools { display:flex; gap:.4rem; margin-top:.6rem; }
      .aic-msg-tool {
        border:1px solid var(--border); background:transparent; color:var(--text-light);
        border-radius:7px; padding:.28rem .6rem; font-size:.72rem; font-weight:600; cursor:pointer; font-family:inherit;
        display:inline-flex; align-items:center; gap:.3rem; transition:border-color .12s, color .12s;
      }
      .aic-msg-tool:hover { border-color:var(--accent); color:var(--accent); }

      .aic-typing { display:flex; gap:5px; padding:.5rem 0; }
      .aic-typing span {
        width:8px; height:8px; border-radius:50%; background:var(--text-muted);
        animation:aicBlink 1.3s infinite ease-in-out both;
      }
      .aic-typing span:nth-child(2) { animation-delay:.18s; }
      .aic-typing span:nth-child(3) { animation-delay:.36s; }
      @keyframes aicBlink { 0%,80%,100% { opacity:.25; transform:scale(.85); } 40% { opacity:1; transform:scale(1); } }

      /* Empty state */
      .aic-empty { max-width:720px; margin:auto; padding:2rem 1rem; text-align:center; }
      .aic-empty-orb {
        width:60px; height:60px; border-radius:50%; margin:0 auto 1.1rem;
        background: radial-gradient(circle at 62% 38%, #fde68a 0%, #f9a8d4 32%, #a78bfa 68%, #7c3aed 100%);
        box-shadow:0 0 30px 8px rgba(167,139,250,.4);
        animation: aiOrbFloat 5s ease-in-out infinite;
      }
      @keyframes aiOrbFloat { 0%,100% { transform:translateY(0) scale(1); } 50% { transform:translateY(-6px) scale(1.04); } }
      .aic-empty h1 { margin:0; font-size:clamp(1.4rem,4vw,2rem); font-weight:800; letter-spacing:-.5px; color:var(--text); }
      .aic-empty p { margin:.5rem 0 0; font-size:.92rem; color:var(--text-light); }
      .aic-chips { display:flex; flex-wrap:wrap; gap:.5rem; justify-content:center; margin-top:1.6rem; }
      .aic-chip {
        display:inline-flex; align-items:center; gap:.42rem; padding:.55rem .9rem; border-radius:999px;
        background:var(--bg-card, var(--bg-secondary, #fff)); border:1px solid var(--border); cursor:pointer;
        font-size:.78rem; font-weight:600; color:var(--text); font-family:inherit;
        transition:transform .12s, box-shadow .12s, border-color .12s;
      }
      .aic-chip:hover { transform:translateY(-1px); border-color:var(--accent); box-shadow:0 4px 14px rgba(79,110,247,.15); }

      /* Composer pinned at the bottom */
      .aic-composer-wrap { flex-shrink:0; padding:.7rem 1rem 1rem; border-top:1px solid var(--border); background:var(--bg); }
      [data-theme="dark"] .aic-composer-wrap { background:#0d1224; }
      .aic-composer {
        max-width:760px; margin:0 auto; display:flex; align-items:flex-end; gap:.4rem;
        background:var(--bg-card, var(--bg-secondary, #fff)); border:1.5px solid var(--border);
        border-radius:24px; padding:.4rem .4rem .4rem 1rem; transition:border-color .15s, box-shadow .15s;
      }
      .aic-composer:focus-within { border-color:var(--accent); box-shadow:0 4px 18px rgba(79,110,247,.16); }
      .aic-composer textarea {
        flex:1; border:none; outline:none; background:transparent; color:var(--text); resize:none;
        font-size:.95rem; font-family:inherit; line-height:1.5; max-height:140px; padding:.5rem 0;
      }
      .aic-tool {
        width:36px; height:36px; border:none; border-radius:50%; background:transparent; cursor:pointer;
        display:flex; align-items:center; justify-content:center; color:var(--text-light); flex-shrink:0; transition:background .12s;
      }
      .aic-tool:hover { background:var(--bg-secondary); }
      .aic-send {
        width:38px; height:38px; border:none; border-radius:50%; cursor:pointer; flex-shrink:0;
        background:linear-gradient(135deg, var(--accent, #4f6ef7), var(--accent2, #7c3aed));
        display:flex; align-items:center; justify-content:center; color:#fff;
        box-shadow:0 4px 14px rgba(124,58,237,.35); transition:transform .12s, opacity .12s;
      }
      .aic-send:hover { transform:scale(1.06); }
      .aic-send:disabled { opacity:.45; cursor:not-allowed; transform:none; }
      .aic-composer-hint { max-width:760px; margin:.5rem auto 0; text-align:center; font-size:.7rem; color:var(--text-muted); }
    </style>

    <div class="aic-wrap">
      <div class="aic-head">
        <div class="aic-head-orb"></div>
        <div class="aic-head-title">Dikly AI</div>
        <button class="aic-head-new" onclick="_aiChatReset()" title="Start a new chat">
          ${svgIcon('<line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/>', 13)} New chat
        </button>
      </div>

      <div class="aic-scroll" id="aic-scroll">
        <div class="aic-thread" id="aic-thread"></div>
      </div>

      ${canAsk ? `
      <div class="aic-composer-wrap">
        <div class="aic-composer">
          <textarea id="aic-input" rows="1" placeholder="Ask Dikly AI anything about your institution…"
            oninput="_aiChatAutogrow(this)" onkeydown="_aiChatKeydown(event)"></textarea>
          ${hasSpeech ? `<button class="aic-tool" id="aic-mic" title="Speak your question" onclick="_aiChatVoice()">
            ${svgIcon('<path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" y1="19" x2="12" y2="23"/><line x1="8" y1="23" x2="16" y2="23"/>', 16)}
          </button>` : ''}
          <button class="aic-send" id="aic-send" title="Send" onclick="_aiChatSubmit()">
            ${svgIcon('<line x1="12" y1="19" x2="12" y2="5"/><polyline points="5 12 12 5 19 12"/>', 17, '#fff')}
          </button>
        </div>
        <div class="aic-composer-hint">Dikly AI can make mistakes. Verify important figures against your dashboards.</div>
      </div>` : `
      <div class="aic-composer-wrap"><div class="aic-composer-hint">Free-form questions aren't available for your role — use the quick actions above.</div></div>`}
    </div>`;

  // Store quick actions for the empty state + expose to chip handlers.
  window._aiQuickActions = available.filter(([t]) => t !== 'custom_query');
  _aiChatRepaint();
}

// Rebuild the thread DOM from the _aiChat transcript (or the empty state).
function _aiChatRepaint() {
  const thread = document.getElementById('aic-thread');
  if (!thread) return;

  if (!_aiChat.length) {
    const firstName = (currentUser?.name || 'there').trim().split(/\s+/)[0];
    const hour = new Date().getHours();
    const greeting = hour < 12 ? 'Good morning' : hour < 17 ? 'Good afternoon' : 'Good evening';
    const chips = (window._aiQuickActions || []).map(([type, d]) => `
      <button class="aic-chip" title="${esc(d.desc)}" onclick="aiReportOpen('${type}')">
        ${svgIcon(d.icon, 13, d.color)} ${esc(d.label)}
      </button>`).join('');
    thread.innerHTML = `
      <div class="aic-empty">
        <div class="aic-empty-orb"></div>
        <h1>${greeting}, ${esc(firstName)}</h1>
        <p>Ask me anything about your institution's data — attendance, performance, at-risk students, and more.</p>
        ${chips ? `<div class="aic-chips">${chips}</div>` : ''}
      </div>`;
    return;
  }

  thread.innerHTML = _aiChat.map((m, i) => {
    if (m.role === 'user') {
      return `<div class="aic-row user"><div class="aic-bubble-user">${esc(m.text)}</div></div>`;
    }
    if (m.role === 'typing') {
      return `<div class="aic-row"><div class="aic-avatar"></div><div class="aic-msg-assistant"><div class="aic-typing"><span></span><span></span><span></span></div></div></div>`;
    }
    // assistant
    const tools = m.reportId || m.regen
      ? `<div class="aic-msg-tools">
           ${m.regen ? `<button class="aic-msg-tool" onclick='_aiChatRegen(${JSON.stringify(m.regen)})'>${svgIcon('<polyline points="23 4 23 10 17 10"/><path d="M20.49 15a9 9 0 1 1-.57-4.13"/>', 12)} Regenerate</button>` : ''}
           <button class="aic-msg-tool" onclick="_aiChatCopy(${i})">${svgIcon('<rect x="9" y="9" width="13" height="13" rx="2" ry="2"/><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"/>', 12)} Copy</button>
         </div>`
      : '';
    return `<div class="aic-row"><div class="aic-avatar"></div><div class="aic-msg-assistant">${m.html || esc(m.text || '')}${tools}</div></div>`;
  }).join('');

  _aiChatScrollBottom();
}

function _aiChatScrollBottom() {
  const scroll = document.getElementById('aic-scroll');
  if (scroll) scroll.scrollTop = scroll.scrollHeight;
}

window._aiChatReset = function() {
  _aiChat = [];
  _aiChatRepaint();
  document.getElementById('aic-input')?.focus();
};

window._aiChatAutogrow = function(el) {
  el.style.height = 'auto';
  el.style.height = Math.min(el.scrollHeight, 140) + 'px';
};

window._aiChatKeydown = function(e) {
  // Enter sends, Shift+Enter inserts a newline (ChatGPT behavior).
  if (e.key === 'Enter' && !e.shiftKey) {
    e.preventDefault();
    _aiChatSubmit();
  }
};

// Send the composer text as a custom_query and stream the answer into the thread.
window._aiChatSubmit = function() {
  const input = document.getElementById('aic-input');
  const q = (input?.value || '').trim();
  if (!q) { input?.focus(); return; }
  input.value = '';
  _aiChatAutogrow(input);
  _aiChat.push({ role: 'user', text: q });
  _aiChatRepaint();
  _aiChatAsk('custom_query', { question: q });
};

// Shared path for both free-text questions and quick-action reports: show a
// typing indicator, call the backend, then replace it with the answer.
async function _aiChatAsk(type, parameters = {}, forceRefresh = false) {
  _aiChat.push({ role: 'typing' });
  _aiChatRepaint();
  const send = document.getElementById('aic-send');
  if (send) send.disabled = true;
  try {
    const d = await api('/api/ai-reports/generate', {
      method: 'POST',
      body: JSON.stringify({ type, parameters, forceRefresh }),
    });
    const report = d.report || {};
    _aiChat.pop(); // remove typing
    _aiChat.push({
      role: 'assistant',
      html: _aiMarkdownToHtml(report.report || report.summary || 'No answer was returned.'),
      regen: { type, parameters },
    });
  } catch (e) {
    _aiChat.pop();
    _aiChat.push({ role: 'assistant', html: `<p style="color:var(--error)">Sorry — I couldn't answer that. ${esc(e.message)}</p>` });
  } finally {
    if (send) send.disabled = false;
    _aiChatRepaint();
    document.getElementById('aic-input')?.focus();
  }
}

window._aiChatRegen = function(regen) {
  if (!regen?.type) return;
  _aiChatAsk(regen.type, regen.parameters || {}, true);
};

window._aiChatCopy = function(i) {
  const m = _aiChat[i];
  if (!m) return;
  const tmp = document.createElement('div');
  tmp.innerHTML = m.html || '';
  navigator.clipboard?.writeText(tmp.innerText.trim()).then(() => toastSuccess('Copied to clipboard'));
};

// Voice input for the composer (Chrome/Edge SpeechRecognition)
window._aiChatVoice = function() {
  const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
  if (!SR) return;
  const btn = document.getElementById('aic-mic');
  const rec = new SR();
  rec.lang = 'en-US';
  rec.interimResults = false;
  if (btn) btn.style.color = 'var(--error)';
  rec.onresult = (e) => {
    const input = document.getElementById('aic-input');
    if (input) { input.value = e.results[0][0].transcript; input.focus(); _aiChatAutogrow(input); }
  };
  rec.onend = () => { if (btn) btn.style.color = ''; };
  rec.onerror = () => { if (btn) btn.style.color = ''; };
  rec.start();
};

window.aiReportOpen = async function(type) {
  const def = AI_REPORT_DEFS[type];
  if (!def) return;

  // Student lookup
  if (type === 'student_lookup') {
    _aiShowStudentLookupModal();
    return;
  }

  // If custom_query, show the question input modal
  if (type === 'custom_query') {
    _aiShowCustomQueryModal();
    return;
  }

  // For course-specific reports, pick a course first
  if (['class_health', 'exam_readiness', 'at_risk_students'].includes(type)) {
    await _aiShowCoursePickerModal(type);
    return;
  }

  // For department_overview, pick a department
  if (type === 'department_overview') {
    await _aiShowDeptPickerModal();
    return;
  }

  // Everything else: just generate directly
  aiReportGenerate(type);
};

// A quick-action report becomes a chat turn: a user "action" bubble naming
// the report, then the assistant answer via the shared _aiChatAsk path.
window.aiReportGenerate = async function(type, parameters = {}, forceRefresh = false) {
  const def = AI_REPORT_DEFS[type];
  if (!def) return;
  // Only push the action bubble on a fresh request, not a regenerate (which
  // already has its own turn in the transcript).
  if (!forceRefresh) {
    _aiChat.push({ role: 'user', text: def.label });
    _aiChatRepaint();
  }
  _aiChatAsk(type, parameters, forceRefresh);
};

// Opening a saved report from elsewhere drops its rendered body into the chat
// as an assistant turn.
window.aiReportView = async function(id) {
  if (currentView !== 'ai-reports') navigateTo('ai-reports');
  try {
    const d = await api(`/api/ai-reports/${id}`);
    const report = d.report || {};
    const def = AI_REPORT_DEFS[report.type] || { label: report.type };
    _aiChat.push({ role: 'user', text: def.label });
    _aiChat.push({
      role: 'assistant',
      html: _aiMarkdownToHtml(report.report || report.summary || ''),
      regen: { type: report.type, parameters: report.parameters || {} },
    });
    _aiChatRepaint();
  } catch (e) {
    toastError(e.message || 'Failed to open report');
  }
};

function _aiMarkdownToHtml(md) {
  return md
    .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
    .replace(/^## (.+)$/gm, '<h2 style="font-size:1rem;font-weight:700;margin:1.25rem 0 .5rem;color:var(--text)">$1</h2>')
    .replace(/^### (.+)$/gm, '<h3 style="font-size:.9rem;font-weight:700;margin:1rem 0 .4rem;color:var(--text)">$1</h3>')
    .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
    .replace(/\*(.+?)\*/g, '<em>$1</em>')
    .replace(/^- (.+)$/gm, '<li style="margin:.25rem 0;padding-left:.25rem">$1</li>')
    .replace(/(<li.*<\/li>\n?)+/g, m => `<ul style="padding-left:1.25rem;margin:.5rem 0">${m}</ul>`)
    .replace(/\n{2,}/g, '</p><p style="margin:.5rem 0">')
    .replace(/^(?!<[hul])/gm, '')
    .replace(/\n/g, '<br>')
    + '';
}

async function _aiShowCoursePickerModal(type) {
  let courses = [];
  try {
    const d = await api('/api/courses');
    courses = d.courses || [];
  } catch(_) {}

  if (!courses.length) {
    toastError('No courses found. Create a course first.');
    return;
  }

  const overlay = document.createElement('div');
  overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.55);z-index:9999;display:flex;align-items:center;justify-content:center;padding:1rem';
  overlay.innerHTML = `
    <div class="card" style="width:100%;max-width:420px">
      <h3 style="margin:0 0 1rem">Select Course</h3>
      <select id="ai-course-pick" style="width:100%;padding:.6rem;border-radius:8px;border:1px solid var(--border);background:var(--bg);color:var(--text);margin-bottom:1rem;font-size:.9rem">
        ${courses.map(c => `<option value="${c._id}">${esc(c.title)}${c.code?' ('+esc(c.code)+')':''}</option>`).join('')}
      </select>
      <div style="display:flex;gap:.5rem;justify-content:flex-end">
        <button class="btn btn-ghost" onclick="this.closest('[style*=position]').remove()">Cancel</button>
        <button class="btn btn-primary" onclick="(()=>{const v=document.getElementById('ai-course-pick')?.value;if(!v)return;this.closest('[style*=position]').remove();aiReportGenerate('${type}',{courseId:v})})()">Generate Report</button>
      </div>
    </div>`;
  document.body.appendChild(overlay);
  overlay.addEventListener('click', e => { if (e.target === overlay) overlay.remove(); });
}

async function _aiShowDeptPickerModal() {
  let depts = [];
  try {
    const d = await api('/api/departments');
    depts = (d.departments || d.data || []);
  } catch(_) {}

  const overlay = document.createElement('div');
  overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.55);z-index:9999;display:flex;align-items:center;justify-content:center;padding:1rem';
  overlay.innerHTML = `
    <div class="card" style="width:100%;max-width:420px">
      <h3 style="margin:0 0 1rem">Select Department</h3>
      ${depts.length
        ? `<select id="ai-dept-pick" style="width:100%;padding:.6rem;border-radius:8px;border:1px solid var(--border);background:var(--bg);color:var(--text);margin-bottom:1rem;font-size:.9rem">${depts.map(d => `<option value="${esc(d.name||d._id)}">${esc(d.name||d._id)}</option>`).join('')}</select>`
        : `<input id="ai-dept-pick" placeholder="Enter department name" style="width:100%;padding:.6rem;border-radius:8px;border:1px solid var(--border);background:var(--bg);color:var(--text);margin-bottom:1rem;font-size:.9rem">`
      }
      <div style="display:flex;gap:.5rem;justify-content:flex-end">
        <button class="btn btn-ghost" onclick="this.closest('[style*=position]').remove()">Cancel</button>
        <button class="btn btn-primary" onclick="(()=>{const v=document.getElementById('ai-dept-pick')?.value;if(!v)return;this.closest('[style*=position]').remove();aiReportGenerate('department_overview',{department:v})})()">Generate Report</button>
      </div>
    </div>`;
  document.body.appendChild(overlay);
  overlay.addEventListener('click', e => { if (e.target === overlay) overlay.remove(); });
}

function _aiShowStudentLookupModal() {
  const overlay = document.createElement('div');
  overlay.id = 'student-lookup-overlay';
  overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.55);z-index:9999;display:flex;align-items:center;justify-content:center;padding:1rem';
  overlay.innerHTML = `
    <div class="card" style="width:100%;max-width:520px;max-height:90vh;overflow-y:auto">
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:1.2rem">
        <h3 style="margin:0;display:flex;align-items:center;gap:.5rem">
          <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#0ea5e9" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg>
          Student Lookup
        </h3>
        <button onclick="document.getElementById('student-lookup-overlay').remove()" style="background:none;border:none;font-size:1.4rem;cursor:pointer;color:var(--text-muted);line-height:1">×</button>
      </div>
      <div style="display:flex;gap:.5rem;margin-bottom:1rem">
        <input id="sl-query" placeholder="Enter index number or name…" style="flex:1;padding:9px 12px;border:1.5px solid var(--border);border-radius:8px;font-size:14px;font-family:inherit;outline:none;background:var(--bg);color:var(--text)"
          onkeydown="if(event.key==='Enter')_slSearch()">
        <button class="btn btn-primary" onclick="_slSearch()" style="white-space:nowrap">Search</button>
      </div>
      <div id="sl-results"></div>
    </div>`;
  document.body.appendChild(overlay);
  overlay.addEventListener('click', e => { if (e.target === overlay) overlay.remove(); });
  setTimeout(() => document.getElementById('sl-query')?.focus(), 80);
}

window._slSearch = async function() {
  const q = (document.getElementById('sl-query')?.value || '').trim();
  const out = document.getElementById('sl-results');
  if (!q || !out) return;
  out.innerHTML = '<div style="text-align:center;padding:1.5rem;color:var(--text-muted)">Searching…</div>';
  try {
    const d = await api('/api/users/student-lookup?q=' + encodeURIComponent(q));
    if (d.student) {
      out.innerHTML = _slCard(d.student);
    } else if (d.students?.length) {
      out.innerHTML = d.students.length === 1
        ? _slCard(d.students[0])
        : `<div style="font-size:.82rem;color:var(--text-muted);margin-bottom:.6rem">${d.students.length} matches — click one to expand</div>` +
          d.students.map(s => `
            <div style="display:flex;align-items:center;gap:.75rem;padding:.6rem .85rem;border-radius:8px;border:1px solid var(--border);margin-bottom:.4rem;cursor:pointer;transition:background .12s"
              onmouseover="this.style.background='var(--bg-secondary)'" onmouseout="this.style.background=''"
              onclick="document.getElementById('sl-results').innerHTML=_slCard(${JSON.stringify(s).replace(/"/g,'&quot;')})">
              <div style="width:34px;height:34px;border-radius:50%;background:#0ea5e920;display:flex;align-items:center;justify-content:center;font-weight:700;color:#0ea5e9;font-size:.85rem;flex-shrink:0">${esc((s.name||'?')[0].toUpperCase())}</div>
              <div style="flex:1;min-width:0">
                <div style="font-weight:600;font-size:.9rem">${esc(s.name||'')}</div>
                <div style="font-size:.78rem;color:var(--text-muted)">${esc(s.IndexNumber||'')}${s.programme?' · '+esc(s.programme):''}</div>
              </div>
              <div style="font-size:.75rem;padding:2px 8px;border-radius:20px;background:${s.isActive?'#dcfce7':'#fee2e2'};color:${s.isActive?'#16a34a':'#dc2626'}">${s.isActive?'Active':'Inactive'}</div>
            </div>`).join('');
    } else {
      out.innerHTML = '<div style="text-align:center;padding:1.5rem;color:var(--text-muted)">No student found.</div>';
    }
  } catch(e) {
    out.innerHTML = `<div style="padding:.75rem 1rem;background:#fef2f2;border:1px solid #fecaca;border-radius:8px;color:#dc2626;font-size:.85rem">${esc(e.message)}</div>`;
  }
};

window._slCard = function(s) {
  const statusColor = s.isActive ? '#16a34a' : '#dc2626';
  const statusBg    = s.isActive ? '#dcfce7'  : '#fee2e2';
  const rows = [
    ['Index Number', s.IndexNumber],
    ['Email',        s.email],
    ['Phone',        s.phone],
    ['Programme',    s.programme],
    ['Department',   s.department],
    ['Level',        s.studentLevel],
    ['Group',        s.studentGroup],
    ['Semester',     s.semester],
    ['Study Type',   s.studyType],
    ['Qualification',s.qualificationType],
    ['Trust Score',  s.attendanceTrustScore != null ? s.attendanceTrustScore + '%' : null],
    ['Joined',       s.createdAt ? new Date(s.createdAt).toLocaleDateString() : null],
  ].filter(([,v]) => v != null && v !== '');

  const flags = [];
  if (!s.isActive)    flags.push('<span style="background:#fee2e2;color:#dc2626;padding:2px 8px;border-radius:20px;font-size:.75rem;font-weight:700">Inactive</span>');
  if (s.isLocked)     flags.push('<span style="background:#fef3c7;color:#92400e;padding:2px 8px;border-radius:20px;font-size:.75rem;font-weight:700">🔒 Locked</span>');
  if (s.isSuspended)  flags.push('<span style="background:#fce7f3;color:#9d174d;padding:2px 8px;border-radius:20px;font-size:.75rem;font-weight:700">Suspended</span>');

  return `
    <div style="border:1px solid var(--border);border-radius:10px;overflow:hidden">
      <div style="background:linear-gradient(135deg,#0ea5e915,#0ea5e905);padding:1rem;display:flex;align-items:center;gap:.85rem;border-bottom:1px solid var(--border)">
        <div style="width:46px;height:46px;border-radius:50%;background:#0ea5e925;display:flex;align-items:center;justify-content:center;font-weight:800;font-size:1.2rem;color:#0ea5e9;flex-shrink:0">${esc((s.name||'?')[0].toUpperCase())}</div>
        <div style="flex:1;min-width:0">
          <div style="font-weight:700;font-size:1rem">${esc(s.name||'Unknown')}</div>
          <div style="font-size:.8rem;color:var(--text-muted)">${esc(s.IndexNumber||'')}${s.programme?' · '+esc(s.programme):''}</div>
        </div>
        <div style="display:flex;flex-direction:column;align-items:flex-end;gap:.25rem">
          <span style="background:${statusBg};color:${statusColor};padding:2px 10px;border-radius:20px;font-size:.75rem;font-weight:700">${s.isActive?'Active':'Inactive'}</span>
          ${flags.join('')}
        </div>
      </div>
      <div style="padding:.85rem 1rem;display:grid;grid-template-columns:1fr 1fr;gap:.4rem .75rem">
        ${rows.map(([label, val]) => `
          <div style="padding:.4rem 0;border-bottom:1px solid var(--border)">
            <div style="font-size:.7rem;font-weight:700;text-transform:uppercase;letter-spacing:.4px;color:var(--text-muted);margin-bottom:.15rem">${label}</div>
            <div style="font-size:.88rem;font-weight:500">${esc(String(val))}</div>
          </div>`).join('')}
      </div>
      ${s.isLocked && s.lockReason ? `<div style="margin:.5rem 1rem 1rem;padding:.6rem .85rem;background:#fef3c7;border-radius:7px;font-size:.8rem;color:#92400e"><strong>Lock reason:</strong> ${esc(s.lockReason)}</div>` : ''}
    </div>`;
};

// A free-text question asked from the modal (or the dashboard "Ask Dikly AI"
// entry point) lands in the chat as the real question text, then answers.
window._aiAskFromModal = function(question) {
  const go = () => {
    _aiChat.push({ role: 'user', text: question });
    _aiChatRepaint();
    _aiChatAsk('custom_query', { question });
  };
  if (currentView !== 'ai-reports') {
    navigateTo('ai-reports');
    // Let renderAIReports() build the thread first, then post into it.
    setTimeout(go, 60);
  } else {
    go();
  }
};

function _aiShowCustomQueryModal() {
  const overlay = document.createElement('div');
  overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.55);z-index:9999;display:flex;align-items:center;justify-content:center;padding:1rem';
  overlay.innerHTML = `
    <div class="card" style="width:100%;max-width:480px">
      <h3 style="margin:0 0 .5rem;display:flex;align-items:center;gap:.5rem">
        ${svgIcon('<path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/>', 18, 'var(--accent)')}
        Ask Dikly AI
      </h3>
      <p style="margin:0 0 1rem;font-size:.83rem;color:var(--text-light)">Ask any question about your institution's data in plain English.</p>
      <textarea id="ai-query-input" rows="4" placeholder="e.g. Which students in Level 300 had below 60% attendance last month?" style="width:100%;padding:.7rem;border-radius:8px;border:1px solid var(--border);background:var(--bg);color:var(--text);font-size:.88rem;resize:vertical;margin-bottom:1rem;font-family:inherit"></textarea>
      <div style="display:flex;gap:.5rem;justify-content:flex-end">
        <button class="btn btn-ghost" onclick="this.closest('[style*=position]').remove()">Cancel</button>
        <button class="btn btn-primary" onclick="(()=>{const v=document.getElementById('ai-query-input')?.value?.trim();if(!v)return;this.closest('[style*=position]').remove();_aiAskFromModal(v)})()">
          ${svgIcon('<path d="M15 4V2"/><path d="M15 16v-2"/><path d="M8 9h2"/><path d="M20 9h2"/><path d="M17.8 11.8 19 13"/><path d="M15 9h.01"/><path d="M17.8 6.2 19 5"/><path d="M13.2 6.2 12 5"/><path d="M3 21l9-9"/>', 13)}
          Ask AI
        </button>
      </div>
    </div>`;
  document.body.appendChild(overlay);
  overlay.addEventListener('click', e => { if (e.target === overlay) overlay.remove(); });
  setTimeout(() => overlay.querySelector('#ai-query-input')?.focus(), 50);
}

window._realSelectMode   = selectMode;
window._realSelectPortal = selectPortal;
window._appLoaded = true;
// Execute any pending calls from before app.js loaded
if (window._pendingMode)   { selectMode(window._pendingMode);     window._pendingMode = null; }
if (window._pendingPortal) { selectPortal(window._pendingPortal); window._pendingPortal = null; }

// ═══════════════════════════════════════════════════════════════════
//  SIDEBAR UX: pins, recents, accordions, badges, active-state sync
//  (appended last so the navigateTo wrapper sits outside every patch)
// ═══════════════════════════════════════════════════════════════════

function _navUid() { return (window.currentUser && (currentUser._id || currentUser.id)) || 'anon'; }
function _navGetPins()   { try { return JSON.parse(localStorage.getItem('dikly_pins::' + _navUid()) || '[]'); } catch (_) { return []; } }
function _navGetRecent() { try { return JSON.parse(localStorage.getItem('dikly_recent::' + _navUid()) || '[]'); } catch (_) { return []; } }

window._navTogglePin = function(id) {
  let pins = _navGetPins();
  pins = pins.includes(id) ? pins.filter(p => p !== id) : [...pins, id].slice(-6);
  localStorage.setItem('dikly_pins::' + _navUid(), JSON.stringify(pins));
  buildSidebar();
};

// Pinned + Recent quick-access block at the very top of the nav
function _navRenderQuick() {
  const box = document.getElementById('nav-quick');
  if (!box || !window._navLinkMeta || !window._navItemHtml) return;
  const meta = window._navLinkMeta;
  const pins = _navGetPins().filter(id => meta[id]);
  const recent = _navGetRecent().filter(id => meta[id] && !pins.includes(id)).slice(0, 3);
  let html = '';
  if (pins.length) {
    html += '<div class="nav-q-label">★ Pinned</div>' +
      pins.map(id => window._navItemHtml({ id, label: meta[id].label, icon: meta[id].icon }, true)).join('');
  }
  if (recent.length) {
    html += '<div class="nav-q-label">Recent</div>' +
      recent.map(id => window._navItemHtml({ id, label: meta[id].label, icon: meta[id].icon }, true)).join('');
  }
  box.innerHTML = html;
  // keep active state consistent on the fresh copies
  box.querySelectorAll('a[data-view]').forEach(a => a.classList.toggle('active', a.dataset.view === window.currentView));
}

// ── Notification badges ────────────────────────────────────────────
window._setNavBadge = function(view, count) {
  document.querySelectorAll(`.sidebar-nav a[data-view="${view}"] [data-badge]`).forEach(b => {
    if (count > 0) { b.textContent = count > 99 ? '99+' : String(count); b.classList.add('on'); }
    else b.classList.remove('on');
  });
};

async function _updateNavBadges() {
  // Messages: unread conversation total
  try {
    const d = await api('/api/messages/conversations');
    const convs = d.conversations || d || [];
    const unread = Array.isArray(convs) ? convs.reduce((n, c) => n + (c.unread || c.unreadCount || 0), 0) : 0;
    _setNavBadge('messages', unread);
  } catch (_) {}
  // Approvals: corporate admins/managers — must match what the Approvals
  // page itself counts (pending employee/manager registrations via
  // /api/approvals/pending), not the executive dashboard's `pendingApprovals`
  // KPI, which is a sum of pending leave + timesheet requests --
  // a different thing entirely that just happens to share the name. Using
  // that here made the sidebar badge disagree with the page it labels.
  try {
    if (currentUser?.company?.mode === 'corporate' && ['admin', 'superadmin', 'manager'].includes(currentUser.role)) {
      const cacheKey = 'dikly_approvals_badge';
      const cached = JSON.parse(sessionStorage.getItem(cacheKey) || 'null');
      let count;
      if (cached && Date.now() - cached.at < 120000) count = cached.count;
      else {
        const d = await api('/api/approvals/pending');
        count = (d.pending || []).length;
        sessionStorage.setItem(cacheKey, JSON.stringify({ count, at: Date.now() }));
      }
      _setNavBadge('approvals', count);
    }
  } catch (_) {}
}

// ── Wrap the FINAL navigateTo: recents, active sync on copies, auto-expand ──
(function () {
  const _origNavigateTo = navigateTo;
  navigateTo = function (view) {
    const r = _origNavigateTo.apply(this, arguments);
    try {
      document.querySelectorAll('.sidebar-nav a[data-view]').forEach(a =>
        a.classList.toggle('active', a.dataset.view === view));
      if (!['dashboard', 'emp-home'].includes(view)) {
        let rec = _navGetRecent().filter(x => x !== view);
        rec.unshift(view);
        localStorage.setItem('dikly_recent::' + _navUid(), JSON.stringify(rec.slice(0, 5)));
      }
      _navRenderQuick();
    } catch (_) {}
    return r;
  };
})();


// ═══════════════════════════════════════════════════════════════════════════
//  EXAMS TIMETABLE — date-specific exam sittings, distinct from the weekly
//  class Timetable. Editable by HODs (their department), class reps (their
//  own class's courses only), and admins; everyone else views their scope.
//  All permission rules are enforced server-side (routes/examTimetable.js);
//  the UI just mirrors them via each entry's `canEdit` and the
//  /editable-courses list (empty = read-only user, no Add button).
// ═══════════════════════════════════════════════════════════════════════════
let _examTTCourses = [];

async function renderExamTimetable() {
  const content = document.getElementById('main-content');
  if (!content) return;
  content.innerHTML = '<div class="loading">Loading exams timetable…</div>';
  try {
    const [listData, coursesData] = await Promise.all([
      api('/api/exam-timetable'),
      api('/api/exam-timetable/editable-courses').catch(() => ({ courses: [] })),
    ]);
    const entries = listData.entries || [];
    _examTTCourses = coursesData.courses || [];
    const canAdd = _examTTCourses.length > 0;

    const now = new Date(); now.setHours(0, 0, 0, 0);
    const upcoming = entries.filter(e => new Date(e.examDate) >= now);
    const past     = entries.filter(e => new Date(e.examDate) < now);

    const fmtDate = d => new Date(d).toLocaleDateString('en-GB', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' });

    const entryCard = (e, faded) => {
      const c = e.course || {};
      const cls = [c.level ? `L${esc(c.level)}` : null, c.group ? `Grp ${esc(c.group)}` : null].filter(Boolean).join(' · ');
      const safe = esc(JSON.stringify({
        _id: e._id, courseId: c._id, examDate: (e.examDate || '').slice(0, 10),
        startTime: e.startTime, endTime: e.endTime, venue: e.venue || '', notes: e.notes || '',
      }));
      return `
        <div class="card" style="display:flex;align-items:center;gap:14px;${faded ? 'opacity:.55;' : ''}margin-bottom:10px">
          <div style="text-align:center;min-width:64px;background:var(--bg);border-radius:10px;padding:8px 10px">
            <div style="font-size:18px;font-weight:800">${new Date(e.examDate).getDate()}</div>
            <div style="font-size:10px;text-transform:uppercase;color:var(--text-light)">${new Date(e.examDate).toLocaleDateString('en-GB', { month: 'short' })}</div>
          </div>
          <div style="flex:1;min-width:0">
            <div style="font-weight:700;font-size:14px">${esc(c.code || '')} — ${esc(c.title || 'Unknown course')}</div>
            <div style="font-size:12px;color:var(--text-light);margin-top:2px">
              🕐 ${esc(e.startTime)}–${esc(e.endTime)}
              ${e.venue ? ` · 📍 ${esc(e.venue)}` : ''}
              ${cls ? ` · <span style="background:#eef2ff;color:#4f46e5;border-radius:10px;padding:1px 8px;font-size:11px;font-weight:600">${cls}</span>` : ''}
            </div>
            ${e.notes ? `<div style="font-size:12px;color:var(--text-light);margin-top:4px">${esc(e.notes)}</div>` : ''}
            ${e.createdBy?.name ? `<div style="font-size:10px;color:var(--text-muted);margin-top:4px">Added by ${esc(e.createdBy.name)}${e.createdBy.role === 'student' ? ' (class rep)' : e.createdBy.role === 'hod' ? ' (HOD)' : ''}</div>` : ''}
          </div>
          ${e.canEdit ? `
            <div style="display:flex;flex-direction:column;gap:6px">
              <button class="btn btn-ghost btn-sm" style="font-size:12px" onclick='_examTTOpenModal(${safe})'>Edit</button>
              <button class="btn btn-ghost btn-sm" style="font-size:12px;color:#dc2626" onclick="_examTTDelete('${e._id}')">Delete</button>
            </div>` : ''}
        </div>`;
    };

    const groupByDate = list => {
      const groups = new Map();
      for (const e of list) {
        const k = fmtDate(e.examDate);
        if (!groups.has(k)) groups.set(k, []);
        groups.get(k).push(e);
      }
      return [...groups.entries()].map(([date, items]) => `
        <div style="font-size:12px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;color:var(--text-light);margin:18px 0 8px">${date}</div>
        ${items.map(e => entryCard(e, false)).join('')}`).join('');
    };

    content.innerHTML = `
      <div class="page-header" style="display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:12px">
        <div><h2>Exams Timetable</h2><p>Scheduled exam sittings${canAdd ? ' — you can add and edit entries for your scope' : ''}</p></div>
        ${canAdd ? `<button class="btn btn-primary" onclick="_examTTOpenModal()">+ Schedule Exam</button>` : ''}
      </div>
      ${entries.length === 0 ? `
        <div class="card" style="max-width:520px;text-align:center;padding:32px 24px">
          <div style="font-size:32px;margin-bottom:8px">📅</div>
          <div style="font-weight:700;margin-bottom:6px">No exams scheduled yet</div>
          <div style="font-size:13px;color:var(--text-light)">${canAdd ? 'Use “Schedule Exam” to add the first sitting.' : 'Your HOD or class rep hasn\'t published any exam dates yet.'}</div>
        </div>` : `
        ${upcoming.length ? groupByDate(upcoming) : '<div class="card" style="max-width:520px"><p style="color:var(--text-light);font-size:13px">No upcoming exams.</p></div>'}
        ${past.length ? `
          <details style="margin-top:22px">
            <summary style="cursor:pointer;font-size:13px;color:var(--text-light);font-weight:600">Past exams (${past.length})</summary>
            ${past.map(e => entryCard(e, true)).join('')}
          </details>` : ''}`}`;
  } catch (e) {
    content.innerHTML = `<div class="card"><p style="color:var(--danger)">${esc(e.message || 'Failed to load exams timetable')}</p></div>`;
  }
}

window._examTTOpenModal = function(entry) {
  document.getElementById('examtt-modal')?.remove();
  const isEdit = !!entry;
  const courseOptions = _examTTCourses.map(c =>
    `<option value="${c._id}" ${entry && entry.courseId === c._id ? 'selected' : ''}>${esc(c.code || '')} — ${esc(c.title || '')}${c.level ? ` (L${esc(c.level)}${c.group ? ` ${esc(c.group)}` : ''})` : ''}</option>`).join('');
  const ol = document.createElement('div');
  ol.id = 'examtt-modal';
  ol.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.55);display:flex;align-items:center;justify-content:center;z-index:9999;padding:16px';
  ol.innerHTML = `
    <div style="background:var(--card,#fff);border-radius:16px;padding:26px 22px;max-width:440px;width:100%;max-height:90vh;overflow-y:auto">
      <div style="font-size:16px;font-weight:800;margin-bottom:16px">${isEdit ? 'Edit Exam' : 'Schedule Exam'}</div>
      <label style="font-size:12px;font-weight:600;color:var(--text-light)">Course</label>
      <select id="examtt-course" style="width:100%;border:1px solid var(--border);border-radius:8px;padding:9px 10px;font-size:13px;margin:4px 0 12px">${courseOptions}</select>
      <label style="font-size:12px;font-weight:600;color:var(--text-light)">Date</label>
      <input type="date" id="examtt-date" value="${entry?.examDate || ''}" style="width:100%;border:1px solid var(--border);border-radius:8px;padding:9px 10px;font-size:13px;margin:4px 0 12px">
      <div style="display:flex;gap:10px">
        <div style="flex:1"><label style="font-size:12px;font-weight:600;color:var(--text-light)">Start</label>
          <input type="time" id="examtt-start" value="${entry?.startTime || '09:00'}" style="width:100%;border:1px solid var(--border);border-radius:8px;padding:9px 10px;font-size:13px;margin:4px 0 12px"></div>
        <div style="flex:1"><label style="font-size:12px;font-weight:600;color:var(--text-light)">End</label>
          <input type="time" id="examtt-end" value="${entry?.endTime || '11:00'}" style="width:100%;border:1px solid var(--border);border-radius:8px;padding:9px 10px;font-size:13px;margin:4px 0 12px"></div>
      </div>
      <label style="font-size:12px;font-weight:600;color:var(--text-light)">Venue (optional)</label>
      <input type="text" id="examtt-venue" maxlength="120" value="${entry ? esc(entry.venue) : ''}" placeholder="e.g. Main Hall / Lab 2" style="width:100%;border:1px solid var(--border);border-radius:8px;padding:9px 10px;font-size:13px;margin:4px 0 12px">
      <label style="font-size:12px;font-weight:600;color:var(--text-light)">Notes (optional)</label>
      <input type="text" id="examtt-notes" maxlength="500" value="${entry ? esc(entry.notes) : ''}" placeholder="e.g. Bring calculators" style="width:100%;border:1px solid var(--border);border-radius:8px;padding:9px 10px;font-size:13px;margin:4px 0 18px">
      <div style="display:flex;gap:10px;justify-content:flex-end">
        <button class="btn btn-secondary btn-sm" onclick="document.getElementById('examtt-modal').remove()">Cancel</button>
        <button class="btn btn-primary btn-sm" onclick="_examTTSave(${isEdit ? `'${entry._id}'` : 'null'})">${isEdit ? 'Save Changes' : 'Schedule'}</button>
      </div>
    </div>`;
  document.body.appendChild(ol);
};

window._examTTSave = async function(entryId) {
  const body = {
    courseId:  document.getElementById('examtt-course')?.value,
    examDate:  document.getElementById('examtt-date')?.value,
    startTime: document.getElementById('examtt-start')?.value,
    endTime:   document.getElementById('examtt-end')?.value,
    venue:     document.getElementById('examtt-venue')?.value,
    notes:     document.getElementById('examtt-notes')?.value,
  };
  if (!body.courseId) return toastError('Pick a course');
  if (!body.examDate) return toastError('Pick a date');
  try {
    if (entryId) {
      await api(`/api/exam-timetable/${entryId}`, { method: 'PATCH', body: JSON.stringify(body) });
      toastSuccess('Exam updated');
    } else {
      await api('/api/exam-timetable', { method: 'POST', body: JSON.stringify(body) });
      toastSuccess('Exam scheduled');
    }
    document.getElementById('examtt-modal')?.remove();
    renderExamTimetable();
  } catch (e) { toastError(e.message || 'Failed to save exam'); }
};

window._examTTDelete = async function(id) {
  if (!confirm('Remove this exam from the timetable?')) return;
  try {
    await api(`/api/exam-timetable/${id}`, { method: 'DELETE' });
    toastSuccess('Exam removed');
    renderExamTimetable();
  } catch (e) { toastError(e.message || 'Failed to delete exam'); }
};
